parameters.jsCode:
// Iteramos sobre todos os itens recebidos do nó anterior
for (const item of $input.all()) {

  // Verificamos se o item possui o array column_values
  if (item.json && item.json.column_values) {

    // Criamos um novo objeto chamado 'mapeamento' para facilitar o acesso
    item.json.mapeamento = {};

    // Rodamos por cada coluna e criamos uma chave com o ID dela recebendo o texto
    item.json.column_values.forEach(coluna => {
      // Usamos col.id como chave e col.text como valor. 
      // Se precisar do valor bruto, pode adicionar: item.json.mapeamento[coluna.id + '_value'] = coluna.value;
      item.json.mapeamento[coluna.id] = coluna.text; 
    });
  }
}

// Retornamos os itens modificados
return $input.all();

// ==================================================
// MAPEAMENTO COM LÓGICA DE UNIDADES MÚLTIPLAS
// ==================================================

const columnValues = $input.item.json.column_values || [];

// Função Helper: Busca pelo ID e retorna o texto, ou "Não Preenchido"
function getText(id) {
  if (!Array.isArray(columnValues)) return "Não Preenchido";

  const col = columnValues.find(c => c.id === id);

  // Se a coluna existe e tem texto, retorna o texto. Senão, retorna o padrão.
  if (col && col.text && col.text !== "") {
    return col.text;
  }
  return "Não Preenchido";
}

// ==================================================
// 1. VARIÁVEIS PRINCIPAIS
// ==================================================

// Nome do item
let nome = $input.item.json.name || "Não Preenchido";

// Extração inicial
let diasAtestado     = getText('numberjox5johv');
let orgao            = getText('department');
let tipoDocumentacao = getText('sele__o_individual__1');
let observacoes      = getText('short_textcpcyzaec');

// ==================================================
// 2. LÓGICA CONDICIONAL DE ÓRGÃOS (Telefones)
// ==================================================

// Salva o nome original do órgão caso você precise dele para debugar depois
const orgaoOriginal = orgao;

const orgaosNaoMapeados = ["CETAM", "TRE PB", "DETRAN"];
const orgaosSeduc = ["SEDUC ESCOLA", "SEDUC INTERIOR", "SEDUC SEDE", "SEDUC COORDENADORIAS"];
const orgaoSemsa = "SEMSA";

if (orgaosNaoMapeados.includes(orgao)) {
  orgao = "Não Mapeado";
} else if (orgaosSeduc.includes(orgao)) {
  orgao = "559293950342-1633092731@g.us";
} else if (orgao === orgaoSemsa) {
  orgao = "120363196550232313@g.us";
} else {
  // Isso garante que QUALQUER OUTRA COISA caia aqui
  orgao = "Não Mapeado"; 
}

// ==================================================
// 3. LÓGICA DE PREENCHIMENTO DE UNIDADE
// ==================================================

// Captura todas as variáveis possíveis de unidade
const unidadeCetam          = getText('dropdown_mkztj8wp');
const unidadeSemsa          = getText('dropdown_mkzte97y');
const unidadeSeducEscola    = getText('dropdown_mkztt8h0');
const unidadeSeducInterior  = getText('dropdown_mkztf29k');
const unidadeDetran         = getText('dropdown_mkztpndp');
const unidadeCoordenadorias = getText('dropdown_mkztph7r');

// Lista de prioridade
const possiveisUnidades = [
  unidadeCetam,
  unidadeSemsa,
  unidadeSeducEscola,
  unidadeSeducInterior,
  unidadeDetran,
  unidadeCoordenadorias
];

const unidadeFinal = possiveisUnidades.find(u => u !== "Não Preenchido") || "Não Preenchido";

return {
  nome: nome,
  diasAtestado: diasAtestado,
  orgao: orgao,
  tipoDocumentacao: tipoDocumentacao,
  unidade: unidadeFinal, 
  observacoes: observacoes,

  metadata: {
    boardId: $input.item.json.board?.id,
    pulseId: $input.item.json.id,
    groupName: $input.item.json.group?.title,
    dataAtestado: getText('date'),
    orgaoOriginal: orgaoOriginal // Adicionei isso para facilitar se você precisar ver o nome original
  }
};

