parameters.jsCode:
// ===== EXTRAI MENSAGEM CITADA =====
const quotedMsg = $json.body.data.contextInfo?.quotedMessage?.conversation;
if (!quotedMsg) {
  throw new Error('Mensagem citada não encontrada');
}

// ===== EXTRAI BOARD ID E PULSE ID =====
// Formato: "ID: 18393297024, 10867544012"
const idMatch = quotedMsg.match(/^ID:\s*(\d+),\s*(\d+)/);
if (!idMatch) {
  throw new Error('IDs não encontrados no formato esperado. Use: ID: boardID, pulseID');
}

const boardId = idMatch[1];  // 8913964197
const pulseId = idMatch[2];  // 11024235389

// ===== MAPEIA BOARD ID PARA COLUMN ID =====
const boardConfig = {
  '18393297024': {
    boardId: '18393297024',
    columnId: 'color_mkz2qx66',
    nome: 'Board 1'
  },
  '18393330959': {
    boardId: '18393330959',
    columnId: 'status',
    nome: 'Board 2'
  },
  '8913964197': {
    boardId: '8913964197',
    columnId: 'color_mkzcnstr',
    nome: 'Board 3'
  },
  '18395723206': {
    boardId: '18395723206',
    columnId: 'status',
    nome: 'Board Comercial'
  }
};

const config = boardConfig[boardId];
if (!config) {
  throw new Error(`Board ID ${boardId} não mapeado. Boards válidos: ${Object.keys(boardConfig).join(', ')}`);
}

// ===== EXTRAI E PADRONIZA RESPOSTA =====
const respostaRaw = $json.body.data.message.conversation
  .toUpperCase()
  .trim()
  .replace(/[!?.,;:]/g, ''); // Remove pontuação

// Mapeamento de sinônimos
const mapeamentoSinonimos = {
  // Respostas Positivas → APROVADO
  'AUTORIZADO': 'APROVADO',
  'APROVADO': 'APROVADO',
  'APROVO': 'APROVADO',
  'OK': 'APROVADO',
  'SIM': 'APROVADO',
  'ACEITO': 'APROVADO',
  'POSITIVO': 'APROVADO',
  'PODE': 'APROVADO',

  // Respostas Negativas → RECUSADO
  'NEGADO': 'RECUSADO',
  'RECUSADO': 'RECUSADO',
  'NEGO': 'RECUSADO',
  'NÃO': 'RECUSADO',
  'NAO': 'RECUSADO',
  'NEGATIVO': 'RECUSADO',
  'RECUSO': 'RECUSADO',
  'NÃO PODE': 'RECUSADO',
  'NAO PODE': 'RECUSADO',
  'NÃO AUTORIZADO': 'RECUSADO',
  'NAO AUTORIZADO': 'RECUSADO'
};

const respostaPadronizada = mapeamentoSinonimos[respostaRaw];
if (!respostaPadronizada) {
  throw new Error(`Resposta "${respostaRaw}" não é válida. Use: AUTORIZADO, OK, SIM, NEGADO, NÃO`);
}

// ===== RETORNA TUDO PRONTO =====
return {
  // IDs necessários para o Monday Update
  boardId: config.boardId,
  itemId: pulseId,
  columnId: config.columnId,

  // Resposta padronizada
  respostaPadronizada: respostaPadronizada,

  // Dados adicionais para debug/log
  respostaOriginal: $json.body.data.message.conversation,
