];

// Função para definir o grupo correto baseado no NOME_SECAO
function definirGrupoMonday(nomeSecao) {
  if (!nomeSecao) return "OUTROS"; 

  // Converte para maiúsculo para evitar erros de digitação
  const secao = nomeSecao.toUpperCase().trim();

  // 1. Verifica se pertence ao grupo "CONTATO"
  if (setoresContato.some(setor => secao.includes(setor))) {
    return "CONTATO";
  }

  // 2. Verifica as regras específicas de Contratos/Projetos
  if (secao.includes("TRE")) return "TRE - PB";
  if (secao.includes("BARCO")) return "BARCO";
  if (secao.includes("CETAM")) return "CETAM";
  if (secao.includes("SEDUC")) return "SEDUC";
  if (secao.includes("SEMSA")) return "SEMSA";
  if (secao.includes("DETRAN")) return "DETRAN";
  if (secao.includes("IFAM")) return "IFAM";
  if (secao.includes("CONTRATOS EM TRANSICAO") || secao.includes("CONTRATOS EM TRANSIÇÃO")) return "CONTRATOS EM TRANSICAO";
  if (secao.includes("DIRETORIA EXECUTIVA")) return "DIRETORIA EXECUTIVA";
  if (secao.includes("INSTITUTO PCD")) return "INSTITUTO PCD";
  if (secao.includes("LICENÇA MATERNIDADE") || secao.includes("LICENCA MATERNIDADE")) return "LICENÇA MATERNIDADE";

  // 3. Fallback: Se não bater com nada acima, devolve o próprio nome
  return nomeSecao;
}

