parameters.jsCode:
// Code Node para N8N - Processamento de Diárias Monday.com
const items = $input.all();
const output = [];

items.forEach(item => {
  // Extrai o objeto JSON do Monday (pode estar em item.json ou direto)
  const mondayData = item.json[0] || item.json;

  // Função auxiliar para buscar texto da coluna (sempre retorna texto legível)
  const getColumnText = (columnId) => {
    const column = mondayData.column_values.find(col => col.id === columnId);
    return column?.text || '';
  };

  // Função auxiliar para buscar valor de coluna (retorna objeto parseado)
  const getColumnValue = (columnId) => {
    const column = mondayData.column_values.find(col => col.id === columnId);
    if (!column) return null;

    // Parse do value se necessário
    if (column.value && column.value !== 'null') {
      try {
        return JSON.parse(column.value);
      } catch {
        return column.value;
      }
    }
    return null;
  };

  // Extrai TEXTOS das colunas (legível para humanos)
  const diasIndividuais = getColumnText('text_mkzdsn3p');
  const contratoTexto = getColumnText('dropdown_mkzqzz21'); // "DETRAN"
  const solicitante = getColumnText('text_mkzq1esd'); // "Mike"
  const funcaoTexto = getColumnText('dropdown_mkzcn83s'); // "ASG"
  const motivoTexto = getColumnText('color_mkyf75'); // "ATESTADO"
  const empregadoCoberto = getColumnText('text_mkyf4eem'); // "ADRIANA SANTOS FERREIRA"

  // Link do cumprimento (objeto completo)
  const linkCumprimento = getColumnValue('link_mkzq1rsv');
  const linkCumprimentoUrl = linkCumprimento?.url || '';
  const linkCumprimentoTexto = linkCumprimento?.text || '';

  // Valores numéricos
  const qtdDiasPagos = parseFloat(getColumnText('numeric_mkpx30f2')) || 0;
  const valorPorDia = parseFloat(getColumnText('numeric_mkpxdbwk')) || 0;
  const vrPorDia = parseFloat(getColumnText('numeric_mkpxv5pe')) || 0;
  const vtPorDia = parseFloat(getColumnText('numeric_mkpx68f4')) || 0;

  // Insalubridade
  let insalubridade = parseFloat(getColumnText('numeric_mkpxbgaj'));
  if (isNaN(insalubridade) || insalubridade === null) {
    insalubridade = 0;
  }

  // Validação: verifica se dados essenciais estão preenchidos
  const dadosPreenchidos = !!(
    diasIndividuais &&
    funcaoTexto &&
    motivoTexto &&
    empregadoCoberto &&
    qtdDiasPagos > 0 &&
    valorPorDia >= 0 &&
    vrPorDia >= 0 &&
    vtPorDia >= 0
  );

  // Cálculo do Valor Total
  const valorTotal = 
    (vrPorDia * qtdDiasPagos) + 
    (vtPorDia * qtdDiasPagos) + 
    (valorPorDia * qtdDiasPagos) + 
    insalubridade;

  // Monta objeto de saída (SOMENTE TEXTOS)
  output.push({
    json: {
      itemId: mondayData.id,
      nome: mondayData.name,

      // Campos de texto
      diasIndividuais: diasIndividuais,
      contrato: contratoTexto, // "DETRAN"
      solicitante: solicitante, // "Mike"
      funcao: funcaoTexto, // "ASG"
      motivo: motivoTexto, // "ATESTADO"
      empregadoCoberto: empregadoCoberto, // "ADRIANA SANTOS FERREIRA"

      // Link do cumprimento
      linkCumprimentoUrl: linkCumprimentoUrl,
      linkCumprimentoTexto: linkCumprimentoTexto,

      // Valores numéricos
      qtdDiasPagos: qtdDiasPagos,
      valorPorDia: valorPorDia,
      insalubridade: insalubridade,
      vrPorDia: vrPorDia,
      vtPorDia: vtPorDia,
      valorTotal: parseFloat(valorTotal.toFixed(2)),

      // Validação
      dadosPreenchidos: dadosPreenchidos
    }
  });
});

return output;

