// vtDia é calculado dentro deste WF a partir de contrato+funcao+flags.

const body = $json.body || {};
const sabados = Array.isArray(body.sabados) ? body.sabados.filter(d => /^\d{4}-\d{2}-\d{2}$/.test(d)) : [];

if (sabados.length === 0) {
  return [{ json: { _statusCode: 400, _erro: 'sem_sabados', mensagem: 'Nenhum sábado extra informado.' } }];
}
if (!body.chapa) {
  return [{ json: { _statusCode: 400, _erro: 'chapa_obrigatoria', mensagem: 'Campo chapa é obrigatório.' } }];
}
if (!body.nome) {
  return [{ json: { _statusCode: 400, _erro: 'nome_obrigatorio', mensagem: 'Campo nome é obrigatório.' } }];
}
if (body.optanteVT !== true && body.optanteVT !== 'SIM' && body.optanteVT !== 'sim') {
  return [{ json: { _statusCode: 400, _erro: 'nao_optante_vt', mensagem: 'Empregado não é optante de VT — sábado extra não gera benefício.' } }];
}

const hoje = new Date();
const anoComp = Number(body.anoComp) || hoje.getFullYear();
const mesComp = Number(body.mesComp) || (hoje.getMonth() + 1);

return [{
  json: {
    _statusCode: 200,
    uuid: body.uuid || null,
    nome: String(body.nome).trim(),
    chapa: String(body.chapa).padStart(6, '0'),
    contrato: String(body.contrato || '').toUpperCase().trim(),
    sabados,
    qtdSabados: sabados.length,
    optanteVT: true,
    vtSoVolta: body.vtSoVolta === true || body.vtSoVolta === 'SIM*',
    anoComp,
    mesComp,
    nomeLike: `%${String(body.nome).trim()}%`
  }
}];

