  for (const r of linhas) {
    const chapa = String(r['Matrícula/Chapa'] || r.chapa || '').padStart(6, '0');
    if (chapa === chapaTarget) { matched = r; break; }
  }
  if (matched) break;
}

if (!matched) {
  return [{ json: { _statusCode: 404, _erro: 'empregado_nao_encontrado', mensagem: `Chapa ${chapaTarget} não encontrada em BEN 2.` } }];
}

const dados = $('Validar payload').first().json;
const funcaoRM = String(matched['Função'] || matched.funcao || '').toUpperCase().trim();
const contrato = dados.contrato;

// Regra de vtDia por contrato (igual WF5 antigo).
let vtDia = 0;
let regraAplicada = '';
if (contrato === 'DETRAN') {
  vtDia = 10.00;
  if (funcaoRM.includes('PORTARIA')) regraAplicada = 'DETRAN - Portaria';
  else if (funcaoRM.includes('MOTO BOY')) regraAplicada = 'DETRAN - Moto Boy';
  else regraAplicada = `DETRAN - ${funcaoRM}`;
} else if (contrato === 'TRE PB') {
  vtDia = 10.40;
  regraAplicada = 'TRE PB';
} else {
  vtDia = 10.00;
  regraAplicada = `Padrão (${contrato})`;
}

