if (dados.vtSoVolta && vtDia > 0) {
  vtDia = vtDia / 2;
  regraAplicada += ' + VT só volta (½)';
}
vtDia = Math.round(vtDia * 100) / 100;

const valorTotal = Math.round(dados.qtdSabados * vtDia * 100) / 100;

return [{
  json: {
    ...dados,
    cpf: String(matched['CPF'] || matched.cpf || '').replace(/\D/g, ''),
