// Obtém o valor do fato gerador do Monday Fields
const fatoGerador = $('Monday Fields').item.json.fatoGerador;

// Define os fatos geradores que resultam em desídia
const fatosDesídia = [
  'Atrasos injustificados, sem apresentação de justificativas no prazo de 48h',
  'Esquecimento de registro de ponto',
  'Falta injustificada, sem apresentação de justificativas no prazo de 48h',
  'Intrajornada',
  'Não uso de EPI/Uniforme',
  'Não utilização de crachá',
  'Saídas antecipadas, sem apresentação de justificadas no prazo de 48h'
];

// Define o fato gerador que resulta em insubordinação
const fatoInsubordinacao = [
  'Insubordinação ou indisciplina',
  'Utilização de Adornos'
];

// Determina a classificação baseada no fato gerador
let classificacao;

if (fatosDesídia.includes(fatoGerador)) {
  classificacao = 'Desídia no desempenho das respectivas funções. Alínea e do Art. 482 da CLT';
} else if (fatoGerador === fatoInsubordinacao) {
  classificacao = 'Ato de indisciplina ou de insubordinação. Alínea h do Art. 482 da CLT';
} else {
  classificacao = 'Fato gerador não mapeado';
}

// Retorna o resultado
return {
  json: {
    fatoGerador: fatoGerador,
    classificacao: classificacao
  }
};

const inputData = items[0].json;

let phone = '';   // Número limpo (para o Banco de Dados)
let message = ''; // Texto da mensagem
let source = '';  // 'test' ou 'whatsapp'
let chatId = '';  // O JID completo (para devolver a resposta na Evolution)

// =================================================================
// CENÁRIO 1: MODO TESTE (Chat Trigger)
// =================================================================
if (inputData.sessionId) {
  source = 'test';
  // No teste, o sessionId serve tanto como telefone quanto como ID do chat
  phone = inputData.sessionId;
  chatId = inputData.sessionId; 
  message = inputData.chatInput || "";
} 

// =================================================================
// CENÁRIO 2: MODO WHATSAPP (Webhook)
// =================================================================
else {
  source = 'whatsapp';
  const payload = inputData.body || inputData;

  // --- 1. Identificar o JID (chatId) e o Telefone (phone) ---
  let rawJid = "";

  // Tenta achar o JID em vários lugares
  if (payload.sender) {
      rawJid = payload.sender; 
  } else if (payload.data?.key?.remoteJid) {
      rawJid = payload.data.key.remoteJid;
  } else if (payload.key?.remoteJid) {
      rawJid = payload.key.remoteJid;
  }

  // Define as variáveis
  if (rawJid) {
      chatId = rawJid;                 // Ex: 55929999@s.whatsapp.net
      phone = rawJid.split('@')[0];    // Ex: 55929999
  }

  // --- 2. Extração da Mensagem ---
  const msgData = payload.data?.message || payload.message || payload.body?.message;

  if (msgData) {
      message = msgData.conversation || 
                msgData.extendedTextMessage?.text || 
                msgData.imageMessage?.caption || 
                msgData.videoMessage?.caption || 
                "";
  } else if (payload.conversation) {
      message = payload.conversation;
  }
}

// Retorna tudo organizadinho
return {
  json: {
    phone: phone,    // Use no MongoDB
    chatId: chatId,  // Use na Evolution API (campo remoteJid/number)
    message: message,// Use na IA
    source: source   // Use no IF final
  }
};

