// Obtem a resposta bruta do Assistente
const resposta = $json.output;

// Separa por quebras de linha e remove espaços
const linhas = resposta.split('\n').map(l => l.trim()).filter(l => l !== '');

// Remove duplicatas mantendo ordem
const unicas = [...new Set(linhas)];

// Junta novamente com quebras de linha
const respostaFinal = unicas.join('\n');

// Retorna para o próximo nó
return [
  {
    json: {
      mensagem_formatada: respostaFinal
    }
  }
];

// ============================================================
// 1. PEGAR DADOS DO FLUXO ANTERIOR (Nó Adaptador)
// ============================================================
// IMPORTANTE: O nome dentro de $('...') deve ser EXATAMENTE o nome do seu primeiro nó de código.
// Se você não renomeou ele para "Adaptador", mude o nome abaixo para "Code" (ou o nome que estiver lá).
const inputData = $('Code').first().json;

const phone = inputData.phone;
const messageContent = inputData.message;
const source = inputData.source;
const chatId = inputData.chatId; // <--- AQUI ESTÁ O SEGREDO (Pega o JID vindo do início)

// ============================================================
// 2. PEGAR DADOS DO MONGODB (Histórico encontrado)
// ============================================================
// O input direto ($json) é o que veio do nó MongoDB1
const mongoData = $json; 

// Define o turno inicial
let currentTurn = 0;

// Se o banco retornou um histórico, pegamos o turno atual
if (mongoData && mongoData.turn_count) {
    currentTurn = mongoData.turn_count;
}

// ============================================================
// 3. LÓGICA DE INCREMENTO E RESET
// ============================================================
currentTurn = currentTurn + 1;

// Verificação de 24h (Reset de conversa antiga)
if (mongoData && mongoData.timestamp) {
    const lastDate = new Date(mongoData.timestamp);
    const now = new Date();
    const diffHours = Math.abs(now - lastDate) / 36e5;

    if (diffHours > 24) {
        currentTurn = 1; // Reseta para o primeiro turno
    }
}

// ============================================================
// 4. PREPARA A SAÍDA FINAL
// ============================================================
return {
    phone: phone,             // Usado como chave no MongoDB
    chatId: chatId,           // <--- NOVO: JID completo para salvar no banco e enviar msg
    thread_id: phone,
    turn_count: currentTurn,
    message: messageContent,
    source: source,           // 'test' ou 'whatsapp' (Usado no IF final)
    timestamp: new Date().toISOString()
};

