    numero_nf_fiscal: getText(cv, 'numeric_mkx03rz2'),

    // ========== IDs DAS COLUNAS FISCAL (para changeColumnValue) ==========
    id_coluna_arquivo: 'text_mkxsjs4b',
    id_coluna_numero_oc: 'numeric_mkxth4jk',
    id_coluna_valor_pago: 'numeric_mkxsr9k9',
