    link_drive: comprasData.link_drive,
    numero_pc: comprasData.numero_pc,
    valor_pago_compras: comprasData.valor_pago,
    valor_nf_compras: comprasData.valor_nf,
    vencimento: comprasData.vencimento,
    item_id_compras: comprasData.item_id,
