  // 2. Transforma em maiúsculo
  // 3. Se NÃO incluir "NAO", retorna true (é fiscal).
  // 4. Se incluir "NAO", retorna false (não é fiscal).
  e_documento_fiscal: !getStatusLabel('color_mky38wws').toUpperCase().includes('NAO'),

  // ========== DADOS ORIGINAIS ==========
  _original_column_values: columnValues
};

return mapped;

