          }
          if (col.column && col.column.title === 'Status Processo') {
              statusProcesso = col.text;
          }
      }
  }

  // Regra: Tem data e não está Concluído/Não Iniciado
  if (dataReposicao && dataReposicao !== "empty" && dataReposicao !== null && statusProcesso !== "RECEBIDO" && statusProcesso !== "NÃO INICIADO") {

      let diffDias = -1;
      try {
          // Lê a data no formato "2026-07-01"
          const partes = dataReposicao.split('-');
          if (partes.length === 3) {
              const ano = parseInt(partes[0], 10);
              const mes = parseInt(partes[1], 10) - 1; // Mês no JS começa em zero
              const dia = parseInt(partes[2], 10);

              const dataAlvo = new Date(ano, mes, dia);
              const diffTempo = dataAlvo - hoje;
              diffDias = Math.ceil(diffTempo / (1000 * 60 * 60 * 24));
          }
      } catch (e) {}

      // A REGRA DE OURO LIGADA NOVAMENTE
      if (diffDias === 45 || diffDias === 30 || diffDias === 15) {
          resultados.push({
