const updates = prep.updates || [];
return updates.map((update, index) => {
  const replies = update.replies || [];
  const creator = update.creator?.name || "Autor nao informado";
  const replyHtml = replies.length ? `<hr><p><strong>Respostas copiadas:</strong></p>${replies.map(reply => {
    const replyCreator = reply.creator?.name || "Autor nao informado";
    const replyBody = reply.body || `<p>${reply.text_body || ""}</p>`;
    return `<blockquote><p><strong>${replyCreator}</strong> em ${reply.created_at || "data nao informada"}</p>${replyBody}</blockquote>`;
  }).join("")}` : "";
  return { json: { duplicateBoardId: duplicateBoard.id, sourceUpdateId: update.id, body: `<p><strong>Mensagem copiada do bal?o central</strong></p><p>Autor original: ${creator}<br>Data original: ${update.created_at || "data nao informada"}<br>Update original: ${update.id}</p><hr>${update.body || `<p>${update.text_body || ""}</p>`}${replyHtml}`, index } };
});

const prep = $("Preparar dados da virada").first().json;
const centralBoardId = prep.centralBoardId;
const targetGroupId = "group_mm2eqsdr";
const formatDate = (value) => value ? String(value).substring(0, 10) : "";
const output = [];
for (const item of $input.all()) {
  const data = item.json;
  const intermitente = (data["Intermitente?"] || "").toString().toUpperCase();
  if (intermitente === "SIM") continue;
  const columnValues = { texto: data["Funcion?rio"] || data["Nome do Funcion?rio"] || "", dup__of_matr_cula: data["CPF"] || "", texto75: data["Local/Unidade"] || "", text_mkrzbj02: data["Campo Complementar"] || "", text_mkrztp4t: data["Jornada"] || "", texto0: data["Fun??o"] || "", text_mkzh8jhn: formatDate(data["Admiss?o"]), text_mkt63tyk: data["C?digo"] || "", optante___vt: { label: data["Vale Transporte"] || "N?O" } };
  output.push({ json: { boardId: centralBoardId, groupId: targetGroupId, itemName: data["Nome do Funcion?rio"] || data["Funcion?rio"] || "Sem nome", columnValuesString: JSON.stringify(columnValues) } });
}
return output;

const licitacoes = items.map(item => ({
  id: item.json.id,
  nome: item.json.Name,
  portal: item.json.Portal,
  data: item.json.Data,
  link: item.json.link
}));

// Define singular ou plural
const textoLicitacao = licitacoes.length === 1 ? 'licitação' : 'licitações';

let mensagem = `📢 NOVAS LICITAÇÕES DISPONÍVEIS 📢\n\n`;
mensagem += `Total: ${licitacoes.length} ${textoLicitacao}\n`;
mensagem += `━━━━━━━━━━━━━━━━━━━━\n\n`;

licitacoes.forEach((lic, index) => {
