const monthNames = ['JANEIRO', 'FEVEREIRO', 'MAR\u00c7O', 'ABRIL', 'MAIO', 'JUNHO', 'JULHO', 'AGOSTO', 'SETEMBRO', 'OUTUBRO', 'NOVEMBRO', 'DEZEMBRO'];
const now = new Date();
const targetGroupName = `${monthNames[now.getMonth()]}/${now.getFullYear().toString().slice(-2)}`;

function extractMondayItems(responseItem) {
  const json = responseItem.json;
  const firstPageItems = json?.data?.boards?.[0]?.items_page?.items;
  const nextPageItems = json?.data?.next_items_page?.items;

  if (Array.isArray(firstPageItems)) return firstPageItems;
  if (Array.isArray(nextPageItems)) return nextPageItems;
  if (json?.id && json?.column_values) return [json];

  return [];
}

const allItems = $input.all().flatMap(extractMondayItems);
const itemsDoGrupo = allItems.filter(item => item.group?.title === targetGroupName);

let totalGeral = 0;
let totaisPorContrato = {};
let itensFinalizados = 0;

function getValorColuna(item, colId) {
  const columns = item.column_values;

  if (Array.isArray(columns)) {
    const col = columns.find(c => c.id === colId);
    return col ? (col.display_value || col.text || col.value || '0') : '0';
  }

  if (columns?.[colId]) {
    const col = columns[colId];
    return col.display_value || col.text || col.value || '0';
  }

  return '0';
}

function limparNumero(valorStr) {
  if (!valorStr) return 0;
  let texto = valorStr.toString().replace(/[^0-9.,-]/g, '');

  if (texto.includes(',') && texto.includes('.')) {
    texto = texto.replace(/\./g, '').replace(',', '.');
  } else if (texto.includes(',')) {
    texto = texto.replace(',', '.');
  }

  return parseFloat(texto) || 0;
}

for (const item of itemsDoGrupo) {
  const status = getValorColuna(item, 'lookup_mkyfb0pv');

  if (status !== 'Finalizado') {
    continue;
  }

  itensFinalizados++;

  const contrato = getValorColuna(item, 'dropdown_mkzqzz21') || 'Sem Contrato';
  const dias = limparNumero(getValorColuna(item, 'numeric_mkpx30f2'));
  const valorDiaria = limparNumero(getValorColuna(item, 'numeric_mkpxdbwk'));
  const vr = limparNumero(getValorColuna(item, 'numeric_mkpxv5pe'));
  const vt = limparNumero(getValorColuna(item, 'numeric_mkpx68f4'));
