// Propósito: Mapear múltiplos itens + consolidar com Compras
// Versão: 2.1 - CORREÇÃO DE MODO
// ==================================================

const itemsFiscal = $input.all();
const comprasData = $('Mapear Colunas - Compras').item.json;

// ========== FUNÇÕES HELPER ==========
function getColumn(columnValues, id) {
  return columnValues.find(col => col.id === id);
}

function getText(columnValues, id) {
  const col = getColumn(columnValues, id);
  return col ? (col.text || '') : '';
}

// ========== PROCESSA CADA ITEM DO FISCAL ==========
const mappedItems = itemsFiscal.map(item => {
  const cv = item.json.column_values;

  return {
    // ========== IDENTIFICAÇÃO ==========
    pulse_id_fiscal: item.json.id,
