// =============================================
// WEBHOOK 2 — CODE NODE 1
// Verifica se TODOS os itens do grupo estão
// com status = "REALIZADO"
// Se NÃO → retorna array vazio (para o fluxo)
// Se SIM → passa os itens adiante
// =============================================
//
// INPUT: $input.all() → todos os itens do grupo
// OUTPUT: array com todos os itens ou [] para parar
// =============================================

const todosItens = $input.all().map(i => i.json);

if (!todosItens || todosItens.length === 0) {
  throw new Error('Nenhum item recebido do grupo.');
}

const getColuna = (item, colId) =>
  (item.column_values || []).find(c => c.id === colId) || null;

const todosConcluidos = todosItens.every(item => {
  const status = getColuna(item, 'color_mkzz2h0x');
  return status && status.text === 'REALIZADO';
});

// Se não concluídos: para o fluxo silenciosamente
if (!todosConcluidos) {
  return [];
}

// Passa todos os itens adiante para o Code Node 2
return todosItens.map(item => ({ json: item }));

// =============================================
// WEBHOOK 2 — CODE NODE 2
// Consolida todos os itens do grupo por pessoa
// Calcula ausências, percentual e nível de alerta
// Prepara payload para o HTTP Request da IA
// =============================================
//
// INPUT: $input.all() → itens aprovados do CN1
// OUTPUT: objeto consolidado para a IA
//
// MAPEAMENTO DE COLUNAS:
//   Nome            → item.name (PulseName)
//   Qtd Dias        → numeric_mkw933fd
//   Tipo Ausência   → color_mkw91fgd
//   Competência     → color_mkw9n9yw  (ex: "MARÇO/26")
// =============================================

const DIAS_UTEIS_MES = 22;

const TIPOS_INJUSTIFICADOS = ['INTEGRAL', 'EM HORAS', 'SUSPENSÃO', 'SUSPENSAO'];

const DRIVE_IDS_POR_MES = {
  'JANEIRO':   '11463079222',
  'FEVEREIRO': '11463096987',
  'MARÇO':     '11463087974',
  'MARCO':     '11463087974',
  'ABRIL':     '11463097078',
};

const todosItens = $input.all().map(i => i.json);

const getColuna = (item, colId) =>
  (item.column_values || []).find(c => c.id === colId) || null;

// ── Extrair competência do primeiro item ──────────────────────────
const competenciaRaw = (getColuna(todosItens[0], 'color_mkw9n9yw') || {}).text || '';
const mesNome = competenciaRaw.split('/')[0].trim().toUpperCase();
const driveItemId = DRIVE_IDS_POR_MES[mesNome] || null;

// ── Consolidar por pessoa ─────────────────────────────────────────
const consolidado = {};

todosItens.forEach(item => {
  const nome = (item.name || '').trim();
  if (!nome) return;

  const qtd  = parseFloat((getColuna(item, 'numeric_mkw933fd') || {}).text || '0') || 0;
  const tipo = ((getColuna(item, 'color_mkw91fgd') || {}).text || '').trim().toUpperCase();
  const isInjustificada = TIPOS_INJUSTIFICADOS.includes(tipo);

  if (!consolidado[nome]) {
    consolidado[nome] = { nome, justificadas: 0, injustificadas: 0, totalAusencias: 0 };
  }

  if (isInjustificada) consolidado[nome].injustificadas += qtd;
  else                 consolidado[nome].justificadas   += qtd;

  consolidado[nome].totalAusencias += qtd;
});

// ── Calcular percentual e nível de alerta ─────────────────────────
const pessoas = Object.values(consolidado).map(p => {
  const pct = parseFloat(((p.totalAusencias / DIAS_UTEIS_MES) * 100).toFixed(1));

  let nivelAlerta;
  if      (pct < 50) nivelAlerta = 'NORMAL';
  else if (pct < 60) nivelAlerta = 'ALERTA BAIXO';
  else if (pct < 70) nivelAlerta = 'ALERTA MEDIO';
  else               nivelAlerta = 'ALERTA ALTO';

  return { ...p, pct, percentual: String(pct), nivelAlerta };
}).sort((a, b) => b.pct - a.pct);

// ── Montar prompt para a IA ───────────────────────────────────────
const resumoParaIA = pessoas.map(p =>
  `- ${p.nome}: ${p.totalAusencias} ausencias (${p.justificadas} justificadas, ${p.injustificadas} injustificadas) — ${p.percentual}% — ${p.nivelAlerta}`
).join('\n');

const promptIA = `Voce e um analista de RH. Com base nos dados de ausencias do mes de ${competenciaRaw}, gere um parecer profissional e objetivo (maximo 5 linhas) com recomendacoes para cada nivel de alerta identificado. Considere: acima de 50% alerta baixo, acima de 60% alerta medio, acima de 70% alerta alto com possibilidade de desligamento.\n\nDados:\n${resumoParaIA}`;

return [{
  json: {
    competencia: competenciaRaw,
    mes_nome: mesNome,
    drive_item_id_relatorio: driveItemId,
    total_funcionarios: pessoas.length,
    total_ausencias_geral: pessoas.reduce((acc, p) => acc + p.totalAusencias, 0),
    pessoas,
    prompt_ia: promptIA,
  }
}];

// =============================================
// WEBHOOK 2 — CODE NODE 3 (v3)
// Dados do CN2  → $('Code in JavaScript1').first().json
// Parecer da IA → $('Message a model').first().json.content[0].text
// Gera o PDF Geral do grupo/mês
// =============================================

const dados      = $('Code in JavaScript1').first().json;
const parecerRaw = $('Message a model').first().json.content[0].text;

const competencia = dados.competencia           || '';
const pessoas     = dados.pessoas               || [];
const totalGeral  = dados.total_ausencias_geral || 0;

// ── Normalizar UTF-8 → ASCII puro (sem acentos, sem corrupção no PDF) ──
function normalizarParaPDF(str) {
  return String(str)
    .normalize('NFD')                   // decompõe letra + acento
    .replace(/[\u0300-\u036f]/g, '')    // remove os acentos
    .replace(/[^\x00-\x7F]/g, '');     // remove qualquer char não-ASCII
}

// ── Truncar nome se passar do limite de caracteres ────────────────
function truncarNome(str, maxChars) {
  const normalizado = normalizarParaPDF(str);
  if (normalizado.length <= maxChars) return normalizado;
  return normalizado.substring(0, maxChars - 3).trimEnd() + '...';
}

// ── Processar parecer: limpa markdown, separa parágrafos, quebra linhas ──
function processarParecer(texto, maxChars) {
  let t = normalizarParaPDF(texto);

  t = t.replace(/---/g, '\n');           // separadores viram quebra
  t = t.replace(/#{1,6}\s*/g, '');      // remove ## headers
  t = t.replace(/\*\*/g, '');           // remove negrito
  t = t.replace(/[*_`]/g, '');          // remove outros markdown

  const paragrafos = t.split(/\n{2,}/); // divide em parágrafos reais
  const linhas = [];

  paragrafos.forEach(paragrafo => {
    const p = paragrafo.replace(/\n/g, ' ').replace(/\s{2,}/g, ' ').trim();
    if (!p) return;

    if (linhas.length > 0) linhas.push(''); // linha em branco entre parágrafos

    const palavras = p.split(' ');
    let linha = '';
    palavras.forEach(palavra => {
      if ((linha + ' ' + palavra).trim().length > maxChars) {
        if (linha) linhas.push(linha.trim());
        linha = palavra;
      } else {
        linha = (linha + ' ' + palavra).trim();
      }
    });
    if (linha) linhas.push(linha.trim());
  });

  return linhas;
}

const parecerLinhas = processarParecer(parecerRaw, 88);

// ── ENGINE DE PDF ──────────────────────────────────────────────────
function criarGerador() {
  let pdf = '%PDF-1.4\n';
  const objetos = [];
  const offsets = {};

  const F = { normal: 'F1', bold: 'F2' };

  const C = {
    azulEscuro:  [0.10, 0.25, 0.45],
    azulMedio:   [0.18, 0.40, 0.65],
    branco:      [1.00, 1.00, 1.00],
    preto:       [0.10, 0.10, 0.10],
    cinzaClaro:  [0.95, 0.95, 0.95],
    cinzaMedio:  [0.75, 0.75, 0.75],
    verde:       [0.13, 0.55, 0.13],
    amarelo:     [0.70, 0.55, 0.00],
    laranja:     [0.80, 0.35, 0.00],
    vermelho:    [0.75, 0.10, 0.10],
  };

  const rgb = c => c[0].toFixed(3)+' '+c[1].toFixed(3)+' '+c[2].toFixed(3);
  const esc = s => normalizarParaPDF(String(s)).replace(/[()\\]/g, '\\$&');

  function pagina() {
    const ops = [];
    return {
      rect(x,y,w,h,cf,cb){
        ops.push('q');
        if(cf) ops.push(rgb(cf)+' rg '+x+' '+y+' '+w+' '+h+' re f');
        if(cb) ops.push(rgb(cb)+' RG 0.5 w '+x+' '+y+' '+w+' '+h+' re S');
        ops.push('Q');
      },
      linha(x1,y1,x2,cor,esp){
        ops.push('q '+(esp||0.5)+' w '+rgb(cor||C.cinzaMedio)+' RG '+x1+' '+y1+' m '+x2+' '+y1+' l S Q');
      },
      txt(x,y,t,fonte,tam,cor){
        ops.push('q BT /'+(fonte||F.normal)+' '+(tam||11)+' Tf '+rgb(cor||C.preto)+' rg '+x+' '+y+' Td ('+esc(t)+') Tj ET Q');
      },
      build(){ return ops.join('\n'); }
    };
  }

  function addObj(id, conteudo){ objetos.push({ id, conteudo }); }

  function compilar(streams) {
    const nf = 3 + streams.length * 2;
    addObj(1, '<</Type /Catalog /Pages 2 0 R>>');
    addObj(2, '<</Type /Pages /Kids ['+streams.map((_,i)=>(3+i*2)+' 0 R').join(' ')+'] /Count '+streams.length+'>>');
    streams.forEach((s,i) => {
      const pid=3+i*2, sid=4+i*2, len=Buffer.byteLength(s,'latin1');
      addObj(pid, '<</Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Contents '+sid+' 0 R /Resources <</Font <</F1 '+nf+' 0 R /F2 '+(nf+1)+' 0 R>>>>>>');
      addObj(sid, '<</Length '+len+'>>\nstream\n'+s+'\nendstream');
    });
    addObj(nf,   '<</Type /Font /Subtype /Type1 /BaseFont /Helvetica>>');
    addObj(nf+1, '<</Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold>>');

    objetos.forEach(({id,conteudo}) => {
      offsets[id] = Buffer.byteLength(pdf,'latin1');
      pdf += id+' 0 obj\n'+conteudo+'\nendobj\n';
    });
    const xp = Buffer.byteLength(pdf,'latin1');
    const mx = Math.max(...objetos.map(o => o.id));
    let xref = 'xref\n0 '+(mx+1)+'\n0000000000 65535 f \n';
    for(let i=1;i<=mx;i++)
      xref += (offsets[i]!==undefined ? String(offsets[i]).padStart(10,'0') : '0000000000')+' 00000 n \n';
    xref += 'trailer\n<</Size '+(mx+1)+' /Root 1 0 R>>\nstartxref\n'+xp+'\n%%EOF';
    return Buffer.from(pdf+xref,'latin1');
  }

  return { pagina, compilar, C, F };
}

// ── MONTAGEM DO PDF COM PAGINAÇÃO AUTOMÁTICA ──────────────────────
function gerarGeral() {
  const { pagina, compilar, C, F } = criarGerador();
  const streams = [];

  const MARGEM_X = 24;
  const LARGURA  = 564;
  const LINHA_H  = 18;
  const RODAPE_Y = 45;

  function cabecalho(p, num) {
    p.rect(0, 742, 612, 50, C.azulEscuro);
    p.txt(24, 766, 'RELATORIO GERAL DE AUSENCIAS', F.bold, 17, C.branco);
    p.txt(24, 750, 'Aions Corp  |  Gestao de Pessoas  |  ' + normalizarParaPDF(competencia), F.normal, 9, C.branco);

    if (num === 1) {
      p.rect(24,  690, 174, 44, C.cinzaClaro, C.cinzaMedio);
      p.txt(34,  720, 'Funcionarios',         F.bold, 10, C.azulEscuro);
      p.txt(34,  703, String(pessoas.length), F.bold, 20, C.azulEscuro);

      p.rect(206, 690, 174, 44, C.cinzaClaro, C.cinzaMedio);
      p.txt(216, 720, 'Total Ausencias',      F.bold, 10, C.azulEscuro);
      p.txt(216, 703, String(totalGeral),     F.bold, 20, C.azulEscuro);

      p.rect(388, 690, 200, 44, C.cinzaClaro, C.cinzaMedio);
      p.txt(398, 720, 'Dias Uteis Ref.',      F.bold, 10, C.azulEscuro);
      p.txt(398, 703, '22 dias',             F.bold, 20, C.azulEscuro);
    }
  }

  function rodape(p, num) {
    p.linha(24, 30, 588, C.cinzaMedio, 0.5);
    p.txt(24,  18, 'Relatorio gerado automaticamente - Aions Corp', F.normal, 8, C.cinzaMedio);
    p.txt(450, 18, new Date().toLocaleDateString('pt-BR') + '  |  Pag. ' + num, F.normal, 8, C.cinzaMedio);
  }

  function headerTabela(p, curY, titulo) {
    p.txt(MARGEM_X, curY, titulo, F.bold, 10, C.azulEscuro);
    curY -= 4;
    p.linha(MARGEM_X, curY, 588, C.azulMedio, 1);
    curY -= 2;
    p.rect(MARGEM_X, curY - LINHA_H, LARGURA, LINHA_H, C.azulEscuro);
    p.txt(28,  curY - 13, 'Funcionario',  F.bold, 9, C.branco);
    p.txt(230, curY - 13, 'Just.',        F.bold, 9, C.branco);
    p.txt(280, curY - 13, 'Injust.',      F.bold, 9, C.branco);
    p.txt(340, curY - 13, 'Total',        F.bold, 9, C.branco);
    p.txt(390, curY - 13, '% (22 dias)',  F.bold, 9, C.branco);
    p.txt(480, curY - 13, 'Status',       F.bold, 9, C.branco);
    return curY - LINHA_H;
  }

  let numPagina = 1;
  let p = pagina();
  cabecalho(p, numPagina);
  let curY = 672;

  // ── Tabela de funcionários ──
  curY = headerTabela(p, curY, 'CONSOLIDADO POR FUNCIONARIO');

  pessoas.forEach((pessoa, i) => {
    if (curY - LINHA_H < RODAPE_Y) {
      rodape(p, numPagina);
      streams.push(p.build());
      numPagina++;
      p = pagina();
      cabecalho(p, numPagina);
      curY = headerTabela(p, 720, 'CONSOLIDADO POR FUNCIONARIO (continuacao)');
    }

    p.rect(MARGEM_X, curY - LINHA_H, LARGURA, LINHA_H, i%2===0 ? C.cinzaClaro : C.branco, C.cinzaMedio);

    let corStatus, labelStatus;
    if      (pessoa.pct < 50) { corStatus=C.verde;    labelStatus='Normal'; }
    else if (pessoa.pct < 60) { corStatus=C.amarelo;  labelStatus='Baixo'; }
    else if (pessoa.pct < 70) { corStatus=C.laranja;  labelStatus='Medio'; }
    else                      { corStatus=C.vermelho; labelStatus='ALTO'; }

    p.txt(28,  curY-13, truncarNome(pessoa.nome, 36),     F.normal, 9, C.preto);
    p.txt(230, curY-13, String(pessoa.justificadas),     F.normal, 9, C.verde);
    p.txt(280, curY-13, String(pessoa.injustificadas),   F.normal, 9, C.vermelho);
    p.txt(340, curY-13, String(pessoa.totalAusencias),   F.bold,   9, C.preto);
    p.txt(390, curY-13, pessoa.percentual+'%',            F.bold,   9, C.preto);
    p.txt(480, curY-13, labelStatus,                     F.bold,   9, corStatus);
    curY -= LINHA_H;
  });

  // ── Bloco do Parecer ──
  curY -= 20; // espaço antes do título do parecer

  if (curY - 50 < RODAPE_Y) {
    rodape(p, numPagina);
    streams.push(p.build());
    numPagina++;
    p = pagina();
    cabecalho(p, numPagina);
    curY = 720;
  }

  p.txt(MARGEM_X, curY, 'PARECER DA INTELIGENCIA ARTIFICIAL', F.bold, 11, C.azulEscuro);
  curY -= 5;
  p.linha(MARGEM_X, curY, 588, C.azulMedio, 1);
  curY -= 16; // espaço generoso após o título antes do texto

  parecerLinhas.forEach(linha => {
    const alturaLinha = linha === '' ? 8 : 14; // linha em branco menor

    if (curY - alturaLinha < RODAPE_Y) {
      rodape(p, numPagina);
      streams.push(p.build());
      numPagina++;
      p = pagina();
      cabecalho(p, numPagina);
      curY = 720;
    }

    if (linha !== '') {
      p.txt(30, curY, linha, F.normal, 9, C.preto);
    }
    curY -= alturaLinha;
  });

  rodape(p, numPagina);
  streams.push(p.build());

  return compilar(streams);
}

// ── EXECUÇÃO ──────────────────────────────────────────────────────
