// Puxa o textão inteiro que saiu do PDF
const text = $input.first().json.text;

// Puxa o Link Público
const publicUrl = $('Recebe o Arquivo').first().json.data.assets[0].public_url; 

// 1. EXTRAÇÃO DO CABEÇALHO
const matchSA = text.match(/Numero documento\n(\d+)/);
const numeroSA = matchSA ? matchSA[1] : "";

// 🛡️ NOVA REGRA DE NEGÓCIO DO CONTRATO
const matchContrato = text.match(/CENTRO DE CUSTO[^\n]*/i);
let contrato = "Adm"; // O Padrão (Plano B) já nasce como Adm!

if (matchContrato) {
   let textoLinha = matchContrato[0].toUpperCase(); // Pega a linha e deixa toda maiúscula pra facilitar

   if (textoLinha.includes("DETRAN")) {
       contrato = "Detran";
   } else if (textoLinha.includes("SEDUC")) {
       contrato = "Seduc";
   } else if (textoLinha.includes("SEMSA")) {
       contrato = "Semsa";
   } else if (textoLinha.includes("CETAM")) {
       contrato = "Cetam";
   }
   // Se ele leu a linha e não achou nenhum desses 4, a variável continua sendo "Adm".
}

// 🛡️ BLINDAGEM DE OBSERVAÇÃO
const matchObs = text.match(/Observações:\s*([^\n]*)/i);
const observacoes = matchObs ? matchObs[1].trim() : "";

// 2. EXTRAÇÃO DAS LINHAS
const lines = text.split('\n');
const itemsToCreate = [];

const itemRegex = /^\d{2}\s+(\d+)\s+(.+?)\s+\S+\s+\d{2}\/\d{2}\/\d{4}\s+\d+\s+(\d+)$/;

for (const line of lines) {
  const match = line.match(itemRegex);

  if (match) {
    itemsToCreate.push({
      json: {
        codigoTotvs: match[1].trim(),
        material: match[2].trim(),
        quantidade: parseInt(match[3], 10),
        numeroSA: numeroSA,
        contrato: contrato, // Agora sai perfeitinho: Detran, Seduc, Semsa, Cetam ou Adm
        elemento: observacoes,
        originalPdfUrl: publicUrl
      }
    });
  }
}

return itemsToCreate;

