const funcionariosElegiveis = [];

const hoje = new Date(
  new Date().toLocaleString('en-US', { timeZone: 'America/Manaus' })
);
hoje.setHours(0, 0, 0, 0);

const limite60Dias = new Date(hoje);
limite60Dias.setDate(limite60Dias.getDate() + 60);

function parseData(valor) {
  if (!valor) return null;

  const str = String(valor).trim().slice(0, 10);

  if (/^\d{2}\/\d{2}\/\d{4}$/.test(str)) {
    const [dia, mes, ano] = str.split('/').map(Number);
    return new Date(ano, mes - 1, dia);
  }

  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) {
    const [ano, mes, dia] = str.split('-').map(Number);
    return new Date(ano, mes - 1, dia);
  }

  const data = new Date(valor);
  return isNaN(data) ? null : data;
}

function parseNumero(valor) {
  if (valor === null || valor === undefined || valor === '') return 0;

  return Number(
    String(valor)
      .replace(/\./g, '')
      .replace(',', '.')
  ) || 0;
}

for (const item of $input.all()) {
  const func = item.json;

  const fimAquisitivo = parseData(func.FIMPERAQUIS);
  const diasAMarcar = Math.ceil(parseNumero(func.FERIAS_A_MARCAR));

  if (!fimAquisitivo || diasAMarcar <= 0) continue;

  fimAquisitivo.setHours(0, 0, 0, 0);

  if (fimAquisitivo <= limite60Dias) {
    const dataLimite = new Date(fimAquisitivo);
    dataLimite.setFullYear(dataLimite.getFullYear() + 1);
    dataLimite.setDate(dataLimite.getDate() - diasAMarcar + 1);

    func.StatusBoard = 'PENDENTE';
    func.AlertaPrazoBoard = 'AGUARDANDO';
    func.DiasDeDireito = diasAMarcar;
    func.DiasRestantes = diasAMarcar;
    func.DataLimiteGozar = dataLimite.toISOString().split('T')[0];
    func.PeriodosJaUtilizados = parseInt(func.PERIODOS_UTILIZADOS) || 0;
    func.FaltasPeriodo = parseInt(func.FALTAS_PERIODO) || 0;

    funcionariosElegiveis.push({ json: func });
  }
}

return funcionariosElegiveis;

