// PASSO A: SEPARAR E SOMAR POR CONTRATO + TIPO DE BENEFÍCIO
// ==========================================
const agrupamento = {};

for (const item of $input.all()) {
  const row = item.json;

  // Identifica o tipo do benefício e ignora se não estiver na nossa lista
  const codBeneficio = String(row['Código Benefício'] || '');
  const tipoBeneficio = mapCodBeneficioParaTipo[codBeneficio];
  if (!tipoBeneficio) continue; 

  // Busca o ID dinâmico da coluna
  const colunaDestino = mapColunasBeneficios[tipoBeneficio];
  if (!colunaDestino) continue; // Pula se a coluna não existir no Monday

  // Extrai e limpa a Seção
  const secaoAtual = String(row['Código Seção'] || '');
  const secaoRaiz = secaoAtual.replace(/\./g, '').substring(0, 8); 

  // Descobre a qual contrato a seção pertence
  let contratoDestino = 'ADM'; // Fallback
  for (const finalSecao in mapSecoes) {
    if (secaoRaiz.endsWith(finalSecao)) {
      contratoDestino = mapSecoes[finalSecao];
      break; 
    }
  }

  // Blindagem Financeira do Valor
  let valorReal = row['Valor Total'] || 0;
  let valorNum = 0;
  if (typeof valorReal === 'string') {
    let limpo = valorReal.replace(/[R$\s]/g, ''); 
    if (limpo.includes(',') && limpo.includes('.')) {
        limpo = limpo.lastIndexOf(',') > limpo.lastIndexOf('.') ? limpo.replace(/\./g, '').replace(',', '.') : limpo.replace(/\,/g, '');
    } else if (limpo.includes(',')) {
        limpo = limpo.replace(',', '.');
    }
    valorNum = parseFloat(limpo);
  } else {
    valorNum = parseFloat(valorReal); 
  }
  if (isNaN(valorNum)) valorNum = 0;

  // Cria a "caixa" de agrupamento única e soma o valor
  const chave = `${contratoDestino}_${colunaDestino}`;
  if (!agrupamento[chave]) {
    agrupamento[chave] = {
      contrato: contratoDestino,
      beneficio: tipoBeneficio,
      column_id: colunaDestino,
      valor_total: 0
    };
  }
  agrupamento[chave].valor_total += valorNum;
}

