// PASSO B: MONTAR O PACOTE PARA O MONDAY
// ==========================================
const resultadoFinal = [];

for (const chave in agrupamento) {
  const grupo = agrupamento[chave];

  // Arredondamento exato de 2 casas
  const valorFinal = Math.round(grupo.valor_total * 100) / 100;

  // Pega o ID da Linha no Monday
  let itemIdMonday = null;
  if (grupo.contrato === 'SEDUC') {
      itemIdMonday = dicionarioIds['SEDUC SEDE'] || dicionarioIds['SEDUC ESCOLA'];
  } else {
      itemIdMonday = dicionarioIds[grupo.contrato];
  }

  // Se achou a linha e tem valor para lançar, envia para a saída
  if (itemIdMonday && valorFinal > 0) {
    resultadoFinal.push({
      json: {
        contrato: grupo.contrato,
        beneficio_tipo: grupo.beneficio,
        item_id: itemIdMonday,       
        column_id: grupo.column_id,  
        valor_final: valorFinal.toString() // Transforma em texto p/ evitar erro do Monday
      }
    });
  }
}

return resultadoFinal;

