const formatarValor = v => Number(v).toFixed(2).replace('.', ',');

function montarDadosXml(codBeneficio, vlrTotal, tpBen) {
  const valorRM = formatarValor(vlrTotal);
  const xml = `<PRJ3230976>
              <ZMDHSTBENFUNC>
                <ID>-1</ID>
                <CODCOLIGADA>3</CODCOLIGADA>
                <ANOCOMP>${anoComp}</ANOCOMP>
                <MESCOMP>${mesComp}</MESCOMP>
                <ANOREF>${anoComp}</ANOREF>
                <MESREF>${mesComp}</MESREF>
                <CHAPA>${chapa}</CHAPA>
                <NOME>${nome}</NOME>
                <CODBENEFICIO>${codBeneficio}</CODBENEFICIO>
                <VLRTOTAL>${valorRM}</VLRTOTAL>
                <TPBEN>${tpBen}</TPBEN>
                <CATFUN>1</CATFUN>
              </ZMDHSTBENFUNC>
            </PRJ3230976>`;
  return xml;
}

const registros = [];
if (dados.creditoVR > 0) registros.push({ tipo: 'CREDITO_VR', dadosXml: montarDadosXml(1, dados.creditoVR, 0), valor: dados.creditoVR });
if (dados.creditoVT > 0) registros.push({ tipo: 'CREDITO_VT', dadosXml: montarDadosXml(2, dados.creditoVT, 0), valor: dados.creditoVT });

return registros.map(r => ({ json: r }));

