const dadosNo3 = $('Code in JavaScript1').first().json;
const evento = $('Webhook').first().json.body.event;
const rm = $('HTTP Request').first().json;
function getRM(...keys) { for (const k of keys) if (rm[k] !== undefined && rm[k] !== null && rm[k] !== '') return rm[k]; return ''; }
function nomeNorm(s) { return String(s || '').normalize('NFD').replace(/[̀-ͯ]/g, '').toUpperCase().trim(); }
const contrato = nomeNorm(evento.columnValues.color_mktcnxwn.label.text);
const funcao = nomeNorm(getRM('Fun\u00e7\u00e3o', 'Funcao', 'funcao'));
