  descricaoSecaoRM: getRM('Descri\u00e7\u00e3o Se\u00e7\u00e3o', 'Descricao Secao', 'descricaoSecao'),
  chapaRM: getRM('Matr\u00edcula/Chapa', 'Matricula/Chapa', 'chapa'),
  dataAdmissaoRM: getRM('Data de Admiss\u00e3o', 'Data de Admissao', 'dataAdmissao'),
  funcaoRM: getRM('Fun\u00e7\u00e3o', 'Funcao', 'funcao'),
};

function round2(n) { return Math.round(Number(n || 0) * 100) / 100; }
function num(v) { return Number(String(v || '0').replace(',', '.')) || 0; }
function valoresItemsMonday() {
  const resp = $('Buscar Valores Beneficios').first().json;
  if (Array.isArray(resp.errors) && resp.errors.length > 0) throw new Error(resp.errors.map(e => e.message).join(' | '));
  return resp?.data?.boards?.[0]?.items_page?.items || [];
}
function colTitle(cv) { return nomeNorm(cv?.column?.title || cv?.id || ''); }
function colPorTitulo(item, candidatos) {
  const alvo = candidatos.map(nomeNorm);
  for (const cv of item.column_values || []) {
    const t = colTitle(cv);
    if (alvo.some(a => t === a || t.includes(a))) return cv;
  }
  return null;
}
function valorTexto(item, candidatos) { return colPorTitulo(item, candidatos)?.text || ''; }
function valorNumero(item, candidatos) { return num(valorTexto(item, candidatos)); }
function linhaAtiva(item) {
  const t = nomeNorm(valorTexto(item, ['Ativo', 'Status', 'Habilitado']));
  return !t || ['SIM', 'ATIVO', 'TRUE', '1', 'HABILITADO', 'REALIZADO', 'DONE'].includes(t);
}
function contratoLinha(item) { return nomeNorm(valorTexto(item, ['Contrato'])); }
function regraLinha(item) { return nomeNorm(valorTexto(item, ['Regra', 'Funcao', 'Cargo'])); }
function prioridadeLinha(item) { return valorNumero(item, ['Prioridade', 'Ordem']) || 0; }
function resolverValoresBeneficios() {
  const items = valoresItemsMonday().filter(linhaAtiva);
  if (items.length === 0) return { erro: 'valores_beneficios_vazio', mensagem: 'O board de valores de beneficios nao retornou linhas ativas.' };
  const matches = [];
  for (const item of items) {
    const c = contratoLinha(item);
    const regra = regraLinha(item);
    const contratoPadrao = ['PADRAO', 'GLOBAL', '*'].includes(c);
    if (c && c !== contrato && !contratoPadrao) continue;
    const regraPadrao = !regra || ['PADRAO', 'GERAL', '*'].includes(regra);
    if (!regraPadrao && !funcao.includes(regra)) continue;
    const especificidade = (c === contrato ? 1000 : 0) + (!regraPadrao ? 100 : 0) + prioridadeLinha(item);
    matches.push({ item, especificidade });
  }
  if (matches.length === 0) return { erro: 'valores_beneficios_sem_regra', mensagem: 'Nenhuma regra ativa encontrada para contrato ' + (contrato || '(vazio)') + ' e funcao ' + (funcao || '(vazia)') + '.' };
  matches.sort((a, b) => b.especificidade - a.especificidade);
  const escolhido = matches[0].item;
  const vrDia = valorNumero(escolhido, ['VR', 'Valor VR']);
  const vtDia = valorNumero(escolhido, ['VT', 'Valor VT', 'Vale Transporte']);
  if (!vrDia && !vtDia) return { erro: 'valores_beneficios_sem_valor', mensagem: 'Regra encontrada, mas VR e VT estao vazios/zerados.' };
  const contratoTxt = valorTexto(escolhido, ['Contrato']) || contrato;
  const regraTxt = valorTexto(escolhido, ['Regra', 'Funcao', 'Cargo']);
  return { vrDia, vtDia, regraAplicada: 'Board valores - ' + contratoTxt + (regraTxt ? ' / ' + regraTxt : ''), fonteValores: 'board' };
}
function failValores(code, mensagem) { return [{ json: { _statusCode: 500, _erro: code, mensagem, acao: 'skip' } }]; }
let valoresBeneficios;
try { valoresBeneficios = resolverValoresBeneficios(); }
catch (e) { return failValores('erro_ler_valores_beneficios', e.message || 'Erro ao ler board de valores de beneficios.'); }
