  const credito = parseNumero(getCol(item, 'n_meros5__1')?.text);
  const debito = parseNumero(getCol(item, 'n_meros9__1')?.text);

  return round2(saldoInicial + credito - debito);
}

const items = consultaSaldo?.data?.boards?.[0]?.groups?.[0]?.items_page?.items || [];

const itemAnterior = [...items]
  .reverse()
  .find((item) => {
    const temSaldoInicial = getCol(item, 'n_meros__1')?.text;
    const temCredito = getCol(item, 'n_meros5__1')?.text;
    const temDebito = getCol(item, 'n_meros9__1')?.text;

    return temSaldoInicial || temCredito || temDebito;
  });

if (!itemAnterior) {
  throw new Error(`Não encontrei item anterior com saldo/crédito/débito no grupo ${groupId}`);
}

const saldoInicial = calcularSaldoFinal(itemAnterior);

let creditoOrderId = '';
try {
  creditoOrderId = String($('HTTP Request4').first().json.allowanceOrderId || '');
} catch (e) {}

const hoje = new Date();
const dataHoje = hoje.toISOString().slice(0, 10);

const contratoMap = {
  SEMSA: 'SEMSA',
  DETRAN: 'DETRAN',
  'TRE PB': 'TRE PB',
  CETAM: 'CETAM',
  'SEDUC SEDE': 'SEDUC SEDE',
  'SEDUC ESCOLA': 'SEDUC ESCOLA',
  'SEDUC INTERIOR': 'SEDUC INTERIOR',
  ADMINISTRATIVO: 'ADMINISTRATIVO'
};

const contratoLabel = contratoMap[dados.contrato] || dados.contrato;
const itemName = `INTERMITENTE - ${dados.nomeEmpregado} (${dataHoje})`;

const columnValues = {
  color_mkpef3mp: { label: contratoLabel },
  n_meros__1: String(saldoInicial),
  n_meros9__1: String(totalCredito),
  dup__of_data_do_cr_dito__1: { date: dataHoje },
  status3__1: { label: 'INTERMITENTE' }
};

const columnValuesJson = JSON.stringify(columnValues);
const columnValuesEscaped = JSON.stringify(columnValuesJson);

const query = `mutation {
  create_item(
    board_id: ${BOARD_CONTROLE_CAJU},
    group_id: ${JSON.stringify(groupId)},
    item_name: ${JSON.stringify(itemName)},
    column_values: ${columnValuesEscaped},
    create_labels_if_missing: true
  ) {
    id
  }
}`;

return [{
  json: {
    query,
    _debug: {
      saldoInicial,
      itemAnteriorId: itemAnterior.id,
      itemAnteriorNome: itemAnterior.name,
      totalCredito,
      creditoVR,
      creditoVT,
      creditoOrderId,
      contratoLabel,
      groupId
    }
  }
}];

const BOARD_CONTROLE_CAJU = 7833600425;

const hoje = new Date();
const ano = hoje.getFullYear();
const mes = hoje.getMonth() + 1;
const chave = `${ano}-${String(mes).padStart(2, '0')}`;

const gruposPorMes = {
  '2026-05': 'group_mm31bqs0',
  '2026-04': 'group_mm20h678',
  '2026-03': 'group_mm1245qb',
  '2026-02': 'group_mm0aab66',
  '2026-01': 'group_mkz7w2zx'
};

const groupId = gruposPorMes[chave];

if (!groupId) {
  throw new Error(`Grupo do Controle Caju não mapeado para ${chave}`);
}

const query = `query {
  boards(ids: [${BOARD_CONTROLE_CAJU}]) {
    groups(ids: ["${groupId}"]) {
      id
      title
      items_page(limit: 500) {
        items {
          id
          name
          column_values(ids: ["n_meros__1", "n_meros5__1", "n_meros9__1"]) {
            id
            text
            value
          }
        }
      }
    }
  }
}`;

return [{ json: { query, groupId } }];

const dados = $('Code in JavaScript8').first().json;

const ROOT_FOLDER_ID = '1U_27eGastNLI_D8BnUB4ZYx0sadpKVhu';

const meses = [
  'JANEIRO',
  'FEVEREIRO',
  'MARÇO',
  'ABRIL',
  'MAIO',
  'JUNHO',
  'JULHO',
  'AGOSTO',
  'SETEMBRO',
  'OUTUBRO',
  'NOVEMBRO',
  'DEZEMBRO'
];

const contratoDriveMap = {
  SEMSA: '85 - SEMSA',
  CETAM: '74 - CETAM',
  'TRE PB': '79 - TRE PB',
  'SEDUC SEDE': 'SEDUC SEDE',
  'SEDUC ESCOLA': '11.01 - SEDUC ESCOLA',
  'SEDUC INTERIOR': '11.02 - SEDUC INTERIOR',
  'BARCO CONTATO': '15 - BARCO CONTATO',
  DETRAN: 'DETRAN',
  ADMINISTRATIVO: 'ADMINISTRATIVO'
};

function parseDate(dateStr) {
  const [ano, mes, dia] = String(dateStr).split('-').map(Number);
  return { ano, mes, dia };
}

const inicio = parseDate(dados.dataInicio);
const fim = parseDate(dados.dataFim);

if (!inicio.ano || !inicio.mes || !inicio.dia || !fim.ano || !fim.mes || !fim.dia) {
  throw new Error(`Datas inválidas para Drive: ${dados.dataInicio} a ${dados.dataFim}`);
}

if (inicio.mes < 1 || inicio.mes > 12 || fim.mes < 1 || fim.mes > 12) {
  throw new Error(`Mês inválido para Drive: ${dados.dataInicio} a ${dados.dataFim}`);
}

const ano = String(inicio.ano);
const mesFolder = `${String(inicio.mes).padStart(2, '0')} - ${meses[inicio.mes - 1]}`;
const contratoFolder = contratoDriveMap[dados.contrato] || dados.contrato;
const pessoaFolder = String(dados.nomeEmpregado || '').trim().toUpperCase();

if (!pessoaFolder) {
  throw new Error('Nome do intermitente vazio ao montar caminho do Drive.');
}

const convocacaoFolder = `${String(inicio.dia).padStart(2, '0')} À ${String(fim.dia).padStart(2, '0')}/${String(fim.mes).padStart(2, '0')}/${fim.ano}`;

const path = [
  ano,
  mesFolder,
  'CONTATO',
  contratoFolder,
  'INTERMITENTE - PONTUAL',
  pessoaFolder,
  convocacaoFolder,
  'VT E VR'
];

return [{
  json: {
    rootFolderId: ROOT_FOLDER_ID,
    parentId: ROOT_FOLDER_ID,
    path,
    pathIndex: 0,
    loopGuard: 0,
    done: false
  }
}];

const state = $input.first().json;

if (state.done) {
  return [{ json: state }];
}

const loopGuard = Number(state.loopGuard || 0) + 1;
const maxLoop = Number(state.path?.length || 0) + 2;

if (loopGuard > maxLoop) {
  throw new Error(`Loop Drive excedeu limite: ${loopGuard}/${maxLoop}. Caminho: ${(state.path || []).join(' / ')}`);
}

if (!Array.isArray(state.path) || state.path.length === 0) {
  throw new Error('Path do Drive vazio ou inválido.');
}

if (state.pathIndex < 0 || state.pathIndex >= state.path.length) {
  throw new Error(`pathIndex inválido: ${state.pathIndex}/${state.path.length}`);
}

if (!state.parentId) {
  throw new Error(`parentId vazio no índice ${state.pathIndex}`);
}

const targetName = state.path[state.pathIndex];

const q = [
  `'${state.parentId}' in parents`,
  `mimeType = 'application/vnd.google-apps.folder'`,
  `trashed = false`
].join(' and ');

return [{
  json: {
    ...state,
    loopGuard,
    targetName,
    listQuery: q
  }
}];

const response = $input.first().json;

let state;
try {
  state = $('Preparar Busca Pasta Drive').last().json;
} catch (e) {
  state = $('Preparar Busca Pasta Drive').first().json;
}

const files = response.files || [];

function normalizeName(name) {
  return String(name || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[ºª]/g, '')
    .replace(/\s+/g, ' ')
    .replace(/\s*-\s*/g, ' - ')
    .trim()
    .toUpperCase();
}

function removePrefix(name) {
  return normalizeName(name)
    .replace(/^\d+(\.\d+)?\s*-\s*/, '')
    .trim();
}

function scoreFolder(existingName, expectedName) {
  const existing = normalizeName(existingName);
  const expected = normalizeName(expectedName);

  if (existing === expected) return 100;
  if (removePrefix(existingName) === removePrefix(expectedName)) return 80;

  return 0;
}

const matches = files
  .map((file) => ({
    ...file,
    score: scoreFolder(file.name, state.targetName)
  }))
  .filter((file) => file.score > 0)
  .sort((a, b) => b.score - a.score);

const found = matches[0];

if (found) {
  const nextIndex = state.pathIndex + 1;
  const done = nextIndex >= state.path.length;

  return [{
    json: {
      ...state,
      parentId: found.id,
      pathIndex: nextIndex,
      done,
      precisaCriar: false,
      finalFolderId: done ? found.id : state.finalFolderId,
      finalFolderName: done ? found.name : state.finalFolderName,
      finalFolderUrl: done ? found.webViewLink : state.finalFolderUrl,
      matchedFolder: found,
      _debugResolver: {
        targetName: state.targetName,
        foundName: found.name,
        foundId: found.id,
        score: found.score,
        pathIndexAnterior: state.pathIndex,
        pathIndexProximo: nextIndex,
        done
      }
    }
  }];
}

return [{
  json: {
    ...state,
    precisaCriar: true,
    createBody: {
      name: state.targetName,
      mimeType: 'application/vnd.google-apps.folder',
      parents: [state.parentId]
    },
    _debugResolver: {
      targetName: state.targetName,
      parentId: state.parentId,
      encontrados: files.map((file) => file.name),
      acao: 'criar_pasta'
    }
  }
}];

const state = $input.first().json;

if (!state.finalFolderId || !state.finalFolderUrl) {
  throw new Error('Caminho do Drive terminou sem pasta final.');
}

return [{
  json: {
    documentosFolderId: state.finalFolderId,
    documentosFolderName: state.finalFolderName,
    documentosFolderUrl: state.finalFolderUrl,
    documentosFolderPath: state.path.join(' / ')
  }
}];

const created = $input.first().json;

let state;
try {
  state = $('Resolver Pasta Drive').last().json;
} catch (e) {
  state = $('Resolver Pasta Drive').first().json;
}

if (!created?.id) {
  throw new Error(`Falha ao criar pasta: ${state?.targetName || 'sem nome'}`);
}

const nextIndex = state.pathIndex + 1;
const done = nextIndex >= state.path.length;

return [{
  json: {
    ...state,
    parentId: created.id,
    pathIndex: nextIndex,
    done,
    finalFolderId: done ? created.id : state.finalFolderId,
    finalFolderName: done ? created.name : state.finalFolderName,
    finalFolderUrl: done ? created.webViewLink : state.finalFolderUrl,
    createdFolder: created
  }
}];

// Prepara leitura obrigatoria do board de valores de beneficios.
// Usa variavel n8n BOARD_VALORES_BENEFICIOS_ID quando existir; senao usa o board atual.
let vars = {};
try { vars = $vars || {}; } catch {}
const boardId = Number(vars.BOARD_VALORES_BENEFICIOS_ID || 18413870370) || 0;
if (!boardId) {
  return [{ json: { _statusCode: 500, _erro: 'board_valores_nao_configurado', mensagem: 'Configure BOARD_VALORES_BENEFICIOS_ID no n8n.' } }];
}
const queryValoresBeneficios = `query { boards(ids: [${boardId}]) { id name items_page(limit: 500) { items { id name column_values { id text value column { title } } } } } }`;
return [{ json: { ...$json, board_valores_beneficios_id: boardId, queryValoresBeneficios } }];

