parameters.jsCode:
// ==================================================
// MAPEAMENTO DE COLUNAS - BOARD FISCAL (LOOP)
// Autor: Mike | Aions Corp
// Propósito: Mapear múltiplos itens + consolidar com Compras
// Versão: 2.1 - CORREÇÃO DE MODO
// ==================================================

const itemsFiscal = $input.all();
const comprasData = $('Mapear Colunas - Compras').item.json;

// ========== FUNÇÕES HELPER ==========
function getColumn(columnValues, id) {
  return columnValues.find(col => col.id === id);
}

function getText(columnValues, id) {
  const col = getColumn(columnValues, id);
  return col ? (col.text || '') : '';
}

// ========== PROCESSA CADA ITEM DO FISCAL ==========
const mappedItems = itemsFiscal.map(item => {
  const cv = item.json.column_values;

  return {
    // ========== IDENTIFICAÇÃO ==========
    pulse_id_fiscal: item.json.id,
    nome_item_fiscal: item.json.name,

    // ========== DADOS DO FISCAL ==========
    cnpj_fiscal: getText(cv, 'text_mkxn60zf'),
    numero_nf_fiscal: getText(cv, 'numeric_mkx03rz2'),

    // ========== IDs DAS COLUNAS FISCAL (para changeColumnValue) ==========
    id_coluna_arquivo: 'text_mkxsjs4b',
    id_coluna_numero_oc: 'numeric_mkxth4jk',
    id_coluna_valor_pago: 'numeric_mkxsr9k9',
    id_coluna_valor_nf: 'numeric_mkxszed1',
    id_coluna_status: 'color_mkxt3v8n',

    // ========== DADOS DO COMPRAS (para inserir no Fiscal) ==========
    cnpj_compras: comprasData.cnpj,
    numero_nf_compras: comprasData.numero_nota_fiscal,
    link_drive: comprasData.link_drive,
    numero_pc: comprasData.numero_pc,
    valor_pago_compras: comprasData.valor_pago,
    valor_nf_compras: comprasData.valor_nf,
    vencimento: comprasData.vencimento,
    item_id_compras: comprasData.item_id,
    item_name_compras: comprasData.item_name
  };
});

return mappedItems;

// ==================================================
// MAPEAMENTO DE COLUNAS - BOARD COMPRAS
// Versão: 2.2 - Inclusão da condição de Aprovação
// ==================================================

const columnValues = $input.item.json.column_values;

// ========== FUNÇÕES HELPER ==========
function getColumn(id) {
  return columnValues.find(col => col.id === id);
}

function getText(id) {
  const col = getColumn(id);
  return col ? (col.text || '') : '';
}

function getValue(id) {
  const col = getColumn(id);
  return col && col.value ? col.value : '';
}

// CORREÇÃO AQUI: Simplificado para pegar o .text diretamente
function getStatusLabel(id) {
  const col = getColumn(id);
  return col ? (col.text || '') : ''; 
}

// ========== MAPEAMENTO DOS CAMPOS ==========
const mapped = {
  // Metadados do item
  item_id: $input.item.json.id,
  item_name: $input.item.json.name,
  board_id: $input.item.json.board?.id || '18257522804',

  // Campos mapeados por ID
  cnpj: getText('text_mkx0gak5'),
  numero_nota_fiscal: getText('numeric_mkx0nenv'),
  numero_pc: getText('numeric_mkx0cqda'),
  valor_pago: getText('numeric_mkx075mm'),
  valor_nf: getText('numeric_mkx03rrm'),
  vencimento: getText('date_mky2wftt'),
  tipo_documento: getStatusLabel('color_mky38wws'), // Agora vai vir "NAO FISCAL"

  // *** CAMPO NOVO: Traz o texto exato que está na coluna de autorização da diretoria ***
  status_autorizacao_diretoria: getStatusLabel('color_mkx0dfjk'),

  // IDs das colunas
  id_coluna_status_jornada: 'color_mkx0anww',

  // Processa o link do drive
  link_drive: (() => {
    try {
      const linkValue = getValue('link_mkx0jg7b');
      if (!linkValue) return '';
      const parsed = JSON.parse(linkValue);
      return parsed.url || '';
    } catch (e) {
      console.error('Erro ao fazer parse do link:', e);
      return '';
    }
  })(),

  // ========== VALIDAÇÕES BOOLEANAS ==========
  tem_cnpj: getText('text_mkx0gak5').length > 0,
  tem_vencimento: getText('date_mky2wftt').length > 0,
  tem_numero_nf: getText('numeric_mkx0nenv').length > 0,

  // LÓGICA BLINDADA: 
  // 1. Pega o texto (agora corrigido)
  // 2. Transforma em maiúsculo
  // 3. Se NÃO incluir "NAO", retorna true (é fiscal).
  // 4. Se incluir "NAO", retorna false (não é fiscal).
  e_documento_fiscal: !getStatusLabel('color_mky38wws').toUpperCase().includes('NAO'),

  // *** CONDIÇÃO NOVA: Verifica se a palavra "APROVADA" (em maiúsculo para evitar erros) está no status ***
  esta_aprovada_diretoria: getStatusLabel('color_mkx0dfjk').toUpperCase().includes('APROVADA'),

  // ========== DADOS ORIGINAIS ==========
  _original_column_values: columnValues
};

return mapped;

