const claudeResponse = items[0].json.content[0].text;

// Remove os backticks e "json" do markdown
const jsonString = claudeResponse
  .replace(/```json\n/g, '')
  .replace(/\n```/g, '')
  .trim();

// Converte para objeto JavaScript
const dados = JSON.parse(jsonString);

return {
  json: {
    nome: dados.nome,
    data_inicio: dados.data_inicio,
    data_fim: dados.data_fim,
    // Mantém IDs para atualizar o Monday depois
    pulseId: items[0].json.pulseId,
    boardId: items[0].json.boardId
  }
};

// Extrai os valores das colunas do Monday
const columnValues = $input.item.json.column_values;

// Função auxiliar para pegar valor numérico de uma coluna
function getNumericValue(columnId) {
  const column = columnValues.find(col => col.id === columnId);
  if (!column || !column.value || column.value === 'null') {
    return 0;
  }
  // Remove aspas do JSON e converte para número
  return parseFloat(column.value.replace(/"/g, '')) || 0;
}

// Extrai os valores necessários
const diasUteisMesVT = getNumericValue('numeric2');        // Dias Úteis/Mês - VT
const diasUteisMesVR = getNumericValue('numeric21');       // Dias Úteis/Mês - VR
const vtDiario = getNumericValue('n_meros0');              // VT - Diário
const vrUnitario = getNumericValue('vr___saldo');          // VR - Unitário
const diasUteisIA = getNumericValue('numeric_mkzwatp0');   // Dias Úteis (I.A)

// Cálculos MANUAL (feitos pelo operador)
const vtManual = diasUteisMesVT * vtDiario;
const vrManual = diasUteisMesVR * vrUnitario;

// Cálculos I.A (baseado na análise da imagem)
const vtIA = diasUteisIA * vtDiario;
const vrIA = diasUteisIA * vrUnitario;

// Validação: I.A = MANUAL?
const vtIgual = vtIA === vtManual;
const vrIgual = vrIA === vrManual;
const tudoIgual = vtIgual && vrIgual;

// Prepara resultado estruturado
return {
  // Valores extraídos
  diasUteisMesVT: diasUteisMesVT,
  diasUteisMesVR: diasUteisMesVR,
  vtDiario: vtDiario,
  vrUnitario: vrUnitario,
  diasUteisIA: diasUteisIA,

  // Cálculos MANUAL
  vtManual: vtManual,
  vrManual: vrManual,

  // Cálculos I.A
  vtIA: vtIA,
  vrIA: vrIA,

  // Validações
  vtIgual: vtIgual,
  vrIgual: vrIgual,
  tudoIgual: tudoIgual,

  // Status textual (para facilitar visualização)
  status: tudoIgual ? 'Igual' : 'Divergente',

  // Detalhes da divergência (se houver)
  divergencia: {
    vt: vtIgual ? null : {
      manual: vtManual,
      ia: vtIA,
      diferenca: Math.abs(vtManual - vtIA)
    },
    vr: vrIgual ? null : {
      manual: vrManual,
      ia: vrIA,
      diferenca: Math.abs(vrManual - vrIA)
    }
  },

  // Mantém IDs para próximos nós
  pulseId: $input.item.json.id,
  pulseName: $input.item.json.name
};

const outputCalculado = []; 

for (const item of $input.all()) {
  const itemMonday = item.json;
  let v = {}; 

  // Função aprimorada para extrair valores financeiros (Dinheiro)
  const parseNum = (col) => {
    if (!col || !col.text) return 0;

    let texto = col.text.toString().trim();
    // Remove R$, letras e espaços, mantendo apenas números, vírgula, ponto e sinal de menos
    texto = texto.replace(/[^0-9.,\-]/g, '');

    // Se o número estiver no padrão brasileiro (ex: 1.234,56), removemos os pontos de milhar
    if (texto.includes(',') && texto.includes('.')) {
       texto = texto.replace(/\./g, ''); // Remove o ponto de milhar
    }

    // Transforma a vírgula decimal em ponto (padrão do JavaScript)
    texto = texto.replace(',', '.');

    return parseFloat(texto) || 0;
  };

  // 1. MAPEAMENTO DAS COLUNAS (Busca usando os termos do Monday)
  if (itemMonday.column_values) {
    itemMonday.column_values.forEach(col => {
      const t = (col.column && col.column.title ? col.column.title : col.title || '').toLowerCase().trim();
      const val = parseNum(col);

      // --- Colunas para DIAS VR ---
      if (t.includes('úteis/mês - vr')) v.dias_uteis_vr = val;
      if (t.includes('descontar vr - extra')) v.desc_vr_extra = val;

      // --- Colunas para DIAS VT ---
      if (t.includes('úteis/mês - vt')) v.dias_uteis_vt = val;
      if (t.includes('descontar vt - extra')) v.desc_vt_extra = val;

      // --- Colunas de Descontos Comuns (Dias) ---
      if (t.includes('falta - mês anterior') || t.includes('mês anterior')) v.falta_mes_anterior = val;
      if (t.includes('atestados')) v.atestados = val;
      if (t.includes('declaração') && t.includes('-6hrs')) v.declaracao = val;
      if (t.includes('atraso') && t.includes('-6 horas')) v.atraso = val;

      // --- Colunas Financeiras VR (Dinheiro) ---
      if (t.includes('vr - unitário') || t.includes('vr - unitario')) v.vr_unitario = val;
      if (t.includes('vr - mensal')) v.vr_mensal = val;
      if (t.includes('desconto - vr')) v.desconto_vr = val;

      // --- Colunas Financeiras VT (Dinheiro) ---
      if (t.includes('vt - diário') || t.includes('vt - diario')) v.vt_diario = val;
      if (t.includes('desconto - vt')) v.desconto_vt = val;
    });
  }

  // 2. CÁLCULO DOS DIAS (Números inteiros/fracionados de dias)

  // Cálculo: Dias de VR = {Dias Úteis/Mês - VR} - ({Dia a descontar VR - EXTRA} + {Falta - Mês Anterior} + {ST - D.U. Atestados} + {ST - Declaração (-6hrs trab.)} + {OP - Desconto por Atraso -6 horas})
  const soma_descontos_dias_vr = (v.desc_vr_extra || 0) + (v.falta_mes_anterior || 0) + (v.atestados || 0) + (v.declaracao || 0) + (v.atraso || 0);
  const dias_vr = (v.dias_uteis_vr || 0) - soma_descontos_dias_vr;

  // Cálculo: Dias de VT = {Dias Úteis/Mês - VT} - {ST - D.U. Atestados} - {Dia a descontar VT - EXTRA} - {Falta - Mês Anterior}
  const dias_vt = (v.dias_uteis_vt || 0) - (v.atestados || 0) - (v.desc_vt_extra || 0) - (v.falta_mes_anterior || 0);

  // 3. CÁLCULOS FINANCEIROS FINAIS (Garantindo formato de Dinheiro/Real)

  // VR Passo A: VR - TOTAL = {Dias de VR} * {VR - Unitário}
  // Uso do Number e toFixed(2) garante precisão de duas casas decimais (Ex: 150.50)
  const vr_total = Number((dias_vr * (v.vr_unitario || 0)).toFixed(2));

  // VR Passo B: Resultado Final = {VR - TOTAL} + {VR - MENSAL} - {DESCONTO - VR}
  let resVR = Number((vr_total + (v.vr_mensal || 0) - (v.desconto_vr || 0)).toFixed(2));

  // VT Final: ({Dias de VT} * {VT - Diário}) - {DESCONTO - VT}
  let resVT = Number(((dias_vt * (v.vt_diario || 0)) - (v.desconto_vt || 0)).toFixed(2));

  // Trava de Segurança (Se por algum motivo der negativo, zera)
  itemMonday.Resultado_Final_VT = Math.max(0, resVT);
  itemMonday.Resultado_Final_VR = Math.max(0, resVR);

  // AUDITORIA FINANCEIRA (Confira os valores no OUTPUT)
  itemMonday.DEBUG_FINAL = {
    VT: { 
      dias_calculados: dias_vt, 
      resultado: itemMonday.Resultado_Final_VT 
    },
    VR: { 
      dias_calculados: dias_vr, 
      bruto_total: vr_total, 
      resultado: itemMonday.Resultado_Final_VR 
    }
  };

  outputCalculado.push({ json: itemMonday });
}

return outputCalculado;

