    valor_nf_compras: comprasData.valor_nf,
    vencimento: comprasData.vencimento,
    item_id_compras: comprasData.item_id,
    item_name_compras: comprasData.item_name
  };
});

return mappedItems;

const items = items[0].json.column_values;

function getText(id) {
  try {
    const col = items.find(c => c.id === id);
    return col && col.text ? col.text.trim() : '';
  } catch (e) {
    return '';
  }
}

function getValue(id) {
  try {
    const col = items.find(c => c.id === id);
    return col && col.value ? JSON.parse(col.value) : null;
  } catch (e) {
    return null;
  }
}

const cnpj = getText('text_mkx0gak5');
