const item = $input.first().json;
const colunas = item.column_values;

const termoVT = colunas.find(c => c.id === 'file_mkvfwdme');
const kitAdmissional = colunas.find(c => c.id === 'file_mkvgr4fn');

const temTermoVT = termoVT?.value !== null && termoVT?.value !== '';
const temKitAdmissional = kitAdmissional?.value !== null && kitAdmissional?.value !== '';

if (!temTermoVT || !temKitAdmissional) {
  return [{
    json: {
      continuar: false,
      motivo: `Pendente - Termo VT: ${temTermoVT}, Kit Admissional: ${temKitAdmissional}`,
      nome: item.name
    }
  }];
}

const termoVTFiles = JSON.parse(termoVT.value).files;
const kitFiles = JSON.parse(kitAdmissional.value).files;

const termoVTAssetIds = termoVTFiles.map(f => f.assetId);
const kitAssetIds = kitFiles.map(f => f.assetId);

const dataAdmissao = colunas.find(c => c.id === 'date_mkv8ka5k');
const dataValue = JSON.parse(dataAdmissao.value);
const mes = new Date(dataValue.date + 'T00:00:00').getMonth() + 1;

const pastasCompetencia = {
  1:  '1pCsKrLr7hNFbVebz7ejnwqQZ4hfVDti4',
  2:  '1UfUy7X-L94yKKGjUzL-SCXtbA604lFYF',
  3:  '1Ce32YIJLaQbZbwQfER8_ROh-D28qh_bJ',
  4:  '1JJL35aBy7jYMLjNjpHC3u9_pyB95XDyw',
  5:  '1ne_e0C4bW6AcI3X08ju7jvlzlaxJVdJT',
  6:  '1Fab1DGSTgZN5odSe6A9UuD7kKhvke60H',
  7:  '1jkEB65F9b5vnuzV7EpM4WZqyZeIcII5x',
  8:  '1IbEAhOgCoNPtnb80KSybtorlBMWOXThY',
  9:  '1wdbdjjs7Ogw4Yo_dR-m94yOd0h8nCMdB',
  10: '1qDMHT240T_Cd-wgTgOozabgjeDDAohDx',
  11: '1arRIsdLDwALKyGypBSc5C6jEIuvCMXLy',
  12: '14BqqdFXIH5XeofccJ-1EUvLA0pe-R_8g'
};

const meses = {
  1: 'Janeiro', 2: 'Fevereiro', 3: 'Março',
  4: 'Abril', 5: 'Maio', 6: 'Junho',
  7: 'Julho', 8: 'Agosto', 9: 'Setembro',
  10: 'Outubro', 11: 'Novembro', 12: 'Dezembro'
};

const pastaId = pastasCompetencia[mes];

return [{
  json: {
    continuar: true,
    nome: item.name,
    itemId: item.id,
    mesNumero: mes,
    mesNome: meses[mes],
    pastaGoogleDriveId: pastaId,
    pastaGoogleDriveLink: `https://drive.google.com/drive/folders/${pastaId}`,
    dataAdmissao: dataValue.date,
    termoVTAssetIds,
    kitAdmissionalAssetIds: kitAssetIds,
    todosAssetIds: [...termoVTAssetIds, ...kitAssetIds]
  }
}];

let dados = $input.first().json;

// 1. Limpeza de Dados
let cargo = (dados["NOME FUNÇÃO"] || "").toUpperCase().trim();
let secao = (dados["DESCRIÇÃO SEÇÃO"] || "").toUpperCase().trim();

// 2. Calcular a Idade (Crucial para a regra do CETAM)
let dataNasc = dados["Data de Nascimento"] || "";
let idade = 0;
if (dataNasc) {
  let p = dataNasc.split('/');
  idade = new Date().getFullYear() - parseInt(p[2]);
}

// 3. Empresa e Grupo FIXOS (Esquece a adivinhação da JCF!)
let idGrupo = "group_mm0wpwth"; // Grupo fixo da Contato
let empresaLabel = "Contato";   // Empresa fixa

// 4. Lógica de Contrato
let contratoLabel = "CONTATO"; 

if (secao.includes("TRE")) contratoLabel = "TRE-PB";
else if (secao.includes("SEDUC") && secao.includes("INTERIOR")) contratoLabel = "SEDUC-INTERIOR";
else if (secao.includes("SEDUC")) contratoLabel = "SEDUC";
else if (secao.includes("SEMSA")) contratoLabel = "SEMSA";
else if (secao.includes("DETRAN")) contratoLabel = "DETRAN";
else if (secao.includes("CETAM") && secao.includes("INTERIOR")) contratoLabel = "CETAM-INTERIOR";
else if (secao.includes("CETAM")) contratoLabel = "CETAM";
else if (secao.includes("FAAR")) contratoLabel = "FAAR";
else if (secao.includes("UEA")) contratoLabel = "UEA";
else if (secao.includes("DRF")) contratoLabel = "DRF-AM";
else if (secao.includes("JF-RO") || secao.includes("FEDERAL")) contratoLabel = "JF-RO";
else if (secao.includes("IFAM")) contratoLabel = "IFAM TEFÉ";
else if (secao.includes("FINANCEIRO") || secao.includes("PESSOAL") || secao.includes("CONTABILIDADE") || secao.includes("ADMINISTRA")) contratoLabel = "ADM";

// 5. Lógica de Categoria
let categoriaLabel = "CLT"; // Padrão

if (cargo.includes("APRENDIZ") || secao.includes("APRENDIZ") || secao.includes("ESTAGIARIO") || cargo.includes("ESTAGIARIO")) {
    categoriaLabel = "CONTRATO";
} else if (secao.includes("INTERMITENTE")) {
    categoriaLabel = "INTERMITENTE";
}

// ==========================================
// 6. AS REGRAS DE OURO DO PCMSO (Validade)
// ==========================================
let validadeAnos = 1; // Unidades de Ponta (Contato) = 1 ano padrão
let tipoPrazo = "365 DIAS";

// Regra CETAM: Até 45 anos = 2 anos | Acima de 45 = 1 ano
if (contratoLabel === "CETAM" || contratoLabel === "CETAM-INTERIOR") {
    if (idade <= 45) {
        validadeAnos = 2;
        tipoPrazo = "730 DIAS";
    }
} 
// Regra ADM, Estagiários e Aprendizes = 2 anos
else if (contratoLabel === "ADM" || categoriaLabel === "CONTRATO") {
    validadeAnos = 2;
    tipoPrazo = "730 DIAS";
}

// ==========================================
// 7. O CÁLCULO TEMPORAL DOS EXAMES
// ==========================================
let admissao = dados["Data de Admissão"] || "";
let dataExameFormatada = "";
let dataVencimentoFormatada = "";

if (admissao && admissao.includes('/')) {
    let p = admissao.split('/');
    let dataAdmissao = new Date(parseInt(p[2]), parseInt(p[1]) - 1, parseInt(p[0]));
    let dataAtual = new Date(); // Data de hoje (Março de 2026)

    let ultimoExame = new Date(dataAdmissao);
    let proximoExame = new Date(dataAdmissao);
    proximoExame.setFullYear(proximoExame.getFullYear() + validadeAnos);

    // O Cérebro avança os anos até descobrir qual é o ciclo atual do funcionário
    while (proximoExame < dataAtual) {
        ultimoExame.setFullYear(ultimoExame.getFullYear() + validadeAnos);
        proximoExame.setFullYear(proximoExame.getFullYear() + validadeAnos);
    }

    // Formata bonitinho pro Monday (YYYY-MM-DD)
    dataExameFormatada = `${ultimoExame.getFullYear()}-${String(ultimoExame.getMonth() + 1).padStart(2, '0')}-${String(ultimoExame.getDate()).padStart(2, '0')}`;
    dataVencimentoFormatada = `${proximoExame.getFullYear()}-${String(proximoExame.getMonth() + 1).padStart(2, '0')}-${String(proximoExame.getDate()).padStart(2, '0')}`;
}

// 8. Guardar tudo no pacote
dados.idadeCalculada = idade;
dados.idGrupoCalculado = idGrupo;
dados.empresaLabel = empresaLabel;
dados.contratoLabel = contratoLabel;
dados.categoriaLabel = categoriaLabel;
dados.tipoPrazoCalculado = tipoPrazo;
dados.dataExameFormatada = dataExameFormatada;
dados.dataVencimentoFormatada = dataVencimentoFormatada;

return { json: dados };

// 1. Extrai todos os itens recebidos do nó HTTP Request
const registros = $input.all().map(item => item.json);
const dadosAgrupados = {};

// 2. Itera sobre cada registro para fazer o tratamento e agrupamento
registros.forEach(row => {
    // Usando colchetes para ler chaves com espaços e acentuação perfeitamente
    const funcionario = row['Nome do Funcionário'] || 'N/A';
    const chapa = row['Chapa'] || 'N/A';
    const tipoBeneficio = row['Código Benefício'] || 'N/A';
    const secaoOriginal = row['Código Seção'] || '';

    // Converte o valor para decimal
    const valorBeneficio = parseFloat(row['Valor Total']) || 0;

    // 3. Tratamento da Seção Raiz: Remove os pontos e pega os primeiros 8 dígitos
    const secaoRaiz = secaoOriginal.replace(/\./g, '').substring(0, 8);

    // 4. Criação de uma chave única para agrupar (Chapa + Tipo Benefício + Seção Raiz)
    const chaveAgrupamento = `${chapa}_${tipoBeneficio}_${secaoRaiz}`;

    // 5. Agrupamento e Soma
    if (!dadosAgrupados[chaveAgrupamento]) {
        // Se a chave não existe, cria o registro inicial
        dadosAgrupados[chaveAgrupamento] = {
            Chapa: chapa,
            Funcionario: funcionario,
            CodigoBeneficio: tipoBeneficio,
            SecaoRaiz: secaoRaiz,
            ValorTotal: 0
        };
    }

    // Soma o valor do benefício ao total daquele agrupamento
    dadosAgrupados[chaveAgrupamento].ValorTotal += valorBeneficio;
});

// 6. RETORNO PARA O N8N (Obrigatório para evitar o erro "doesn't return items properly")
return Object.values(dadosAgrupados).map(resultado => ({ json: resultado }));

const meses = ['janeiro', 'fevereiro', 'março', 'abril', 'maio', 'junho', 'julho', 'agosto', 'setembro', 'outubro', 'novembro', 'dezembro'];
const dataAtual = new Date();
// Subtrai 1 mês para pegar o mês de referência (o mesmo do RM Labore)
dataAtual.setMonth(dataAtual.getMonth() - 1);
const nomeMesAlvo = meses[dataAtual.getMonth()];

let idGrupoAlvo = null;

// Procura qual grupo no Monday tem o nome do mês exato
for (const item of $input.all()) {
  const tituloGrupo = (item.json.title || '').toLowerCase().trim();
  if (tituloGrupo === nomeMesAlvo) {
    idGrupoAlvo = item.json.id;
    break;
  }
}

if (!idGrupoAlvo) {
