// ===== EXTRAI DADOS DO WEBHOOK =====
const columnValues = $json.body.event.columnValues;

// ===== VERIFICA TIPO DE BANCO DE HORAS =====
const tipoBancoHoras = columnValues.color_mkz37j7h?.label?.text || '';

// ===== DEFINE HORÁRIO DE USO =====
let horarioUso;

if (tipoBancoHoras === 'INTEGRAL') {
  horarioUso = 'Dia Inteiro';
} else {
  horarioUso = columnValues.color_mkz3cmwe?.label?.text || 'Não informado';
}

// ===== FUNÇÃO PARA FORMATAR DATA =====
function formatarData(dataISO) {
  if (!dataISO) return 'Não informada';
  const [ano, mes, dia] = dataISO.split('-');
  return `${dia}/${mes}/${ano}`;
}

// ===== FORMATA DATA DE USO =====
const dataUsoISO = columnValues.date_mkz32pvx?.date;
const dataUso = formatarData(dataUsoISO);

// ===== FORMATA DATA DA SOLICITAÇÃO (data de criação do item) =====
const dataSolicitacaoISO = $json.body.event.triggerTime; // "2026-01-05T17:25:45.436Z"
const dataSolicitacao = new Date(dataSolicitacaoISO).toLocaleDateString('pt-BR', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
}); // "05/01/2026"

// ===== RETORNA DADOS FORMATADOS =====
return {
  boardId: $json.body.event.boardId,
  pulseId: $json.body.event.pulseId,
  pulseName: $json.body.event.pulseName,
  dataSolicitacao: dataSolicitacao,
