parameters.jsCode:
// ============================================================
// NÓ 2 — Extrair e Tratar Dados do Webhook
// ============================================================
// Entrada: payload bruto do webhook do Monday.com
// Saída: objeto limpo com todos os dados necessários para o fluxo
// ============================================================

const event = $input.first().json.body.event;
const cols = event.columnValues;

// --- Extração dos campos ---
const nomeEmpregado = cols.dropdown_mktadatt.chosenValues[0].name.trim();
const dataInicio = cols.date_mktayxhb.date;       // "2026-03-16"
const dataFim = cols.date_mktasnwq.date;           // "2026-03-20"
const optanteVT = (cols.optante___vt?.label?.text || "NÃO").toUpperCase() === "SIM";
const trabalhaSabado = (cols.color_mktaavmp?.label?.text || "NÃO").toUpperCase() === "SIM";
const interior = (cols.color__1?.label?.text || "NÃO").toUpperCase() === "SIM";
const contratoOrgao = (cols.color_mktcnxwn?.label?.text || "").toUpperCase().trim();

// IDs do Monday para atualizações futuras
const boardId = event.boardId;
const itemId = event.pulseId;

// --- Tratamento do nome para a URL do RM ---
// A API do RM espera o nome com % para o LIKE, ex: %JAMILE JORGINA DOS SANTOS%
// E precisa de encoding na URL
const nomeParaRM = encodeURIComponent(`%${nomeEmpregado}%`);

// URL completa montada para o HTTP Request do próximo nó que precisar
const urlRM = `https://003080:.2099840340@contatoservicos165112.rm.cloudtotvs.com.br:8051/api/framework/v1/consultaSQLServer/RealizaConsulta/BEN%202/3/P/?parameters=$CODCOLIGADA%3D3%3BNOME%3D${nomeParaRM}`;

return [{
  json: {
    // Dados do empregado
    nomeEmpregado,
    nomeParaRM,
    urlRM,

    // Configurações de benefício
    optanteVT,
    trabalhaSabado,
    interior,
    contratoOrgao,

    // Período
    dataInicio,
    dataFim,

    // IDs Monday (para atualizações futuras)
    boardId,
    itemId
  }
}];

// ============================================================
// NÓ 3 — Calcular Dias Úteis (VR e VT com regras distintas)
// ============================================================
// Entrada: dados tratados do Nó 2
// Saída: mesmos dados + diasVR e diasVT calculados
// ============================================================
// Regra:
//   - diasVR = dias úteis seg-sex (sábado NUNCA conta para VR)
//   - diasVT = dias úteis seg-sex, MAS se trabalhaSabado = true,
//     sábados no período também contam para VT
//   - Se optanteVT = false, diasVT = 0
//   - Domingos nunca contam
// ============================================================

const dados = $input.first().json;

const inicio = new Date(dados.dataInicio + "T00:00:00");
const fim = new Date(dados.dataFim + "T00:00:00");

let diasVR = 0;
let diasVT = 0;

// Percorre cada dia do período (inclusive início e fim)
const atual = new Date(inicio);
while (atual <= fim) {
  const diaSemana = atual.getDay(); // 0=Dom, 1=Seg, ..., 5=Sex, 6=Sáb

  if (diaSemana >= 1 && diaSemana <= 5) {
    // Seg a Sex: conta para VR e VT
    diasVR++;
    diasVT++;
  } else if (diaSemana === 6 && dados.trabalhaSabado) {
    // Sábado: conta APENAS para VT se trabalha sábado
    diasVT++;
  }
  // Domingo: não conta para nada

  atual.setDate(atual.getDate() + 1);
}

// Se não é optante de VT, zera os dias de VT
if (!dados.optanteVT) {
  diasVT = 0;
}

return [{
  json: {
    ...dados,
    diasVR,
    diasVT
  }
}];

// ============================================================
// NÓ 6 — Identificar Regra de Benefício
// ============================================================
// Entrada: 
//   - Contrato/Órgão do Webhook (color_mktcnxwn)
//   - Função do RM (HTTP Request)
//   - Dados do Nó 2 e 3 via referência direta
// Saída: valores unitários de VR e VT por dia + dados consolidados
// ============================================================

// --- Referências diretas aos nós (não depende do $input) ---
const dadosNó3 = $('Code in JavaScript1').first().json;
const contrato = $('Webhook').first().json.body.event.columnValues.color_mktcnxwn.label.text.toUpperCase().trim();
const funcaoRM = $('HTTP Request').first().json['Função'].toUpperCase().trim();
const optanteVT = dadosNó3.optanteVT;

// Dados do RM para manter no fluxo (histórico futuro)
const dadosRM = {
  nomeRM: $('HTTP Request').first().json['Nome do Intermitente'],
  secaoRM: $('HTTP Request').first().json['Seção'],
  descricaoSecaoRM: $('HTTP Request').first().json['Descrição Seção'],
  chapaRM: $('HTTP Request').first().json['Matrícula/Chapa'],
  dataAdmissaoRM: $('HTTP Request').first().json['Data de Admissão'],
  funcaoRM: $('HTTP Request').first().json['Função'],
};

// --- Lógica de identificação ---
let vrDia = 0;
let vtDia = 0;
let regraAplicada = '';

if (contrato === 'DETRAN') {

  if (funcaoRM.includes('PORTARIA')) {
    vrDia = 514.50 / 30;
    regraAplicada = 'DETRAN - Agente de Portaria';
  } else if (funcaoRM.includes('MOTO BOY')) {
    vrDia = 27.00;
    regraAplicada = 'DETRAN - Moto Boy';
  } else {
    vrDia = 588.00 / 30;
    regraAplicada = `DETRAN - Outras Funções (${dadosRM.funcaoRM})`;
  }
  vtDia = 10.00;

} else if (contrato === 'TRE PB') {

  vrDia = 660.00 / 30;
  vtDia = 10.40;
  regraAplicada = 'TRE PB';

} else {

  // SEDUC SEDE, SEDUC ESCOLA, SEDUC INTERIOR, CETAM, SEMSA, URUGUAIANA, ADMINISTRATIVO
  vrDia = 24.50;
  vtDia = 10.00;
  regraAplicada = `Padrão (${contrato})`;

}

// Se não é optante de VT, zera o valor unitário de VT
if (!optanteVT) {
  vtDia = 0;
}

// Arredonda valores unitários para 2 casas decimais
vrDia = Math.round(vrDia * 100) / 100;
vtDia = Math.round(vtDia * 100) / 100;

return [{
  json: {
    // Dados do Nó 2/3 (preservados)
    ...dadosNó3,
    // Dados do RM
    ...dadosRM,
    // Dados calculados neste nó
    contrato,
    funcao: dadosRM.funcaoRM,
    regraAplicada,
    vrDia,
    vtDia
  }
}];

// ============================================================
// NÓ 7 — Calcular Valor Bruto Total
// ============================================================
// Entrada: dados do Nó 6 com vrDia, vtDia, diasVR, diasVT
// Saída: mesmos dados + valorBrutoVR e valorBrutoVT
// ============================================================

const dados = $input.first().json;

const valorBrutoVR = Math.round(dados.vrDia * dados.diasVR * 100) / 100;
const valorBrutoVT = Math.round(dados.vtDia * dados.diasVT * 100) / 100;

return [{
  json: {
    ...dados,
    valorBrutoVR,
    valorBrutoVT
  }
}];

// ============================================================
// NÓ 8 — Buscar Descontos no Board do Monday
// ============================================================
// Tipo: HTTP Request (POST)
// URL: https://api.monday.com/v2
// ============================================================
// Configuração do nó HTTP Request no N8N:
//
// Method: POST
// URL: https://api.monday.com/v2
// Authentication: None (usaremos header manual)
// 
// Headers:
//   Content-Type: application/json
//   Authorization: eyJhbGciOiJIUzI1NiJ9.eyJ0aWQiOjQ0MDQyMzQ0NywiYWFpIjoxMSwidWlkIjo0NTk4NTI3NSwiaWFkIjoiMjAyNC0xMS0yM1QxODowNDo1MC4wMDBaIiwicGVyIjoibWU6d3JpdGUiLCJhY3RpZCI6MTI2ODUwMDYsInJnbiI6InVzZTEifQ.rQ4gm1nLNGZnI24LD4awmZIKM67iNZP7GDyI_tquLHA
//
// Body (JSON):
// Use a expressão abaixo no campo "JSON" do body
// ============================================================

// Se preferir montar via Code Node antes do HTTP Request,
// use este código para gerar o body da requisição:

const dados = $input.first().json;
const nomeEmpregado = dados.nomeEmpregado;

const query = `query {
  items_page_by_column_values(
    limit: 1
    board_id: 18400981023
    columns: [
      {
        column_id: "dropdown_mm0rgfrx"
        column_values: ["${nomeEmpregado}"]
      }
    ]
  ) {
    items {
      id
      name
      column_values {
        id
        text
        value
      }
    }
  }
}`;

return [{
  json: {
    ...dados,
    mondayDescontoQuery: {
      query
    }
  }
}];

// ============================================================
// NÓ 9 — Parsear Retorno do Monday e Verificar Desconto Ativo
// ============================================================
// Entrada: retorno do HTTP Request do Monday (board de descontos)
// Saída: dados consolidados + flag de desconto ativo
// ============================================================
// Este nó faz o papel de "preparação" antes do IF nativo do N8N.
// Após este Code Node, use um nó IF do N8N verificando:
//   {{ $json.descontoAtivo }} equals true
// ============================================================

// Dados acumulados dos nós anteriores
const dados = $('Code in JavaScript3').first().json; // Nó 7 - Calcular Valor Bruto
// ↑ AJUSTE O NOME DO NÓ conforme seu workflow

// Retorno do Monday
const response = $input.first().json;
const items = response.data?.items_page_by_column_values?.items || [];

let descontoAtivo = false;
let desconto = {
  itemIdDesconto: null,
  statusDesconto: null,
  descontoVR: 0,
  descontoVT: 0,
  valorDescontadoVR: 0,
  valorDescontadoVT: 0,
  valorResidualVR: 0,
  valorResidualVT: 0,
};

if (items.length > 0) {
  const item = items[0];
  const cols = {};

  // Mapeia column_values em objeto { id: text } para fácil acesso
  for (const col of item.column_values) {
    cols[col.id] = col.text;
  }

  const status = (cols['color_mm0r8mjr'] || '').toUpperCase().trim();

  if (status === 'PENDENTE' || status === 'PARCIAL') {
    descontoAtivo = true;

    desconto.itemIdDesconto = item.id;
    desconto.statusDesconto = status;

    if (status === 'PENDENTE') {
      // Primeiro desconto: usa valor original
      desconto.descontoVR = parseFloat(cols['numeric_mm0rgsaw']) || 0;
      desconto.descontoVT = parseFloat(cols['numeric_mm0r5tca']) || 0;
    } else {
      // Parcial: usa valor residual (o que ainda falta descontar)
      desconto.descontoVR = parseFloat(cols['numeric_mm0r1691']) || 0;
      desconto.descontoVT = parseFloat(cols['numeric_mm0rtwwg']) || 0;
    }

    // Valores já descontados anteriormente (para acumular)
    desconto.valorDescontadoVR = parseFloat(cols['numeric_mm0rqy6z']) || 0;
    desconto.valorDescontadoVT = parseFloat(cols['numeric_mm0r6cn0']) || 0;
    desconto.valorResidualVR = parseFloat(cols['numeric_mm0r1691']) || 0;
    desconto.valorResidualVT = parseFloat(cols['numeric_mm0rtwwg']) || 0;
  }
}

return [{
  json: {
    ...dados,
    descontoAtivo,
    ...desconto
  }
}];

// ============================================================
// NÓ 10 — Calcular Desconto e Valores Líquidos
// ============================================================
// Entrada: dados com valorBrutoVR, valorBrutoVT e dados de desconto
// Saída: valores líquidos + dados para atualizar board de descontos
// ============================================================
// Este nó só executa no caminho TRUE do IF (descontoAtivo = true)
// O caminho FALSE (sem desconto) vai direto pro Merge,
// e os valores brutos se tornam os valores líquidos no Nó 12
// ============================================================

const dados = $input.first().json;

// Valores brutos calculados no Nó 7
const valorBrutoVR = dados.valorBrutoVR;
const valorBrutoVT = dados.valorBrutoVT;

// Quanto precisa descontar nesta rodada
const descontoVR = dados.descontoVR;
const descontoVT = dados.descontoVT;

// --- Cálculo VR ---
let valorEfetivoDescontoVR = 0; // quanto realmente será descontado agora
let novoResidualVR = 0;

if (descontoVR >= valorBrutoVR) {
  // Desconto maior ou igual ao benefício: empregado não recebe VR
  valorEfetivoDescontoVR = valorBrutoVR;
  novoResidualVR = Math.round((descontoVR - valorBrutoVR) * 100) / 100;
} else {
  // Desconto menor que o benefício: empregado recebe a diferença
  valorEfetivoDescontoVR = descontoVR;
  novoResidualVR = 0;
}

// --- Cálculo VT ---
let valorEfetivoDescontoVT = 0;
let novoResidualVT = 0;

if (descontoVT >= valorBrutoVT) {
  valorEfetivoDescontoVT = valorBrutoVT;
  novoResidualVT = Math.round((descontoVT - valorBrutoVT) * 100) / 100;
} else {
  valorEfetivoDescontoVT = descontoVT;
  novoResidualVT = 0;
}

// --- Valores líquidos (o que o empregado vai receber) ---
const valorLiquidoVR = Math.round((valorBrutoVR - valorEfetivoDescontoVR) * 100) / 100;
const valorLiquidoVT = Math.round((valorBrutoVT - valorEfetivoDescontoVT) * 100) / 100;

// --- Acumulado de descontos (para atualizar o board) ---
const novoDescontadoVR = Math.round((dados.valorDescontadoVR + valorEfetivoDescontoVR) * 100) / 100;
const novoDescontadoVT = Math.round((dados.valorDescontadoVT + valorEfetivoDescontoVT) * 100) / 100;

// --- Status do desconto ---
// Finalizado: ambos residuais = 0 (dívida quitada)
// Parcial: ainda há residual pendente
const novoStatusDesconto = (novoResidualVR === 0 && novoResidualVT === 0) 
  ? 'FINALIZADO' 
  : 'PARCIAL';

return [{
  json: {
    ...dados,

    // Valores líquidos (o que vai pro Caju)
    valorLiquidoVR,
    valorLiquidoVT,

    // Detalhes do desconto aplicado
    valorEfetivoDescontoVR,
    valorEfetivoDescontoVT,

    // Dados para atualizar o board de descontos (Nó 11)
