    novoStatusDesconto
  }
}];

// ============================================================
// NÓ 12 — Consolidar Valores Finais (pós-Merge)
// ============================================================
// Recebe dados de dois caminhos possíveis:
//   TRUE (com desconto):  Code in JavaScript6 → valorLiquidoVR/VT
//   FALSE (sem desconto): Code in JavaScript5 → valorBrutoVR/VT
// Saída: objeto unificado com valorFinalVR e valorFinalVT
// ============================================================

// Tenta pegar do caminho COM desconto (Code in JavaScript6)
let valorFinalVR, valorFinalVT, dados, caminhoDesconto;

try {
