  caminhoDesconto = true;
} catch (e) {
  // Caminho sem desconto: valores brutos são os finais
  const dadosSemDesconto = $('Code in JavaScript5').first().json;
  valorFinalVR = dadosSemDesconto.valorBrutoVR;
  valorFinalVT = dadosSemDesconto.valorBrutoVT;
