const valorFinalVR = consolidado.valorFinalVR;
const valorFinalVT = consolidado.valorFinalVT;
const vrDia = consolidado.vrDia;
const vtDia = consolidado.vtDia;

// --- Separação VR: crédito vs boleto ---
let creditoVR = 0;
let boletoVR = 0;

if (valorFinalVR > 0) {
  if (valorFinalVR <= vrDia) {
    // Valor final menor ou igual a 1 dia: tudo no crédito
    creditoVR = valorFinalVR;
  } else {
    // 1 dia no crédito, restante no boleto
    creditoVR = vrDia;
    boletoVR = Math.round((valorFinalVR - vrDia) * 100) / 100;
  }
}

// --- Separação VT: crédito vs boleto ---
let creditoVT = 0;
let boletoVT = 0;

if (valorFinalVT > 0) {
  if (valorFinalVT <= vtDia) {
    creditoVT = valorFinalVT;
  } else {
    creditoVT = vtDia;
    boletoVT = Math.round((valorFinalVT - vtDia) * 100) / 100;
  }
}

// --- Totais ---
const totalCredito = Math.round((creditoVR + creditoVT) * 100) / 100;
const totalBoleto = Math.round((boletoVR + boletoVT) * 100) / 100;
const temBoleto = totalBoleto > 0;

// --- Conversão para centavos (API Caju) ---
const creditoVR_centavos = Math.round(creditoVR * 100);
const creditoVT_centavos = Math.round(creditoVT * 100);
const boletoVR_centavos = Math.round(boletoVR * 100);
const boletoVT_centavos = Math.round(boletoVT * 100);
const totalCredito_centavos = Math.round(totalCredito * 100);
const totalBoleto_centavos = Math.round(totalBoleto * 100);

// --- Nome do pedido (máx 27 caracteres) ---
