    // Valores separados (reais)
    creditoVR,
    creditoVT,
    totalCredito,
    boletoVR,
    boletoVT,
    totalBoleto,
    temBoleto,

    // Valores em centavos
    creditoVR_centavos,
    creditoVT_centavos,
    totalCredito_centavos,
    boletoVR_centavos,
    boletoVT_centavos,
