function extractFileInfo(columnValue) {
  if (!columnValue || !columnValue.value) {
    return null;
  }

  try {
    const fileData = JSON.parse(columnValue.value);

    // Verifica se existe o array de files e se tem pelo menos um arquivo
    if (fileData.files && fileData.files.length > 0) {
      const firstFile = fileData.files[0];

      // Para arquivos do tipo LINK (Google Drive, etc)
      if (firstFile.fileType === 'LINK' && firstFile.linkToFile) {
        return {
          fileUrl: firstFile.linkToFile,
          fileName: firstFile.name,
          fileType: 'LINK',
          fileId: firstFile.fileId || null
        };
      }

      // Para arquivos do tipo ASSET (upload direto no Monday)
