        return {
          assetId: firstFile.assetId,
          fileName: firstFile.name,
          fileType: 'ASSET',
          // Para ASSET, a URL pode estar no campo 'url' ou precisar ser construída
          fileUrl: firstFile.url || null
        };
      }
    }

    return null;
  } catch (error) {
    console.error('Erro ao extrair informações do arquivo:', error);
    return null;
  }
}

