// Coloquei as duas variações para garantir que ele ache o arquivo que o Upload salvou
const arquivos = todosArquivos.filter(arq => {
    if (!arq.json || !arq.json.name) return false;

    const nomeArquivo = arq.json.name.toUpperCase();
    return nomeArquivo.includes("COMPROVANTE FINANCEIRO") || nomeArquivo.includes("COMPROVANTE DO FINANCEIRO");
});

// A quantidade será apenas dos arquivos que passaram no filtro
let quantidadeArquivos = arquivos.length;
let status = "ESPERAR_DIA"; 

if (quantidadeArquivos >= numeroParcelas && numeroParcelas > 0) {
    status = "CONCLUIDO";
} else if (quantidadeArquivos > 0) {
    // Temos alguns comprovantes, vamos ver a data do mais recente
    let ultimaDataStr = arquivos[0].json.createdTime;

    for (let arq of arquivos) {
        if (arq.json.createdTime && new Date(arq.json.createdTime) > new Date(ultimaDataStr)) {
            ultimaDataStr = arq.json.createdTime;
        }
    }

    const dataUltimoArquivo = new Date(ultimaDataStr);
    const dataAtual = new Date();

    // Se o último comprovante foi enviado no mês e ano atuais
    if (dataUltimoArquivo.getMonth() === dataAtual.getMonth() &&
        dataUltimoArquivo.getFullYear() === dataAtual.getFullYear()) {
        status = "ESPERAR_MES";
    } else {
        status = "ESPERAR_DIA";
    }
} else {
    // Se não achou nenhum comprovante
    status = "ESPERAR_DIA";
}

// Retorna o resultado da nossa verificação
return [{
    json: {
        pulseId: pulseId,
        numeroParcelas: numeroParcelas,
        arquivosEncontrados: quantidadeArquivos,
        statusRota: status
    }
}];

