const dataFormatada = `${dia}-${mes}`; // Data de hoje formatada (ex: 21-01)

// Procura em qual posição a data de hoje está na lista de envio
const indexEncontrado = datasEnvio.indexOf(dataFormatada);

// Se encontrou a data na lista (resultado diferente de -1)
if (indexEncontrado !== -1) {

  // Pega a data de corte que está na MESMA posição encontrada
  const dataCorteParaTexto = datasCorte[indexEncontrado];

