  "OUTUBRO": "Outubro", "NOVEMBRO": "Novembro", "DEZEMBRO": "Dezembro"
};
const mesFormatado = mesesNomeFormatado[mesNormalizado] || mesRaw;

// Busca o ID da pasta final (contrato dentro do mês)
const mesMap = contratoPorMes[mesNormalizado];
const pastaContratoId = mesMap ? (mesMap[grupoName] || null) : null;

// Monta nome esperado do arquivo para matching
const nomeFormatado = nomeItem.replace(/ /g, '_');
