const erroMapeamento = $('Code in JavaScript').item.json.erro;
const pathFormatado = $('Code in JavaScript').item.json.path_formatado;

// Se já tinha erro de mapeamento (mês ou contrato não encontrado)
if (erroMapeamento) {
  return {
    json: {
      nome, cpf, grupo, mes: mesFormatado,
      valor_pago: valorPago,
      status: "reprovado",
      motivo: erroMapeamento
    }
  };
}

// Resultado do Google Drive Search (Node 7)
