// Nenhum arquivo encontrado
if (arquivosEncontrados.length === 0) {
  return {
    json: {
      nome, cpf, grupo, mes: mesFormatado,
      valor_pago: valorPago,
      status: "reprovado",
      motivo: `Comprovante não encontrado no Drive (${pathFormatado})`
    }
  };
}

// Arquivo encontrado — validar nome e valor
const arquivo = arquivosEncontrados[0];
const nomeArquivo = arquivo.name || "";

// Extrai o nome da pessoa do arquivo (entre a data e o R$)
// Padrão: 2026-02-11_NOME_COMPLETO_R$1585,88.pdf
const matchNome = nomeArquivo.match(/^\d{4}-\d{2}-\d{2}_(.+)_R\$/);
const nomeNoArquivo = matchNome ? matchNome[1].replace(/_/g, ' ').trim() : "";

// Extrai o valor do arquivo
const matchValor = nomeArquivo.match(/R\$([\d.,]+)/);
let valorNoArquivo = 0;
if (matchValor) {
  // Converte "1.585,88" ou "1585,88" → 1585.88
  valorNoArquivo = parseFloat(
    matchValor[1].replace(/\./g, '').replace(',', '.')
  );
}

// Validações
const nomesBatem = nomeNoArquivo.toUpperCase() === nome.toUpperCase();
const valoresBatem = Math.abs(valorNoArquivo - valorPago) < 0.02; // tolerância de centavos

const erros = [];
if (!nomesBatem) {
  erros.push(`Nome divergente (Drive: "${nomeNoArquivo}" / Monday: "${nome}")`);
}
if (!valoresBatem) {
  erros.push(`Valor divergente (Drive: R$${matchValor?.[1] || '?'} / Monday: R$${valorPago.toFixed(2).replace('.', ',')})`);
}

if (erros.length === 0) {
  return {
    json: {
      nome, cpf, grupo, mes: mesFormatado,
      valor_pago: valorPago,
      arquivo: nomeArquivo,
      status: "aprovado",
