const reprovados = todosItems.filter(i => i.json.status === "reprovado");
const total = todosItems.length;

// Se não tem erros, para aqui (não envia nada)
if (reprovados.length === 0) {
  return {
    json: {
      enviar: false,
      mensagem: "",
      total: total,
      total_aprovados: aprovados.length,
      total_reprovados: 0
    }
  };
}

// Contratos envolvidos
const grupos = [...new Set(todosItems.map(i => i.json.grupo).filter(Boolean))];
const grupoLabel = grupos.length === 1 ? grupos[0] : grupos.join(', ');

// Data formatada
