  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

// --- Monta mensagem apenas com erros ---
let msg = `Relatorio de Validacao - ${grupoLabel}\n`;
msg += `${dataAtual}\n\n`;
msg += `Total de comprovantes analisados: ${total}\n`;
msg += `Aprovados: ${aprovados.length}\n`;
msg += `Com erro: ${reprovados.length}\n\n`;
msg += `--- Comprovantes com erro ---\n\n`;

reprovados.forEach((item, idx) => {
