// ============================================
// CONFIGURAÇÕES
// ============================================
const LIMITE_48H_MS = 48 * 60 * 60 * 1000; // 48 horas em milissegundos
const agora = new Date();

// ============================================
// PROCESSA CADA PULSE DO DATATABLE
// ============================================
const pulse = $input.item.json;

// Converte timestamps para objetos Date
const lastUpdate = new Date(pulse.lastupdate);
const ultimaNotificacao = pulse.ultima_notificacao 
  ? new Date(pulse.ultima_notificacao) 
  : null;

// ============================================
// CÁLCULOS DE TEMPO
// ============================================
const tempoDesdeUpdate = agora - lastUpdate;
const tempoDesdeNotificacao = ultimaNotificacao 
  ? agora - ultimaNotificacao 
  : null;

// ============================================
// LÓGICA DE DECISÃO
// ============================================
let deveNotificar = false;
let motivo = '';

// REGRA 1: Passou 48h desde o último update?
const passou48hDesdeUpdate = tempoDesdeUpdate >= LIMITE_48H_MS;

if (!passou48hDesdeUpdate) {
  // Se não passou 48h do update, NÃO notifica
  deveNotificar = false;
  motivo = 'Ainda não passaram 48h desde o último update';

} else if (!pulse.notificado) {
  // REGRA 2: Passou 48h E nunca foi notificado
  deveNotificar = true;
  motivo = 'Primeira notificação - 48h sem update';

} else if (pulse.notificado && tempoDesdeNotificacao >= LIMITE_48H_MS) {
  // REGRA 3: Já foi notificado, mas passou 48h desde a última notificação
  deveNotificar = true;
  motivo = 'Notificação recorrente - mais 48h sem update';

} else {
  // Foi notificado recentemente (menos de 48h)
  deveNotificar = false;
  motivo = 'Já foi notificado há menos de 48h';
}

// ============================================
// INFORMAÇÕES ADICIONAIS PARA DEBUG
// ============================================
const horasDesdeUpdate = Math.floor(tempoDesdeUpdate / (1000 * 60 * 60));
const horasDesdeNotificacao = tempoDesdeNotificacao 
  ? Math.floor(tempoDesdeNotificacao / (1000 * 60 * 60))
  : null;

// ============================================
// RETORNO
// ============================================
return {
  json: {
    // Dados do pulse
    pulse_id: pulse.pulseID,
    board_id: pulse.boardID,

    // Decisão
    deve_notificar: deveNotificar,
    motivo: motivo,

    // Detalhes temporais (útil para debug)
    horas_desde_update: horasDesdeUpdate,
    horas_desde_notificacao: horasDesdeNotificacao,

    // Dados originais (para próximos nodes)
    datatable_id: pulse.id,
    ultimo_update: pulse.lastupdate,
    ja_notificado: pulse.notificado,
    data_ultima_notificacao: pulse.ultima_notificacao
  }
};

// ============================================
// CODE NODE: CONSOLIDAR INFORMAÇÕES DO MONDAY
// ============================================
// Mode: Run Once for All Items
// Description: Processa múltiplos pulses e extrai dados por ID de coluna

const mondayItems = $input.all(); // Todos os 50 itens do Monday API
const consolidado = [];

// ============================================
// FUNÇÃO: BUSCAR COLUNA POR ID
// ============================================

function buscarColunaPorId(columnValues, columnId) {
  const coluna = columnValues.find(col => col.id === columnId);
  return coluna || null;
}

// ============================================
// FUNÇÃO: EXTRAIR LABELS DO SETTINGS
// ============================================

function extrairLabelsDoSettings(settingsStr) {
  try {
    if (!settingsStr) return [];
    const settings = JSON.parse(settingsStr);
    return settings.labels || [];
  } catch (error) {
    console.error('Erro ao parsear settings_str:', error);
    return [];
  }
}

// ============================================
// FUNÇÃO: CONVERTER IDs PARA NOMES DE SETORES
// ============================================

function converterIdsParaNomes(coluna) {
  try {
    // Se não tem coluna, retorna vazio
    if (!coluna) return 'Não definido';

    // Se já tem texto direto (fallback do Monday)
    if (coluna.text && coluna.text !== '') {
      return coluna.text;
    }

    // Se não tem value, retorna vazio
    if (!coluna.value || coluna.value === 'null' || coluna.value === '{}') {
      return 'Não definido';
    }

    // Parse do value
    const valueObj = JSON.parse(coluna.value);
    const ids = valueObj.ids || [];

    if (ids.length === 0) {
      return 'Não definido';
    }

    // Extrai labels do settings
    const labels = extrairLabelsDoSettings(coluna.column?.settings_str);

    if (labels.length === 0) {
      return `IDs: ${ids.join(', ')}`; // Fallback
    }

    // Mapeia IDs para nomes
    const nomes = ids.map(id => {
      const label = labels.find(l => l.id === id);
      return label ? label.name : `ID_${id}`;
    });

    return nomes.join(', ');

  } catch (error) {
    console.error('Erro ao converter IDs para nomes:', error);
    return 'Erro na conversão';
  }
}

