function definirGrupoMonday(j) {
  const codSecao = (j.CODSECAO || '').toString().trim();
  const nomeSecao = (j.NOME_SECAO || '').toUpperCase().trim();

  // Regras por código de seção (têm prioridade - mais determinísticas que nome)
  if (codSecao.startsWith('01.01.0079')) return 'TRE-PB';
  if (codSecao.startsWith('01.01.0087')) return 'CONTATO';

  // Regras por nome de seção
  if (!nomeSecao) return "OUTROS";
  if (setoresContato.some(s => nomeSecao.includes(s)))     return "CONTATO";
  if (nomeSecao.includes("TRE"))                              return "TRE-PB";
  if (nomeSecao.includes("BARCO"))                            return "BARCO";
