  if (num(j.SALARIO_BASE) > 0)    cv["numeric_mm17e2jx"] = fmt(j.SALARIO_BASE);

  if (j.DATA_DEMISSAO && String(j.DATA_DEMISSAO).length >= 10) {
    cv["date_mm31rh8"] = { "date": String(j.DATA_DEMISSAO).substring(0, 10) };
  }

  const buckets = [
    ["numeric_mm319kqg", j.LIQUIDO_ADIANTAMENTO_TOTAL],
    ["numeric_mm31ghvf", j.LIQUIDO_FOLHA_MENSAL],
    ["numeric_mm31ckf4", j.LIQUIDO_FERIAS_MES_ANT],
    ["numeric_mm31fkpj", j.LIQUIDO_FERIAS_MES_ATUAL],
    ["numeric_mm3165zp", j.LIQUIDO_FERIAS_MES_POST],
    ["numeric_mm316ytj", j.LIQUIDO_RESCISAO_MES_ANT],
    ["numeric_mm31frqk", j.LIQUIDO_RESCISAO_MES_ATUAL],
  ];
  for (const [colId, val] of buckets) if (num(val) > 0) cv[colId] = fmt(val);
  // Valor a pagar = líquido mensal
if (num(j.LIQUIDO_FOLHA_MENSAL) > 0) cv["numeric_mm0efy8h"] = fmt(j.LIQUIDO_FOLHA_MENSAL);

  out.push({
    json: {
      itemName: j.NOME,
      groupId: grupoId,
      columnValuesString: JSON.stringify(cv),
    }
  });
}

return out;

