// ── Referências aos nodes ─────────────────────────────────────────────────────
const itemAtual = $('HTTP Request').first().json.data.items[0];
const req2      = $('HTTP Request2').first().json;

// ── Map de colunas do board atual ─────────────────────────────────────────────
const cols = {};
for (const col of itemAtual.column_values) {
  cols[col.id] = col.text ?? "";
}

// ── Map de colunas do board de origem (via linked_items) ──────────────────────
let colsOrigem = {};
try {
  const linkedCols = req2.data.items[0].column_values[0].linked_items[0].column_values;
  for (const col of linkedCols) {
    colsOrigem[col.id] = col.text ?? "";
  }
} catch(e) {
  // sem vínculo preenchido
}

// DEBUG: descomente para ver o que está chegando do board de origem
// console.log("colsOrigem:", JSON.stringify(colsOrigem));

// ── Helpers ───────────────────────────────────────────────────────────────────
function formatDate(dateStr) {
  if (!dateStr) return "";
  const [y, m, d] = dateStr.split("-");
  return `${d}/${m}/${y}`;
}

function calcCodigo(name, numero) {
  const parts = name.trim().split(/\s+/);
  return `${parts[0]?.[0] ?? ""}.${parts[1]?.[0] ?? ""}-A.D-Nº${numero} -''e''`;
}

function calcNomeAbreviado(name) {
  const parts = name.trim().split(/\s+/);
  if (parts.length === 1) return parts[0];
  return `${parts[0]} ${parts[parts.length - 1]}`;
}

function calcDescricao(tipo) {
  const map = {
    "INTRAJORNADA":       "O(A) avaliado(a) registrou seu intervalo intrajornada em período inferior a 55 minutos, não observando o mínimo estabelecido pela tolerância institucional, e não apresentou justificativa aceitável no prazo regulamentar de 48 horas após o fato gerador.",
    "ESQUECIMENTO":       "O(A) avaliado(a) não efetuou todos os registros de ponto da forma como deveria, caracterizando esquecimento, e não apresentou justificativa aceitável no prazo regulamentar de 48 horas após o fato gerador.",
    "ENTRADA ANTECIPADA": "O(A) avaliado(a) realizou registro de entrada em momento anterior ao horário previsto excedendo os 5 minutos de tolerância, caracterizando inconsistência por entrada antecipada, e não apresentou justificativa aceitável no prazo regulamentar de 48 horas após o fato gerador.",
    "ATRASO - CHEGADA":   "O(A) avaliado(a) efetuou registro de seu horário de entrada excedendo a tolerância institucional de 5 minutos, caracterizando atraso na chegada, e não apresentou justificativa aceitável no prazo regulamentar de 48 horas após o fato gerador.",
    "ATRASO ALMOÇO":      "O(A) avaliado(a) registrou seu horário de retorno do intervalo excedendo os 65 minutos, horário com a tolerância de 05 minutos, caracterizando atraso de almoço, e não apresentou justificativa aceitável no prazo regulamentar de 48 horas após o fato gerador.",
    "SAÍDA TARDIA":       "O(A) avaliado(a) efetuou registro de seu horário de saída excedendo a tolerância institucional de 5 minutos, caracterizando saída tardia, e não apresentou justificativa aceitável no prazo regulamentar de 48 horas após o fato gerador.",
    "SAÍDA ANTECIPADA":   "O(A) avaliado(a) efetuou registro de seu horário de saída em momento anterior ao previsto, excedendo os 05 minutos de tolerância, caracterizando saída antecipada, e não apresentou justificativa aceitável no prazo regulamentar de 48 horas após o fato gerador.",
    "FALTA":              "O(A) avaliado(a) não compareceu ao trabalho na data prevista, caracterizando falta, e não apresentou justificativa aceitável no prazo regulamentar de 48 horas após o fato gerador.",
  };
  return map[tipo?.trim()] ?? "";
}

function calcRegistroPonto(m1, m2, m3, m4, m5, m6) {
  if ([m1,m2,m3,m4,m5,m6].every(v => !v)) return "Não houve batida de ponto neste dia.";
  return [m1, m2, m4, m3, m5, m6].filter(v => v).join(" - ");
}

// ── Espelhos resolvidos via board de origem ───────────────────────────────────
const tipoOc = colsOrigem["label"]                   ?? "";
const cpf    = colsOrigem["texto__1"]                ?? "";
const funcao = colsOrigem["texto1__1"]               ?? "";
const devDP  = colsOrigem["status3"]                 ?? "";
const m1     = colsOrigem["hora_18"]                 ?? "";
const m2     = colsOrigem["hora_24"]                 ?? "";
const m3     = colsOrigem["hora_37"]                 ?? "";
const m4     = colsOrigem["hora_4"]                  ?? "";
const m5     = colsOrigem["dup__of_marca__o_4__1"]   ?? "";
const m6     = colsOrigem["text__1"]                 ?? "";

const nome   = itemAtual.name;
const numero = cols["n_0__1"];

return [{
  json: {
    item_id:              itemAtual.id,
    nome_completo:        nome,
    data_do_fato:         cols["data4"],
    data_formatada:       formatDate(cols["data4"]),
    mes:                  cols["label"],
    numero,
    tipo:                 cols["sele__o_individual_mkkt182r"],
    motivo:               cols["status"],
    setor:                cols["status_10"],
    responsavel:          cols["pessoas"],
    devolutiva_rh:        cols["status_1__1"],
    descricao_ocorrencia: cols["texto_curto6__1"],

    tipo_ocorrencia:      tipoOc,
    cpf,
    funcao,
    devolutiva_dp:        devDP,
    marcacao_1:           m1,
    marcacao_2:           m2,
    marcacao_3:           m3,
    marcacao_4:           m4,
    marcacao_5:           m5,
    marcacao_6:           m6,

    codigo:               calcCodigo(nome, numero),
    nome_abreviado:       calcNomeAbreviado(nome),
    descricao:            calcDescricao(tipoOc),
    registro_de_ponto:    calcRegistroPonto(m1, m2, m3, m4, m5, m6),
  }
}];

