      const mesmoAno = ultimaNotificacao.getFullYear() === agora.getFullYear();
      const mesmoMes = ultimaNotificacao.getMonth()    === agora.getMonth();
      const mesmoDia = ultimaNotificacao.getDate()     === agora.getDate();

      if (mesmoAno && mesmoMes && mesmoDia) {
