const limparCorpo = (texto) => {
  let limpo = String(texto || '');
  // Remove @mentions (mantém só o nome sem @)
  limpo = limpo.replace(/@([A-ZÀ-Ü][a-zà-ü]+(?:\s+[A-ZÀ-Ü][a-zà-ü]+)*)/g, '$1');
