function normalizar(str) {
  return String(str).normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().trim();
}

function resolverSetor(d) {
  let setor = normalizar(d.setorDemandado || '');
  if (setor && mapaLideres[setor]) return setor;

  // Fallback: busca pelo nome do devedor
  const nomeDevedor = normalizar(d.devedor || '');
  for (const [nomeFuncionario, setorFunc] of Object.entries(funcionarioSetor)) {
    if (nomeDevedor.includes(normalizar(nomeFuncionario)) || normalizar(nomeFuncionario).includes(nomeDevedor)) {
      return normalizar(setorFunc);
    }
  }
  return '';
}

function determinarRemetente(d) {
  const dias = Number(d.dias_inativo) || 1;
  const devedor = normalizar(d.devedor || '');
  const setor = resolverSetor(d);

  // Dr. João é devedor → sempre Tuca
  const devedorEhDrJoao = devedor.includes('joao') && devedor.includes('dr');
  if (devedorEhDrJoao) {
    return { nome: 'Tuca', nivel: '3', tipo: 'TUCA', subtitulo: 'Cobrancas - Dr. Joao sem resposta (Nivel especial)' };
  }

  // Devedor é um líder → pula nível 1
  const devedorEhLider = nomesLideresLista.some(nl => devedor.includes(nl));
  if (devedorEhLider) {
    if (dias >= 2) {
      return { nome: 'Tuca', nivel: '3', tipo: 'TUCA', subtitulo: 'Cobrancas de 2+ dias - Lider sem resposta (Nivel 3)' };
    }
    return { nome: 'Dr. Joao', nivel: '2', tipo: 'DR. JOAO', subtitulo: 'Cobrancas de 24h - Lider sem resposta (Nivel 2)' };
  }

  // Setor Comercial: líder = Dr. João → 24h Dr.João, 48h+ Tuca
  if (setor === 'comercial') {
    if (dias >= 2) {
      return { nome: 'Tuca', nivel: '3', tipo: 'TUCA', subtitulo: 'Cobrancas de 2+ dias - Comercial (Nivel 3)' };
    }
    return { nome: 'Dr. Joao', nivel: '1', tipo: 'DR. JOAO', subtitulo: 'Cobrancas de 24h - Comercial (Nivel 1)' };
  }

  // Liderado comum → escalonamento normal
  if (dias >= 3) {
    return { nome: 'Tuca', nivel: '3', tipo: 'TUCA', subtitulo: 'Cobrancas de 3+ dias sem resposta (Nivel 3)' };
  }
  if (dias === 2) {
    return { nome: 'Dr. Joao', nivel: '2', tipo: 'DR. JOAO', subtitulo: 'Cobrancas de 2 dias sem resposta (Nivel 2)' };
  }

  const lider = setor ? (mapaLideres[setor] || 'Lider Nao Identificado') : 'Lider Nao Identificado';
  return { nome: lider, nivel: '1', tipo: 'LIDER', subtitulo: 'Cobrancas de 24h sem resposta (Nivel 1)' };
}

