  const rankQtd = {};
  demandas.forEach(d => {
    const dev = d.devedor || 'N/A';
    rankQtd[dev] = (rankQtd[dev] || 0) + 1;
  });
  const topQtd = Object.entries(rankQtd).sort((a, b) => b[1] - a[1]).slice(0, 5);

  const rankDias = {};
  demandas.forEach(d => {
    const dev = d.devedor || 'N/A';
    const dias = Number(d.dias_inativo) || 0;
    if (!rankDias[dev] || dias > rankDias[dev]) rankDias[dev] = dias;
  });
  const topDias = Object.entries(rankDias).sort((a, b) => b[1] - a[1]).slice(0, 5);

  const alturaRanking = 16 + Math.max(topQtd.length, topDias.length) * 16 + 20;
  if (curY - alturaRanking < RODAPE_Y) {
    rodapePDF(p, numPagina);
    streams.push(p.build());
    numPagina++;
    p = pagina();
    cabecalhoPDF(p, numPagina);
    curY = 720;
  }

  const colEsq = 24;
  const colDir = 310;
  const largCol = 276;

  p.txt(colEsq, curY, 'TOP 5 DEVEDORES (por quantidade)', F.bold, 10, C.azulEscuro);
  p.txt(colDir, curY, 'TOP 5 DEVEDORES (por dias parado)', F.bold, 10, C.azulEscuro);
  curY -= 4;
  p.linha(colEsq, curY, colEsq + largCol, C.azulMedio, 0.5);
  p.linha(colDir, curY, colDir + largCol, C.azulMedio, 0.5);
  curY -= 2;

  p.rect(colEsq, curY - 16, largCol, 16, C.azulEscuro);
  p.txt(colEsq + 4, curY - 12, 'Nome', F.bold, 8, C.branco);
  p.txt(colEsq + 220, curY - 12, 'Qtd.', F.bold, 8, C.branco);

  p.rect(colDir, curY - 16, largCol, 16, C.azulEscuro);
  p.txt(colDir + 4, curY - 12, 'Nome', F.bold, 8, C.branco);
  p.txt(colDir + 220, curY - 12, 'Qtd.', F.bold, 8, C.branco);
  curY -= 16;

  const maxRows = Math.max(topQtd.length, topDias.length);
  for (let i = 0; i < maxRows; i++) {
    const bgColor = i % 2 === 0 ? C.cinzaClaro : C.branco;

    if (i < topQtd.length) {
      p.rect(colEsq, curY - 16, largCol, 16, bgColor, C.cinzaMedio);
      p.txt(colEsq + 4, curY - 12, truncar(topQtd[i][0], 35), F.normal, 8, C.preto);
      p.txt(colEsq + 220, curY - 12, String(topQtd[i][1]), F.bold, 9, C.vermelho);
    }

    if (i < topDias.length) {
      p.rect(colDir, curY - 16, largCol, 16, bgColor, C.cinzaMedio);
      p.txt(colDir + 4, curY - 12, truncar(topDias[i][0], 35), F.normal, 8, C.preto);
      p.txt(colDir + 220, curY - 12, String(topDias[i][1]), F.bold, 9, C.vermelho);
    }

    curY -= 16;
  }

  rodapePDF(p, numPagina);
  streams.push(p.build());

  const pdfBuffer = compilar(streams);
  const nomeRemetente = normalizarParaPDF(remetente).replace(/\s+/g, '_');
  const nomeArquivo = 'Relatorio_' + nomeRemetente + '_' + normalizarParaPDF(dataFormatada).replace(/\//g, '-') + '.pdf';

  output.push({
    json: {
      temRelatorio: true,
      nome_arquivo: nomeArquivo,
      remetente: remetente,
      tipoRelatorio: tipoInfo.tipo,
      nivel: tipoInfo.nivel,
      totalDemandas: totalDemandas,
      totalDevedores: devedoresUnicos,
      remoteJid: '120363424978312590@g.us'
    },
    binary: {
      data: {
        data: pdfBuffer.toString('base64'),
        mimeType: 'application/pdf',
        fileName: nomeArquivo,
        fileExtension: 'pdf'
      }
    }
  });
}

if (output.length === 0) {
  return [{ json: { temRelatorio: false } }];
}

return output;

// Nó 18.1 — Converter PDF binário para base64 e preparar payload
return (async () => {
  const items = $input.all();
  const result = [];

  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    let base64PDF = '';

    if (item.binary && item.binary.data) {
      const binaryDataBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
      base64PDF = binaryDataBuffer.toString('base64');
    }

    result.push({
      json: {
        pdfBase64: base64PDF,
        fileName: item.json.nome_arquivo || 'Relatorio_Demandas.pdf',
        remoteJid: item.json.remoteJid,
        totalDemandas: item.json.totalDemandas,
        totalSetores: item.json.totalSetores,
        remetente: item.json.remetente
      }
    });
  }

  return result;
})();

