// Pega a data e hora do momento da execução do fluxo
const dataHoje = new Date();

// Cria uma nova variável e soma 4 dias
const dataAlvo = new Date(dataHoje);
dataAlvo.setDate(dataAlvo.getDate() + 4);

// Formata a data para o padrão YYYY-MM-DD (que o Monday usa nas colunas de data)
