  }
};

// Pega o item do Monday
const item = $input.first().json;
const cols = item.column_values || [];

function col(id) {
  return cols.find(c => c.id === id) || {};
}

// ── Chapa ──────────────────────────────────────────────────────────────────
const chapa = col('text_mm2d3fs9').text || '';

// ── Nome ───────────────────────────────────────────────────────────────────
const nome = item.name || '';

// ── Valor líquido ──────────────────────────────────────────────────────────
const valorTexto = col('numeric_mm2pjqsn').text || '0';   // ajuste o id se diferente
const valor = parseFloat(valorTexto.replace(',', '.')) || 0;

// ── Data de pagamento ──────────────────────────────────────────────────────
let dataPagamento = '';
const dateCol = col('date_mm2pk9a8');
if (dateCol.value) {
  try {
    const parsed = JSON.parse(dateCol.value);
    dataPagamento = parsed.date || dateCol.text || '';
  } catch(e) {
    dataPagamento = dateCol.text || '';
  }
}
// garante formato YYYY-MM-DD
if (!/^\d{4}-\d{2}-\d{2}$/.test(dataPagamento)) {
  throw new Error(`Data inválida: ${dataPagamento}`);
}

if (!chapa) throw new Error(`Item sem CHAPA: ${item.id}`);
