  }
};

const monday = $('FormatandoInfos').item.json;
const rm = $('BuscarDadosBanc').item.json;
const d = Array.isArray(rm) ? rm[0] : rm;

// Remove acentos e sobe para maiúsculo (para logradouro)
const norm = (s) => String(s || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toUpperCase()
  .replace(/[^A-Z0-9 ]/g, ' ')
  .trim();

return {
