    tipo_pix:   String(d.TIPOPIX   || '3'),             // 1=tel, 2=email, 3=CPF, 4=CNPJ, 5=aleat.
    tipo_pagto: String(d.TIPOPAGTO || '2'),

    logradouro: norm(d.RUA || ''),                      // pos 33-72 (40 chars)

    banco:     (d.CODBANCO   || '077'),
