// ═══════════════════════════════════════════════════════
// GERAR CNAB 240 – BANCO INTER (077) – PIX SALÁRIOS
// Byte-perfect com o layout gerado pelo RM
// ═══════════════════════════════════════════════════════

const funcionarios = $input.all().map(i => i.json);

// Ordena por ordem alfabética para ficar idêntico ao RM
funcionarios.sort((a, b) => String(a.nome || '').localeCompare(String(b.nome || '')));

if (funcionarios.length === 0) {
  throw new Error("Nenhum funcionário recebido para gerar o CNAB.");
}

// ── Configurações da empresa ────────────────────────────
const BANCO       = '077';
const CNPJ        = '04768594000136';
const AGENCIA     = '00001';
const AGENCIA_DV  = '9';
const CONTA       = '000030141383';
const CONTA_DV    = '5';
const AGCTA_DV    = ' ';
const NOME_EMP    = 'CONTATO SERVICOS DE CONSERVACA';
const LOGRADOURO  = 'R PRUDENTE DE MORAES';
const NUM_END     = '00280';
const COMPLEMENTO = 'CJ D. PEDRO';
const CIDADE      = 'MANAUS';
const CEP         = '69040710';
const UF          = 'AM';

// ── Helpers ─────────────────────────────────────────────
const pad = (v, n, c = ' ', dir = 'R') =>
  dir === 'R'
    ? String(v).substring(0, n).padEnd(n, c)
    : String(v).substring(0, n).padStart(n, c);

const padL = (v, n, c = '0') => pad(v, n, c, 'L');
const padR = (v, n, c = ' ') => pad(v, n, c, 'R');

// Para nomes (RM usa tudo maiúsculo, sem acentos)
const normUpper = (s) => String(s || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toUpperCase()
  .replace(/[^A-Z0-9 \/\-\.]/g, ' ')
  .trim();

// Para logradouro (RM preserva maiúscula/minúscula)
const normCase = (s) => String(s || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^A-Za-z0-9 \/\-\.]/g, ' ')
  .trim();

const fmtData = (iso) => {
  if (!iso) return '00000000';
  const [y, m, d] = iso.split('-');
  return `${d}${m}${y}`;
};

const agora  = new Date();
const dd     = String(agora.getDate()).padStart(2, '0');
const mm     = String(agora.getMonth() + 1).padStart(2, '0');
const yyyy   = String(agora.getFullYear());
const yy     = yyyy.slice(2);
const DT_GER = `${dd}${mm}${yyyy}`;
const HR_GER = String(agora.getHours()).padStart(2, '0')
             + String(agora.getMinutes()).padStart(2, '0')
             + String(agora.getSeconds()).padStart(2, '0');
const SEQ_ARQ = `${dd}${mm}${yy}`;
const dtGer6  = `${dd}${mm}${yy}`;

const somaValor = funcionarios.reduce((acc, f) => {
  const cents = Math.round(parseFloat(String(f.valor).replace(',', '.')) * 100);
  return acc + cents;
}, 0);

// ── HEADER ARQUIVO ───────────────────────────────────────
const headerArquivo = [
  BANCO,                   // 3  pos 1-3
  '0000',                  // 4  pos 4-7
  '0',                     // 1  pos 8
  padR('', 9),             // 9  pos 9-17
  '2',                     // 1  pos 18   tipo insc = CNPJ
  padL(CNPJ, 14),          // 14 pos 19-32
  padR('', 20),            // 20 pos 33-52
  AGENCIA,                 // 5  pos 53-57
  AGENCIA_DV,              // 1  pos 58
  CONTA,                   // 12 pos 59-70
  CONTA_DV,                // 1  pos 71
  AGCTA_DV,                // 1  pos 72
  padR(NOME_EMP, 30),      // 30 pos 73-102
  padR('BANCO INTER', 30), // 30 pos 103-132
  padR('', 10),            // 10 pos 133-142
  '1',                     // 1  pos 143  cód remessa
  DT_GER,                  // 8  pos 144-151
  HR_GER,                  // 6  pos 152-157
  padL(SEQ_ARQ, 6),        // 6  pos 158-163
  '107',                   // 3  pos 164-166
  '01600',                 // 5  pos 167-171
  padR('', 69),            // 69 pos 172-240
].join('');

// ── HEADER LOTE ──────────────────────────────────────────
const headerLote = [
  BANCO,                   // 3
  '0001',                  // 4  lote
  '1',                     // 1
  'C',                     // 1  operação crédito
  '20',                    // 2  tipo serviço (pagto folha)
  '45',                    // 2  forma pgto PIX
  '046',                   // 3  versão lote
  ' ',                     // 1
  '2',                     // 1  tipo insc CNPJ
  padL(CNPJ, 14),          // 14
  padR('', 20),            // 20 cod convenio
  AGENCIA,                 // 5
  AGENCIA_DV,              // 1
  CONTA,                   // 12
  CONTA_DV,                // 1
  AGCTA_DV,                // 1
  padR(NOME_EMP, 30),      // 30
  padR('', 40),            // 40 mensagem
  padR(LOGRADOURO, 30),    // 30
  padL(NUM_END, 5, '0'),   // 5
  padR(COMPLEMENTO, 15),   // 15
  padR(CIDADE, 20),        // 20
  CEP,                     // 8
  UF,                      // 2
  padR('', 18),            // 18
].join('');

// ── DETALHES (Seg A + Seg B) ─────────────────────────────
const detalhes = [];
let seq = 1;

for (const f of funcionarios) {
  const valorCents = Math.round(parseFloat(String(f.valor).replace(',', '.')) * 100);
  const valorStr   = padL(valorCents, 15);
  const dtPagto    = fmtData(f.data_pagamento);

  const nomeFav   = padR(normUpper(f.nome), 30);
  const bancoFav  = padL(String(f.banco || '077'), 3, '0');
  const agFav     = padL(String(f.agencia || '00001'), 5, '0');
  const agFavDv   = String(f.agenciaDV || ' ');

  // CORREÇÃO: Regra blindada da conta bancária
  const contaOriginal = String(f.conta || '').trim().replace(/\D/g, ''); 
  let contaBase = '';
  let contaDv = '0'; // Padrão do RM se for vazio é zero!

  if (contaOriginal.length > 1) {
    contaBase = contaOriginal.slice(0, -1);
    contaDv = contaOriginal.slice(-1);
  } else if (contaOriginal.length === 1) {
    contaDv = contaOriginal;
  }

  const contaFav  = padL(contaBase, 12, '0');
  const ctaFavDv  = padR(contaDv, 1, ' ');
  const agCtaDv   = ' ';

  const chapaFmt  = padL(String(f.chapa || ''), 6, '0');
  const numDoc    = dtGer6 + chapaFmt + padL('', 8, '0');   // 20 chars
  const tpPix     = padL(String(f.tipo_pix || '3'), 2, '0');
  const cpfFav    = padL((f.cpf || '').replace(/\D/g, ''), 14, '0');

  // Chave PIX – apenas para tipos ≠ CPF/CNPJ (03/04)
  // Para 03 (CPF) e 04 (CNPJ) a chave já é o próprio documento em pos 19-32
  let chavePixField = '';
  if (!['03', '3', '04', '4'].includes(String(f.tipo_pix))) {
    chavePixField = String(f.chave_pix || '');
  }

  // SegB – layout RM:
  //   pos 33-62 (30): logradouro, preservando maiúscula/minúscula
  //   pos 63-67 (5):  número — fica EM BRANCO
  //   pos 68-82 (15): complemento — começa com o número ("0" ou valor real)
  const logradouro30 = padR(normCase(f.logradouro || ''), 30);
  const numeroBlank  = padR('', 5);
  const complemento15 = padR(String(f.numero || '0'), 15);

  const seqA = padL(seq,     5, '0');
  const seqB = padL(seq + 1, 5, '0');

  // ════════════ SEGMENTO A ════════════
  // Layout byte-perfect com o RM
  const segA = [
    BANCO,             // 3  pos 1-3
    '0001',            // 4  pos 4-7
    '3',               // 1  pos 8
    seqA,              // 5  pos 9-13
    'A',               // 1  pos 14
    '000',             // 3  pos 15-17  tipo mov (1) + cód instrução (2)
    '000',             // 3  pos 18-20  CÂMARA CENTRALIZADORA 
    bancoFav,          // 3  pos 21-23
    agFav,             // 5  pos 24-28
    agFavDv,           // 1  pos 29
    contaFav,          // 12 pos 30-41
    ctaFavDv,          // 1  pos 42
    agCtaDv,           // 1  pos 43
    nomeFav,           // 30 pos 44-73
    numDoc,            // 20 pos 74-93
    dtPagto,           // 8  pos 94-101
    'BRL',             // 3  pos 102-104
    padL('', 15, '0'), // 15 pos 105-119
    valorStr,          // 15 pos 120-134
    padR('', 20),      // 20 pos 135-154  nosso número banco
    '00000000',        // 8  pos 155-162  data efetivação
    padL('', 15, '0'), // 15 pos 163-177  valor efetivação
    padR('', 22),      // 22 pos 178-199
    '01',              // 2  pos 200-201  finalidade interna (RM)
    padR('', 39),      // 39 pos 202-240 
  ].join('');

  // ════════════ SEGMENTO B ════════════
  const segB = [
    BANCO,                      // 3  pos 1-3
    '0001',                     // 4  pos 4-7
    '3',                        // 1  pos 8
    seqB,                       // 5  pos 9-13
    'B',                        // 1  pos 14
    tpPix,                      // 2  pos 15-16  tipo chave PIX
    ' ',                        // 1  pos 17
    '1',                        // 1  pos 18      tipo insc favorecido (1=CPF)
    cpfFav,                     // 14 pos 19-32
    logradouro30,               // 30 pos 33-62  
    numeroBlank,                // 5  pos 63-67  RM deixa em branco
    complemento15,              // 15 pos 68-82  RM coloca "0" aqui
    padR('', 20),               // 20 pos 83-102 bairro
    padR('', 5),                // 5  pos 103-107 CEP
    padR('', 3),                // 3  pos 108-110 compl CEP
    padR('', 20),               // 20 pos 111-130 cidade
    padR('', 2),                // 2  pos 131-132 UF
    padR(chavePixField, 108),   // 108 pos 133-240 chave PIX + reservado
  ].join('');

  detalhes.push(segA);
  detalhes.push(segB);
  seq += 2;
}

// ── TRAILER LOTE ─────────────────────────────────────────
const qtdRegistrosLote = detalhes.length + 2; // + header + trailer
const trailerLote = [
  BANCO,
  '0001',
  '5',
  padR('', 9),
  padL(qtdRegistrosLote, 6, '0'),
  padL(somaValor, 18, '0'),
  padL('', 18, '0'),
  padL('', 6, '0') + padR('', 175),
].join('');

// ── TRAILER ARQUIVO ──────────────────────────────────────
const qtdTotalReg = detalhes.length + 4; // hdrArq + hdrLote + detalhes + trlLote + trlArq
const trailerArquivo = [
  BANCO,
  '9999',
  '9',
  padR('', 9),
  padL(1, 6, '0'),
  padL(qtdTotalReg, 6, '0'),
  padL('', 6, '0'),
  padR('', 205),
].join('');

// ── MONTAGEM FINAL ───────────────────────────────────────
const linhas = [
  headerArquivo,
  headerLote,
  ...detalhes,
  trailerLote,
  trailerArquivo,
];

for (let i = 0; i < linhas.length; i++) {
  if (linhas[i].length !== 240) {
    throw new Error(`Linha ${i + 1} tem ${linhas[i].length} chars (esperado 240).`);
  }
}

const cnab = linhas.join('\r\n') + '\r\n';

return {
  json: {
    cnab,
    qtd_funcionarios: funcionarios.length,
    valor_total: (somaValor / 100).toFixed(2),
    qtd_linhas: linhas.length,
    lista_funcionarios: funcionarios
  }
};

// Pega o link de visualização gerado pelo Google Drive no nó anterior
const driveLink = $input.first().json.webViewLink;

// Puxa a lista original de funcionários direto do nó 'VerificaSeExiste' (onde o ID está a salvo!)
