return $input.all();

const itemData = $input.first().json; 
const nomeOriginal = itemData.name || "Despesa Sem Nome";

const idColunaParcelas = "text_mm0skc1h"; 
const idColunaVencimento = "date_mm0s9q6h";
const idColunaValor = "numeric_mm0sqvd4";
const idColunaTipo = "color_mm0s2h9g";
const idColunaTipoDoc = "color_mm0sjqqe";
const idColunaTitular = "dropdown_mm0wm577";

const gruposMeses = {
  "01": "group_mm1yy6e8", "02": "group_mm1y5jcp", "03": "group_mm0sqr5r", 
  "04": "group_mm0srwgq", "05": "group_mm0sgcwt", "06": "group_mm0svy23", 
  "07": "group_mm0szj12", "08": "group_mm0sq8tj", "09": "group_mm0spd80", 
  "10": "group_mm0s21s4", "11": "group_mm0sww7q", "12": "group_mm0sn5qy"  
};

let numParcelas = 1;
let dataVencimentoStr = "";
let valor = "";
let tipoDespesa = "";
let tipoDoc = "";
let titular = "";

if (itemData.column_values && Array.isArray(itemData.column_values)) {
  itemData.column_values.forEach(col => {
    if (col.id === idColunaParcelas) numParcelas = parseInt(col.text) || 1; 
    if (col.id === idColunaVencimento) dataVencimentoStr = col.text; 
    if (col.id === idColunaValor) valor = col.text; 
    if (col.id === idColunaTipo && col.text) tipoDespesa = col.text; 
    if (col.id === idColunaTipoDoc && col.text) tipoDoc = col.text; 
    if (col.id === idColunaTitular && col.text) titular = col.text; 
  });
}

if (!dataVencimentoStr) {
  let hoje = new Date();
  dataVencimentoStr = hoje.toISOString().split('T')[0];
}

let novasParcelas = [];
let dataBase = new Date(dataVencimentoStr + "T12:00:00Z"); 

for (let i = 1; i <= numParcelas; i++) {
  let novaData = new Date(dataBase);
  novaData.setMonth(novaData.getMonth() + (i - 1));

  let diaSemana = novaData.getDay(); 
  if (diaSemana === 6) { novaData.setDate(novaData.getDate() + 2); } 
  else if (diaSemana === 0) { novaData.setDate(novaData.getDate() + 1); }

  let ano = novaData.getFullYear().toString(); 
  let mes = String(novaData.getMonth() + 1).padStart(2, '0');
  let dia = String(novaData.getDate()).padStart(2, '0');
  let dataFormatada = `${ano}-${mes}-${dia}`;

  let idGrupoDestino = gruposMeses[mes];
  let textoParcela = numParcelas > 1 ? `${String(i).padStart(2, '0')}/${String(numParcelas).padStart(2, '0')}` : "Cota Única";

  let valoresColunas = {
    "date_mm0s9q6h": {"date": dataFormatada},
    "color_mm1y69kc": {"label": ano},
    "text_mm1ycsmw": textoParcela,
    "color_mm1yeww3": {"label": "PENDENTE"} // O Status do Boleto
  };

  if (valor) valoresColunas["numeric_mm0sqvd4"] = valor;
  if (tipoDespesa) valoresColunas["color_mm0s2h9g"] = {"label": tipoDespesa};
  if (tipoDoc) valoresColunas["color_mm0sjqqe"] = {"label": tipoDoc};
  if (titular) valoresColunas["dropdown_mm0wm577"] = {"labels": [titular]};

  novasParcelas.push({
    json: {
      nome_item: nomeOriginal, 
      id_grupo: idGrupoDestino,
      valores_finais: JSON.stringify(valoresColunas) 
    }
  });
}

return novasParcelas;

