if (!dataVencimentoStr) {
  let hoje = new Date();
  dataVencimentoStr = hoje.toISOString().split('T')[0];
}

let novasParcelas = [];
let dataBase = new Date(dataVencimentoStr + "T12:00:00Z"); 

for (let i = 1; i <= numParcelas; i++) {
  let novaData = new Date(dataBase);
  novaData.setMonth(novaData.getMonth() + (i - 1));

  let diaSemana = novaData.getDay(); 
  if (diaSemana === 6) { novaData.setDate(novaData.getDate() + 2); } 
  else if (diaSemana === 0) { novaData.setDate(novaData.getDate() + 1); }

  let ano = novaData.getFullYear().toString(); 
  let mes = String(novaData.getMonth() + 1).padStart(2, '0');
  let dia = String(novaData.getDate()).padStart(2, '0');
  let dataFormatada = `${ano}-${mes}-${dia}`;

  let idGrupoDestino = gruposMeses[mes];
  let textoParcela = numParcelas > 1 ? `${String(i).padStart(2, '0')}/${String(numParcelas).padStart(2, '0')}` : "Cota Única";

  let valoresColunas = {
    "date_mm0s9q6h": {"date": dataFormatada},
    "color_mm1y69kc": {"label": ano},
    "text_mm1ycsmw": textoParcela,
    "color_mm1yeww3": {"label": "PENDENTE"} // O Status do Boleto
  };

  if (valor) valoresColunas["numeric_mm0sqvd4"] = valor;
  if (tipoDespesa) valoresColunas["color_mm0s2h9g"] = {"label": tipoDespesa};
  if (tipoDoc) valoresColunas["color_mm0sjqqe"] = {"label": tipoDoc};
  if (titular) valoresColunas["dropdown_mm0wm577"] = {"labels": [titular]};

  novasParcelas.push({
    json: {
      nome_item: nomeOriginal, 
      id_grupo: idGrupoDestino,
      valores_finais: JSON.stringify(valoresColunas) 
    }
  });
}

return novasParcelas;

const CENTRAL_BOARD_ID = "18413180912";
const pages = $input.all().map(item => item.json);
const firstBoard = pages.find(page => page.data?.boards?.[0])?.data?.boards?.[0];
if (!firstBoard) throw new Error("Board central de producao nao encontrado ou nao esta ativo: " + CENTRAL_BOARD_ID);
const itemsById = new Map();
for (const page of pages) {
  const board = page.data?.boards?.[0];
  for (const item of board?.items_page?.items || []) itemsById.set(String(item.id), item);
}

const formatBoardName = (date) => {
  const mm = String(date.getMonth() + 1).padStart(2, "0");
  const yy = String(date.getFullYear()).slice(-2);
  return `${mm}/${yy} - Plan. de Benef\u00edcio - Contato`;
};

const now = new Date();
const currentMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const nextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 1);

return [{
  json: {
    centralBoardId: CENTRAL_BOARD_ID,
    currentBoardName: firstBoard.name,
    archiveBoardName: formatBoardName(currentMonth),
    nextBoardName: formatBoardName(nextMonth),
    updates: firstBoard.updates || [],
    itemIdsToArchive: Array.from(itemsById.keys()),
    itemCountToArchive: itemsById.size,
    updateCountToCopy: (firstBoard.updates || []).length,
    itemPagesRead: pages.length
  }
}];

const prep = $("Preparar dados da virada").first().json;
const duplicateBoard = $("Duplicar board central").first().json.data?.duplicate_board?.board;
if (!duplicateBoard?.id) throw new Error("Nao foi possivel obter o ID do board duplicado.");
return (prep.updates || []).map((update, index) => {
  const replies = update.replies || [];
  const creator = update.creator?.name || "Autor nao informado";
  const replyHtml = replies.length ? `<hr><p><strong>Respostas copiadas:</strong></p>${replies.map(reply => {
    const replyCreator = reply.creator?.name || "Autor nao informado";
    const replyBody = reply.body || `<p>${reply.text_body || ""}</p>`;
    return `<blockquote><p><strong>${replyCreator}</strong> em ${reply.created_at || "data nao informada"}</p>${replyBody}</blockquote>`;
  }).join("")}` : "";
  return { json: { duplicateBoardId: duplicateBoard.id, sourceUpdateId: update.id, body: `<p><strong>Mensagem copiada do bal\u00e3o central</strong></p><p>Autor original: ${creator}<br>Data original: ${update.created_at || "data nao informada"}<br>Update original: ${update.id}</p><hr>${update.body || `<p>${update.text_body || ""}</p>`}${replyHtml}`, index } };
});

const TARGET_BOARD_ID = "18413271331";
const BATCH_SIZE = 25;
const mainBoardId = TARGET_BOARD_ID;

const formatDate = (value) => value ? String(value).substring(0, 10) : "";
const normalize = (value) => String(value || "")
  .normalize("NFD")
  .replace(/[\u0300-\u036f]/g, "")
  .replace(/\s+/g, " ")
  .trim()
  .toUpperCase();

const groupIds = {
  "04": "group_mm2edhx5",
  "07": "group_mm2eyxfg",
  "07|6": "group_mm2n79cm",
  "07.02": "group_mm2eprpn",
  "10": "group_mm2ef8mn",
  "11.01": "group_mm2e99p9",
  "11.02": "group_mm2e4kex",
  "15": "group_mm2em803",
  "74": "group_mm2ext7q",
  "78": "group_mm2eknpq",
  "79": "group_mm2enj5b",
  "84": "group_mm2eczww",
  "85": "group_mm2e22nj",
  "AFASTADOS": "group_mm3c4xaq",
  "CONTRATOS_TRANSICAO": "group_mm3ctvr4"
};

const getValue = (data, normalizedNames) => {
  for (const normalizedName of normalizedNames) {
    for (const [key, value] of Object.entries(data)) {
      if (normalize(key) === normalizedName && value !== undefined && value !== null && String(value).trim() !== "") {
        return value;
      }
    }
  }
  return "";
};

const employeeName = (data) => getValue(data, ["NOME DO FUNCIONARIO", "FUNCIONARIO"]) || "Sem nome";

const resolveGroupId = (data) => {
  const unidade = normalize(getValue(data, ["LOCAL/UNIDADE"]));
  if (["AFASTADO INSS", "LICENCA MATERNIDADE", "LICENCA SEM VENCIMENTO", "RESCISAO INDIRETA"].includes(unidade)) {
    return groupIds.AFASTADOS;
  }
  if (unidade.includes("CONTRATOS EM TRANSICAO")) {
    return groupIds.CONTRATOS_TRANSICAO;
  }

  const codeRaw = getValue(data, ["CODIGO", "CODIGO DA SECAO", "CODSECAO", "COD. SECAO"]);
  const digits = String(codeRaw || "").replace(/\D/g, "");
  if (digits.length < 8) throw new Error(`Codigo de secao invalido ou curto para ${employeeName(data)}: ${codeRaw || "vazio"}`);

  const base = digits.substring(6, 8);
  const branch = digits.substring(8, 10);
  const coligada = String(getValue(data, ["CODCOLIGADA", "CODIGO COLIGADA", "COLIGADA", "COD. COLIGADA"])).replace(/\D/g, "");

  if (base === "07" && branch === "02") return groupIds["07.02"];
  if (base === "07" && coligada === "6") return groupIds["07|6"];
  if (base === "07") return groupIds["07"];
  if (base === "11" && branch === "01") return groupIds["11.01"];
  if (base === "11" && branch === "02") return groupIds["11.02"];

  const groupId = groupIds[base];
  if (!groupId) throw new Error(`Codigo de secao sem grupo mapeado para ${employeeName(data)}: ${codeRaw}`);
  return groupId;
};

const mapSituacao = (data) => {
  const situacao = getValue(data, ["SITUACAO"]);
  if (normalize(situacao) === "APOS. POR INCAPACIDADE PERMANENTE") return "Af.Previd\u00eancia";
  return situacao;
};

const collaborators = [];

for (const item of $input.all()) {
  const data = item.json;
  const intermitente = normalize(getValue(data, ["INTERMITENTE?"]));
  if (intermitente === "SIM") continue;

  const columnValues = {
    "texto": getValue(data, ["FUNCIONARIO", "NOME DO FUNCIONARIO"]),
    "dup__of_matr_cula": getValue(data, ["CPF"]),
    "texto75": getValue(data, ["LOCAL/UNIDADE"]),
    "text_mkrzbj02": getValue(data, ["CAMPO COMPLEMENTAR"]),
    "text_mkrztp4t": getValue(data, ["JORNADA"]),
    "texto0": getValue(data, ["FUNCAO"]),
    "texto8": formatDate(getValue(data, ["ADMISSAO"])),
    "texto92": getValue(data, ["INTERMITENTE?"]),
    "text_mkt63tyk": getValue(data, ["CODIGO"]),
    "optante___vt": { "label": getValue(data, ["VALE TRANSPORTE"]) || "N\u00c3O" },
    "status__1": { "label": getValue(data, ["FUNCIONARIO DEFICIENTE"]) || "N\u00c3O" },
    "status2__1": { "label": mapSituacao(data) }
  };

  collaborators.push({
    groupId: resolveGroupId(data),
    itemName: employeeName(data),
    columnValuesString: JSON.stringify(columnValues)
  });
}

const output = [];
for (let start = 0; start < collaborators.length; start += BATCH_SIZE) {
  const batch = collaborators.slice(start, start + BATCH_SIZE);
  const declarations = ["$boardId: ID!"];
  const mutations = ["complexity { before after query }"];
  const variables = { boardId: mainBoardId };

  batch.forEach((collaborator, index) => {
    declarations.push(`$groupId${index}: String!`, `$itemName${index}: String!`, `$columnValues${index}: JSON!`);
    mutations.push(`item${index}: create_item(board_id: $boardId, group_id: $groupId${index}, item_name: $itemName${index}, column_values: $columnValues${index}) { id }`);
    variables[`groupId${index}`] = collaborator.groupId;
    variables[`itemName${index}`] = collaborator.itemName;
    variables[`columnValues${index}`] = collaborator.columnValuesString;
  });

  output.push({
    json: {
      boardId: mainBoardId,
      batchNumber: output.length + 1,
      batchSize: batch.length,
      totalCollaborators: collaborators.length,
      query: `mutation CreateCollaboratorsBatch(${declarations.join(", ")}) { ${mutations.join(" ")} }`,
      variables
    }
  });
}

return output;

