// ==================================================
// MAPEAMENTO DE COLUNAS - BOARD FISCAL (LOOP)
// Autor: Mike | Aions Corp
// Propósito: Mapear múltiplos itens + consolidar com Compras
// Versão: 2.1 - CORREÇÃO DE MODO
// ==================================================

const itemsFiscal = $input.all();
const comprasData = $('Mapear Colunas - Compras').item.json;

// ========== FUNÇÕES HELPER ==========
function getColumn(columnValues, id) {
  return columnValues.find(col => col.id === id);
}

function getText(columnValues, id) {
  const col = getColumn(columnValues, id);
  return col ? (col.text || '') : '';
}

// ========== PROCESSA CADA ITEM DO FISCAL ==========
const mappedItems = itemsFiscal.map(item => {
  const cv = item.json.column_values;

  return {
    // ========== IDENTIFICAÇÃO ==========
    pulse_id_fiscal: item.json.id,
    nome_item_fiscal: item.json.name,

    // ========== DADOS DO FISCAL ==========
    cnpj_fiscal: getText(cv, 'text_mkxn60zf'),
    numero_nf_fiscal: getText(cv, 'numeric_mkx03rz2'),

    // ========== IDs DAS COLUNAS FISCAL (para changeColumnValue) ==========
    id_coluna_arquivo: 'text_mkxsjs4b',
    id_coluna_numero_oc: 'numeric_mkxth4jk',
    id_coluna_valor_pago: 'numeric_mkxsr9k9',
    id_coluna_valor_nf: 'numeric_mkxszed1',
    id_coluna_status: 'color_mkxt3v8n',

    // ========== DADOS DO COMPRAS (para inserir no Fiscal) ==========
    cnpj_compras: comprasData.cnpj,
    numero_nf_compras: comprasData.numero_nota_fiscal,
    link_drive: comprasData.link_drive,
    numero_pc: comprasData.numero_pc,
    valor_pago_compras: comprasData.valor_pago,
    valor_nf_compras: comprasData.valor_nf,
    vencimento: comprasData.vencimento,
    item_id_compras: comprasData.item_id,
    item_name_compras: comprasData.item_name
  };
});

return mappedItems;

// ==================================================
// MAPEAMENTO DE COLUNAS - BOARD COMPRAS
// Versão: 2.3 - Adicionado validação autorização diretoria
// ==================================================

// Pega todos os valores de colunas do item recebido pelo Monday.com
const columnValues = $input.item.json.column_values;

// ========== FUNÇÕES HELPER ==========

// Busca uma coluna pelo seu ID dentro do array de column_values
function getColumn(id) {
  return columnValues.find(col => col.id === id);
}

// Retorna o texto legível de uma coluna
// Se a coluna não existir ou não tiver texto, retorna string vazia
function getText(id) {
  const col = getColumn(id);
  return col ? (col.text || '') : '';
}

// Retorna o valor bruto (JSON) de uma coluna
// Usado para colunas complexas como links, que guardam objetos JSON
function getValue(id) {
  const col = getColumn(id);
  return col && col.value ? col.value : '';
}

// Retorna o texto de uma coluna do tipo Status/Label
// Ex: "FISCAL", "NAO FISCAL", "Aprovado"
function getStatusLabel(id) {
  const col = getColumn(id);
  return col ? (col.text || '') : ''; 
}

// ========== MAPEAMENTO DOS CAMPOS ==========
const mapped = {

  // --- METADADOS DO ITEM ---
  item_id: $input.item.json.id,                          // ID único do item no Monday
  item_name: $input.item.json.name,                      // Nome do item (título da linha)
  board_id: $input.item.json.board?.id || '18257522804', // ID do board

  // --- CAMPOS DO FORMULÁRIO ---
  cnpj: getText('text_mkx0gak5'),                        // CNPJ do fornecedor
  numero_nota_fiscal: getText('numeric_mkx0nenv'),       // Número da nota fiscal
  numero_pc: getText('numeric_mkx0cqda'),                // Número do PC (pedido de compra)
  valor_pago: getText('numeric_mkx075mm'),               // Valor efetivamente pago
  valor_nf: getText('numeric_mkx03rrm'),                 // Valor da nota fiscal
  vencimento: getText('date_mky2wftt'),                  // Data de vencimento
  tipo_documento: getStatusLabel('color_mky38wws'),      // Tipo: "FISCAL" ou "NAO FISCAL"

  // --- IDs DAS COLUNAS DE STATUS ---
  id_coluna_status_jornada: 'color_mkx0anww',                   // Status da jornada do item
  id_coluna_status_autorizacao_diretoria: 'color_mkx0dfjk',     // Status de autorização da diretoria

  // --- STATUS DE AUTORIZAÇÃO DA DIRETORIA ---
  // Retorna o texto do status. Se não preenchido no Monday, retorna "Não Preenchido"
  // Valores possíveis: "Aprovado", "Fornecedor Reprovado", "Não autorizado PC", "NF Saldo", "Para Aprovação"
  status_autorizacao_diretoria: getStatusLabel('color_mkx0dfjk') || 'Não Preenchido',

  // --- LINK DO GOOGLE DRIVE ---
  // A coluna de link guarda um JSON com a URL, precisa ser tratada separadamente
  link_drive: (() => {
    try {
      const linkValue = getValue('link_mkx0jg7b');      // Pega o valor bruto da coluna de link
      if (!linkValue) return '';                         // Se vazio, retorna string vazia
      const parsed = JSON.parse(linkValue);             // Converte o JSON string em objeto
      return parsed.url || '';                          // Retorna só a URL
    } catch (e) {
      console.error('Erro ao fazer parse do link:', e); // Loga erro se o JSON for inválido
      return '';
    }
  })(),

  // ========== VALIDAÇÕES BOOLEANAS ==========

  tem_cnpj: getText('text_mkx0gak5').length > 0,        // true se CNPJ foi preenchido
  tem_vencimento: getText('date_mky2wftt').length > 0,   // true se vencimento foi preenchido
  tem_numero_nf: getText('numeric_mkx0nenv').length > 0, // true se número da NF foi preenchido

  // Verifica se é documento fiscal:
  // 1. Pega o texto do status (ex: "NAO FISCAL")
  // 2. Converte para maiúsculo
  // 3. Se NÃO contém "NAO" → é fiscal → true
  // 4. Se contém "NAO" → não é fiscal → false
  e_documento_fiscal: !getStatusLabel('color_mky38wws').toUpperCase().includes('NAO'),

  // Verifica se a diretoria aprovou o PC:
  // true  → status é exatamente "Aprovado" → segue para escrituração
  // false → qualquer outro valor ou vazio  → bloqueia no nó Trocar
  tem_autorizacao_diretoria: getStatusLabel('color_mkx0dfjk') === 'Aprovado',

  // ========== DADOS ORIGINAIS ==========
  _original_column_values: columnValues  // Dados brutos do Monday para debug
};

return mapped;

