  "79": "TRE PB", "84": "ESTAGIÁRIOS", "85": "SEMSA"
};

function limparValor(valor) {
  if (valor === undefined || valor === null || valor === '') return 0;
  if (typeof valor === 'number') return valor;
  let limpo = String(valor).replace(/[R$\s]/g, '').replace(',', '.');
  return parseFloat(limpo) || 0;
}

for (let item of itensExcel) {
  let valorVR = limparValor(item.json['VR - SALDO']);
  let valorVT = limparValor(item.json['VT - Saldo']);

  let textoInterior = String(item.json['Interior?'] || item.json['interior?'] || '').trim().toUpperCase();
  let codigoContrato = String(item.json['Código'] || item.json['codigo'] || '').trim();

  // [REGRA] TRE PB e Barco Contato = SEMPRE mobilidade
  const codigosMobilidade = ["01.01.0079.01.0001", "01.01.0015.01.0001"];
  let eMobilidade = codigosMobilidade.includes(codigoContrato);

