            motivo: `Calculou ${diasUtilizados} dias. Restam ${diasRestantes} dias.`,
            NOME_DP: rmData.NOME, // O nome limpo, sem a palavra "(Saldo)"
            DATA_INICIO: dataInicioStr,
            DATA_FIM: dataFimStr,
            DIAS_GOZADOS: diasUtilizados
        }
    };
} else {
    return {
        json: {
            acao: "NADA",
            criarFracionado: false,
            motivo: `Lancamento: ${statusLancamento} | Sistema: ${statusSistema}. Nenhuma ação.`
        }
    };
}

// O RM vem direto do nó HTTP (sem loop)
const rmData = $input.first().json; 
const itemsFromMonday = $('PegarChapa').all(); 

let mondayItem = null;
for (let i = 0; i < itemsFromMonday.length; i++) {
    const itemAtual = itemsFromMonday[i].json;
    if (itemAtual.name && !itemAtual.name.includes("(Saldo)")) {
        mondayItem = itemAtual;
        break; 
    }
}

if (!mondayItem) {
    mondayItem = itemsFromMonday[0].json;
}

let statusLancamento = ""; 
let statusSistema = "";    
let dataInicioStr = null;
let dataFimStr = null;
let periodosUsados = 0; // Valor padrão
let diasDireito = rmData.DiasDeDireito || 30; 

if (mondayItem.column_values) {
    for (const col of mondayItem.column_values) {
        if (col.id === 'color_mm28pcnb') statusLancamento = col.text || "";
        if (col.id === 'color_mm27vk6w') statusSistema = col.text || ""; 
        if (col.id === 'date_mm27ndv7') dataInicioStr = col.text; 
        if (col.id === 'date_mm27bqzj') dataFimStr = col.text;
        // 👇 Lê o período atual
        if (col.id === 'numeric_mm27f3yp') periodosUsados = parseInt(col.text) || 0;
    }
}

let diasUtilizados = 0;
if (dataInicioStr && dataFimStr) {
    const dataInicio = new Date(dataInicioStr);
    const dataFim = new Date(dataFimStr);
    const diffTempo = dataFim.getTime() - dataInicio.getTime();
    diasUtilizados = Math.ceil(diffTempo / (1000 * 3600 * 24)) + 1;
}

const diasRestantes = diasDireito - diasUtilizados;

// 🎯 ROTA RECALCULAR (Sniper)
if (statusLancamento === "RECALCULAR") {
    return {
        json: {
            acao: "RECALCULAR", 
            idItemOriginal: mondayItem.id,
            CHAPA: rmData.CHAPA,
            NOME: rmData.NOME + " (Saldo)", 
            DATAADMISSAO: rmData.DATAADMISSAO,
            FIMPERAQUIS: rmData.FIMPERAQUIS,
            DataLimiteGozar: rmData.DataLimiteGozar,
            DiasDeDireito: diasRestantes,
            CODCONTRATO: rmData.CODCONTRATO,
            UNIDADE_MACRO: rmData.UNIDADE_MACRO,
            NOME_SUBSECAO: rmData.NOME_SUBSECAO,
            JORNADA: rmData.JORNADA,
            // 👇 Envia o período somado
            PROXIMO_PERIODO: periodosUsados + 1,
            motivo: "Usuário solicitou recalculo. Saldo será apagado e recriado."
        }
    };
}

//ROTA NORMAL
if (statusLancamento === "SOLICITADO" && statusSistema !== "PROCESSADO" && diasRestantes > 0 && diasUtilizados > 0) {
    return {
        json: {
            acao: "CRIAR_SALDO", 
            criarFracionado: true,
            idItemAntigo: mondayItem.id, 
            CHAPA: rmData.CHAPA,
            NOME: rmData.NOME + " (Saldo)", 
            DATAADMISSAO: rmData.DATAADMISSAO,
            FIMPERAQUIS: rmData.FIMPERAQUIS,
            DataLimiteGozar: rmData.DataLimiteGozar,
            DiasDeDireito: diasRestantes,
            CODCONTRATO: rmData.CODCONTRATO,
            UNIDADE_MACRO: rmData.UNIDADE_MACRO,
            NOME_SUBSECAO: rmData.NOME_SUBSECAO,
            JORNADA: rmData.JORNADA,
            PROXIMO_PERIODO: periodosUsados + 1,
            motivo: `Calculou ${diasUtilizados} dias. Restam ${diasRestantes} dias.`,
            NOME_DP: rmData.NOME, // O nome limpo, sem a palavra "(Saldo)"
            DATA_INICIO: dataInicioStr,
            DATA_FIM: dataFimStr,
            DIAS_GOZADOS: diasUtilizados
        }
    };
} else {
    return {
        json: {
            acao: "NADA",
            criarFracionado: false,
            motivo: `Lancamento: ${statusLancamento} | Sistema: ${statusSistema}. Nenhuma ação.`
        }
    };
}

let dados = $input.first().json;

// 1. Limpeza de Dados (Mapeamento com os cabeçalhos do CSV)
let cargo = String(dados["NOME FUNÇÃO"] || "").toUpperCase().trim();
let secao = String(dados["DESCRIÇÃO SEÇÃO"] || "").toUpperCase().trim();

// 2. Calcular a Idade (Com blindagem para traços ou barras)
let dataNasc = String(dados["Data de Nascimento"] || "");
let idade = 0;
if (dataNasc.includes('-')) {
  let p = dataNasc.split('-');
  idade = new Date().getFullYear() - parseInt(p[0]); // Pega o Ano
} else if (dataNasc.includes('/')) {
  let p = dataNasc.split('/');
  idade = new Date().getFullYear() - parseInt(p[2]);
}

// 3. Empresa, Grupo e Contrato FIXOS para a JCF
let idGrupo = "group_mm0z5jx6"; 
let empresaLabel = "J.C.F. Cavalcanti"; 
let contratoLabel = "J.C.F"; 

// 4. Lógica de Categoria (CLT, Aprendiz, Intermitente)
let categoriaLabel = "CLT"; 
if (cargo.includes("APRENDIZ") || secao.includes("APRENDIZ") || secao.includes("ESTAGIARIO") || cargo.includes("ESTAGIARIO")) {
    categoriaLabel = "CONTRATO";
} else if (secao.includes("INTERMITENTE")) {
    categoriaLabel = "INTERMITENTE";
}

// 5. Regras do PCMSO (JCF cravado em 2 anos)
let validadeAnos = 2; 
let tipoPrazo = "730 DIAS";

// 6. Cálculo Temporal dos Exames (Avançando até o ano atual)
let admissao = String(dados["Data de Admissão"] || "");
let dataExameFormatada = "";
let dataVencimentoFormatada = "";

// Se a data vier com traços (YYYY-MM-DD)
if (admissao.includes('-')) {
    let p = admissao.split('-');
    let dataAdmissao = new Date(parseInt(p[0]), parseInt(p[1]) - 1, parseInt(p[2]));
    let dataAtual = new Date(); 

    let ultimoExame = new Date(dataAdmissao);
    let proximoExame = new Date(dataAdmissao);
    proximoExame.setFullYear(proximoExame.getFullYear() + validadeAnos);

    while (proximoExame < dataAtual) {
        ultimoExame.setFullYear(ultimoExame.getFullYear() + validadeAnos);
        proximoExame.setFullYear(proximoExame.getFullYear() + validadeAnos);
    }

    dataExameFormatada = `${ultimoExame.getFullYear()}-${String(ultimoExame.getMonth() + 1).padStart(2, '0')}-${String(ultimoExame.getDate()).padStart(2, '0')}`;
    dataVencimentoFormatada = `${proximoExame.getFullYear()}-${String(proximoExame.getMonth() + 1).padStart(2, '0')}-${String(proximoExame.getDate()).padStart(2, '0')}`;
} 
// Se a data vier com barras (DD/MM/YYYY)
else if (admissao.includes('/')) {
    let p = admissao.split('/');
    let dataAdmissao = new Date(parseInt(p[2]), parseInt(p[1]) - 1, parseInt(p[0]));
    let dataAtual = new Date(); 

    let ultimoExame = new Date(dataAdmissao);
    let proximoExame = new Date(dataAdmissao);
    proximoExame.setFullYear(proximoExame.getFullYear() + validadeAnos);

    while (proximoExame < dataAtual) {
        ultimoExame.setFullYear(ultimoExame.getFullYear() + validadeAnos);
        proximoExame.setFullYear(proximoExame.getFullYear() + validadeAnos);
    }

    dataExameFormatada = `${ultimoExame.getFullYear()}-${String(ultimoExame.getMonth() + 1).padStart(2, '0')}-${String(ultimoExame.getDate()).padStart(2, '0')}`;
    dataVencimentoFormatada = `${proximoExame.getFullYear()}-${String(proximoExame.getMonth() + 1).padStart(2, '0')}-${String(proximoExame.getDate()).padStart(2, '0')}`;
}

// 7. Guardar tudo no pacote para o Monday
dados.idadeCalculada = idade;
dados.idGrupoCalculado = idGrupo;
dados.empresaLabel = empresaLabel;
dados.contratoLabel = contratoLabel;
dados.categoriaLabel = categoriaLabel;
dados.tipoPrazoCalculado = tipoPrazo;
dados.dataExameFormatada = dataExameFormatada;
dados.dataVencimentoFormatada = dataVencimentoFormatada;

return { json: dados };

const ANO_ALVO = new Date().getFullYear(); 

const mesesNomes = [
  "Janeiro", "Fevereiro", "Março", "Abril", "Maio", "Junho", 
  "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
];

const setoresContato = [
  "ESTAGIARIO", "ADMINISTRACAO", "APRENDIZES", "COMERCIAL",
  "AUTOMAÇÃO INTELIGENTE", "AIONS", "COMPRAS",
  "CONTABILIDADE", "CONTRATOS", "DEPARTAMENTO DE PESSOAL",
  "ESTOQUES", "MARKETING", "OPERAÇÕES", "RECURSOS HUMANOS",
  "SEGURANÇA DO TRABALHO", "TECNOLOGIA DA INFORMAÇÃO",
  "FINANCEIRO", "FISCAL", "BARCO", "CONTRATOS EM TRANSICAO", 
  "CONTRATOS EM TRANSIÇÃO", "DIRETORIA EXECUTIVA", "INSTITUTO PCD"
];

function definirGrupoMonday(nomeSecao, situacaoFuncionario) {
  // 1. Regra de Ouro: Se estiver Afastado ou de Licença, vai para Contato
  const sit = (situacaoFuncionario || "").toUpperCase();
  if (sit.includes("AFASTADO") || sit.includes("LICEN")) {
    return "Contato (adm)";
  }

  if (!nomeSecao) return "OUTROS";
  const secao = nomeSecao.toUpperCase().trim();

  // 2. Verifica se a seção está na nossa super lista de Contato (adm)
  if (setoresContato.some(setor => secao.includes(setor))) {
    return "Contato (adm)";
  }

  // 3. Regras Específicas dos Contratos Restantes
  if (secao.includes("TRE")) return "TRIBUNAL REGIONAL ELEITORAL DA PARAIBA (TREPB)";
  if (secao.includes("CETAM")) return "CENTRO DE EDUCAÇÃO TECNOLÓGICA DO AMAZONAS (CETAM)";
  if (secao.includes("SEDUC")) return "SECRETARIA DE ESTADO DE EDUCAÇÃO E DESPORTO ESCOLAR(SEDUC)";
  if (secao.includes("SEMSA")) return "MANAUS SECRETARIA MUNICIPAL DE SAUDE ( Semsa)";
  if (secao.includes("DETRAN")) return "DEPARTAMENTO ESTADUAL DE TRANSITO (Detran)";

  // 4. Se não for nada disso, cai em OUTROS
  return "OUTROS";
}

// =========================================================
// 2. LER OS DADOS DOS NODES ANTERIORES
// =========================================================
// ATENÇÃO: Substitua 'RM' pelo nome exato do seu node de SQL
const funcionarios = $('recupera funcionarios').all(); 

// ATENÇÃO: Substitua 'Monday Board' pelo nome exato do seu node que buscou a árvore
const boardData = $('itens da rentabilidade').first().json.data.boards[0]; 
const gruposMonday = boardData.groups;

// =========================================================
// 3. FILTRAR, ROTEAR E CONTABILIZAR (AGRUPAMENTO)
// =========================================================
const consolidador = {};

funcionarios.forEach(func => {
  const json = func.json;
  const liquidoFolha = parseFloat(json.LIQUIDO_FOLHA_MENSAL || 0);

  // Filtro 1: Ignora quem não teve folha gerada no mês
  if (liquidoFolha <= 0) return;

  // Descobre o Mês/Ano (Ex: "Fevereiro/2026")
  const numMes = parseInt(json.MES_COMPETENCIA, 10);
  if (!numMes || numMes < 1 || numMes > 12) return; // Ignora se vier mês inválido
  const nomeGrupo = `${mesesNomes[numMes - 1]}/${ANO_ALVO}`;

  // Descobre o Contrato
  const nomeItem = definirGrupoMonday(json.NOME_SECAO, json.SITUACAO);

  // Cria uma chave única combinando Mês + Contrato
  const chaveUnica = `${nomeGrupo}|${nomeItem}`;

  // Se for a primeira vez que essa chave aparece, inicializa o contador
  if (!consolidador[chaveUnica]) {
    consolidador[chaveUnica] = {
      grupo_destino: nomeGrupo,
      item_destino: nomeItem,
      qtd_funcionarios: 0
    };
  }

  // Soma +1 funcionário
  consolidador[chaveUnica].qtd_funcionarios += 1;
});

// =========================================================
// 4. CRUZAR COM O MONDAY E GERAR A SAÍDA
// =========================================================
const resultadoFinal = [];
const avisosDebug = [];

// Transforma o objeto consolidador em uma lista (array) e faz o cruzamento
Object.values(consolidador).forEach(dados => {
  const grupoDestino = dados.grupo_destino;
  const itemDestino = dados.item_destino;

  // Procura o mês no Monday
  const grupoEncontrado = gruposMonday.find(g => g.title === grupoDestino);

  if (grupoEncontrado) {
    // Procura o contrato dentro do mês
    const itemEncontrado = grupoEncontrado.items_page.items.find(i => i.name.trim() === itemDestino);

    if (itemEncontrado) {
      // SUCESSO!
      // Usando o ID da coluna (numeric_mm1rsrrc) que conversamos anteriormente
      const columnValues = JSON.stringify({
        "numeric_mm1rsrrc": dados.qtd_funcionarios
      });

      resultadoFinal.push({
        json: {
          grupo_destino: grupoDestino,
          item_destino: itemDestino,
          qtd_funcionarios: dados.qtd_funcionarios,
          item_id: itemEncontrado.id,
          board_id: boardData.id,
          column_values_string: columnValues
        }
      });
    } else {
      avisosDebug.push(`Contrato '${itemDestino}' não foi achado no mês '${grupoDestino}'.`);
    }
  } else {
    avisosDebug.push(`O grupo '${grupoDestino}' não existe no board de Rentabilidade.`);
  }
});

// Se nada cruzar, avisa!
if (resultadoFinal.length === 0) {
  return [{ 
    json: { 
      erro: "Nenhum ID foi cruzado. Verifique os avisos de debug.", 
      detalhes: avisosDebug 
    } 
  }];
}

return resultadoFinal;

