// ==========================================
// 1. CONFIGURAÇÃO DAS COLUNAS
// ==========================================
const COLUNAS = {
  contrato: 'color_mkzvpj6t',
  competencia: 'color_mkzwr446',
  glosaTotal: 'formula_mm0vz022',
  tipoGlosa: 'color_mkzvxs0x'
};

// ==========================================
// 2. LÓGICA DE PROCESSAMENTO E AGRUPAMENTO
// ==========================================
const agrupamento = {};
const todosItens = [];

// Junta as páginas do n8n (Técnica de Paginação)
$input.all().forEach(pagina => {
    const itensDaPagina = pagina.json?.data?.boards?.[0]?.items_page?.items;
    if (itensDaPagina && itensDaPagina.length > 0) {
        todosItens.push(...itensDaPagina);
    }
});

if (todosItens.length === 0) {
    return [{ json: { aviso: "Nenhum dado retornado do Monday." } }];
}

todosItens.forEach(item => {
  // 💡 TRAVA 1: Removi a trava de cópia. No quadro de Glosas, cópias muitas vezes são registros válidos.
  // if (item.name && item.name.toLowerCase().includes('(copy)')) return; // REMOVIDO

  if (!item.column_values) return;

  let contratoRaw = item.column_values.find(c => c.id === COLUNAS.contrato)?.text;
  let competenciaRaw = item.column_values.find(c => c.id === COLUNAS.competencia)?.text;
  let tipoGlosa = item.column_values.find(c => c.id === COLUNAS.tipoGlosa)?.text;

  // Tenta pegar o display_value (Fórmula). Se não tiver, pega o text normal.
  let colValor = item.column_values.find(c => c.id === COLUNAS.glosaTotal);
  let valorTexto = colValor?.display_value || colValor?.text;

  // FILTRO: Ignora espaços extras e exige apenas que CONTENHA a palavra "GLOSA PENAL"
  if (!tipoGlosa || !tipoGlosa.toUpperCase().includes('GLOSA PENAL')) return;

  let contrato = contratoRaw ? contratoRaw.trim() : "Sem Contrato";
  let competencia = competenciaRaw ? competenciaRaw.trim() : "Sem Competência";

  // Limpeza super robusta de Valor Financeiro (Lida com R$, pontos e vírgulas)
  let valorSoma = 0;
  if (valorTexto) {
    // Remove símbolos de moeda, espaços. Troca vírgula decimal brasileira por ponto JS.
    let limpo = valorTexto.replace(/[R$\s]/g, ''); 
    if (limpo.includes(',') && limpo.includes('.')) {
        // Formato complexo ex: 1.500,50 -> remove ponto, troca vírgula
        limpo = limpo.lastIndexOf(',') > limpo.lastIndexOf('.') ? limpo.replace(/\./g, '').replace(',', '.') : limpo.replace(/\,/g, '');
    } else if (limpo.includes(',')) {
        // Formato simples ex: 1500,50 -> troca vírgula
        limpo = limpo.replace(',', '.');
    }
    valorSoma = parseFloat(limpo);
    if (isNaN(valorSoma)) valorSoma = 0;
  }

  // 💡 TRAVA 2 (Blindagem Matemática): Arredonda o número recebido para eliminar imprecisões binárias BINÁRIAS loucas do Monday/JS.
  // Isso resolve aquele erro louco dos decimais longos no input.
  valorSoma = Math.round(valorSoma * 1e6) / 1e6;

  // Agrupamento e Soma
  if (!agrupamento[competencia]) agrupamento[competencia] = {};
  if (!agrupamento[competencia][contrato]) agrupamento[competencia][contrato] = 0;

  agrupamento[competencia][contrato] += valorSoma;
});

// ==========================================
// 3. MONTAGEM DA SAÍDA
// ==========================================
const resultadoFinal = [];

for (const comp in agrupamento) {
  for (const cont in agrupamento[comp]) {

    // 💡 TRAVA 3 (Arredondamento Final): Arredonda o TOTAL MONETÁRIO acumulado exato para 2 casas decimais.
    // Isso força o JavaScript a entregar "dinheiro" limpo (ex: .35) idêntico ao total da interface do Monday.
    let totalLimpo = agrupamento[comp][cont];
    totalLimpo = Math.round(totalLimpo * 100) / 100;

    resultadoFinal.push({
      json: {
        competencia: comp,
        contrato: cont,
        glosa_total: totalLimpo // <--- Número exato idêntico ao Monday
      }
    });
  }
}

if (resultadoFinal.length === 0) {
    return [{ json: { aviso: "Nenhum valor encontrado com o status 'GLOSA PENAL'." } }];
}

return resultadoFinal;

