// 1. Resgata os valores calculados lá de trás (Substitua pelo nome correto do seu nó de cálculo!)
const calculos = $('Soma total do valor').all(); 

// 2. Pega a planta baixa do board de Rentabilidade que o HTTP Request acabou de buscar
const boardData = $input.all()[0]?.json?.data?.boards?.[0];
if (!boardData) {
    return [{ json: { erro: "Dados do Board de Rentabilidade não encontrados." } }];
}
const gruposMonday = boardData.groups;

const resultadoFinal = [];
const avisosDebug = [];

// ==========================================
// DICIONÁRIOS DE TRADUÇÃO (GLOSAS -> RENTABILIDADE)
// ==========================================
// Traduz a etiqueta de contrato para o nome exato da linha no board de rentabilidade
const mapContratos = {
  "CETAM": "CENTRO DE EDUCAÇÃO TECNOLÓGICA DO AMAZONAS (CETAM)",
  "SEDUC": "SECRETARIA DE ESTADO DE EDUCAÇÃO E DESPORTO ESCOLAR(SEDUC)",
  "SEMSA": "MANAUS SECRETARIA MUNICIPAL DE SAUDE ( Semsa)",
  "DETRAN": "DEPARTAMENTO ESTADUAL DE TRANSITO (Detran)",
  "TRE PB": "TRIBUNAL REGIONAL ELEITORAL DA PARAIBA (TREPB)", // Cuidado com espaços na etiqueta
  "ADM": "Contato (adm)"
};

// Transforma o mês todo maiúsculo do board de Glosas para o formato Capitalizado
const mapMeses = {
  "JANEIRO": "Janeiro", "FEVEREIRO": "Fevereiro", "MARÇO": "Março", "ABRIL": "Abril",
  "MAIO": "Maio", "JUNHO": "Junho", "JULHO": "Julho", "AGOSTO": "Agosto",
  "SETEMBRO": "Setembro", "OUTUBRO": "Outubro", "NOVEMBRO": "Novembro", "DEZEMBRO": "Dezembro"
};

// 3. Faz o Match (Cruzamento)
calculos.forEach(calc => {
  const compOriginal = calc.json.competencia; // Ex: "FEVEREIRO/26" ou "FEVEREIRO / 26"
  const contOriginal = calc.json.contrato;    // Ex: "SEMSA"
  const valorTotal = calc.json.glosa_total;   // Ex: 19489.60

  // Pula se por acaso o item for de "NÃO INICIADO" ou sem competência válida
  if (!compOriginal || !compOriginal.includes('/')) return;

  // --- TRADUÇÃO DO GRUPO (MÊS) ---
  // Quebra "FEVEREIRO/26" -> ["FEVEREIRO", "26"]
  let partesComp = compOriginal.split('/');
  let mesCru = partesComp[0].trim().toUpperCase(); 

  let mesTraduzido = mapMeses[mesCru] || mesCru;
  let grupoDestino = `${mesTraduzido}/2026`; // Fica: "Fevereiro/2026"

  // --- TRADUÇÃO DO ITEM (CONTRATO) ---
  let contLimpo = contOriginal ? contOriginal.trim().toUpperCase() : "";
  let itemDestino = mapContratos[contLimpo] || "Contato (adm)"; // Se for uma etiqueta nova, cai no ADM por padrão

  // --- BUSCA NO MONDAY ---
  // Procura o grupo no Monday (Ex: "Fevereiro/2026")
  const grupoEncontrado = gruposMonday.find(g => g.title === grupoDestino);

  if (grupoEncontrado) {
    // Procura o contrato dentro do mês (Ex: "MANAUS SECRETARIA MUNICIPAL...")
    // Usamos um include flexível para evitar problemas com espaços extras nos nomes das linhas
    const itemEncontrado = grupoEncontrado.items_page.items.find(i => 
        i.name.trim().toLowerCase() === itemDestino.trim().toLowerCase()
    );

    if (itemEncontrado) {
      // SUCESSO! Achou o ID. Monta o pacote para o HTTP Request final (Mutation).
      resultadoFinal.push({
        json: {
          competencia_original: compOriginal,
          contrato_original: contOriginal,
          grupo_destino: grupoDestino,
          item_destino: itemDestino,
          glosa_total: valorTotal,
          item_id: itemEncontrado.id // <-- ID dinâmico encontrado!
        }
      });
    } else {
      avisosDebug.push(`Contrato '${itemDestino}' não foi achado no mês de '${grupoDestino}'.`);
    }
  } else {
    avisosDebug.push(`O grupo (mês) '${grupoDestino}' não existe no board de Rentabilidade.`);
  }
});

// Se nada cruzou, devolve o erro pra gente saber onde falhou
if (resultadoFinal.length === 0) {
  return [{ 
    json: { 
      erro: "Nenhum ID foi cruzado. Verifique os nomes dos grupos e itens no Monday.", 
      detalhes: avisosDebug 
    } 
  }];
}

return resultadoFinal;

