// --- LÓGICA DE DATA ---
const hoje = new Date();
const hojeFormatado = `${(hoje.getMonth() + 1).toString().padStart(2, '0')}-${hoje.getDate().toString().padStart(2, '0')}`;

const dataParaComparar = hojeFormatado; 

const aniversariantes = [];

for (const item of $input.all()) {
  const colunas = item.json.column_values;

  const colAniversario = colunas.find(c => c.id === 'data_15__1'); 
  const colSetor = colunas.find(c => c.id === 'setor__1');
  const colFoto = colunas.find(c => c.id === 'arquivos__1');

  // NOVA LINHA AQUI: Substitua pelo ID real da coluna Função
  const colFuncao = colunas.find(c => c.id === 'status_10__1'); 

  if (colAniversario && colAniversario.text) {
    // Remove espaços e garante o formato MM-DD
    const dataLimpa = colAniversario.text.trim(); 
    const partes = dataLimpa.split('-'); 

    if (partes.length >= 3) {
      const mesDiaAniversario = `${partes[1]}-${partes[2]}`;

      if (mesDiaAniversario === dataParaComparar) {
        let assetId = '';
        if (colFoto && colFoto.value) {
          try {
            const fotoDados = JSON.parse(colFoto.value);
            if (fotoDados.files && fotoDados.files.length > 0) {
              assetId = fotoDados.files[0].assetId;
            }
          } catch (e) {}
        }

        aniversariantes.push({
          json: {
            nome: item.json.name,
            setor: colSetor ? colSetor.text : 'Geral',
            // NOVA LINHA AQUI: Enviando a função para o próximo Node
            funcao: colFuncao ? colFuncao.text : 'Não informada', 
            assetId: assetId,
            data_original: colAniversario.text
          }
        });
      }
    }
  }
}

return aniversariantes;

