// Nó 3 — Pré-triagem: filtra itens inativos há mais de 24h
const HORAS_INATIVIDADE = 24;
const agora = new Date();
const limiteMs = HORAS_INATIVIDADE * 60 * 60 * 1000;

const itensParaAnalisar = [];

for (const item of $input.all()) {
  const lastUpdate = new Date(item.json.lastupdate);
  const diffMs = agora.getTime() - lastUpdate.getTime();
  const diffHoras = diffMs / (1000 * 60 * 60);

  if (diffMs > limiteMs) {
    itensParaAnalisar.push({
      json: {
        pulseID: item.json.pulseID,
        boardID: item.json.boardID,
        lastupdate: item.json.lastupdate,
        notificado: item.json.notificado,
        ultima_notificacao: item.json.ultima_notificacao,
        horas_inativo: Math.round(diffHoras),
        dias_inativo: Math.round(diffHoras / 24),
        id_datatable: item.json.id
      }
    });
  }
}

return itensParaAnalisar;

// Nó 9 — Parse Resposta IA
const iaResponse = $('Message a model').item.json;
const dadosOriginais = $('Code Node - Montar Prompt').item.json;

let responseText = '';
if (iaResponse.message) {
  responseText = iaResponse.message;
} else if (iaResponse.content && Array.isArray(iaResponse.content)) {
  responseText = iaResponse.content[0].text;
} else if (iaResponse.text) {
  responseText = iaResponse.text;
} else {
  responseText = JSON.stringify(iaResponse);
}

let analise;
try {
  const clean = responseText.replace(/```json|```/g, '').trim();
  analise = JSON.parse(clean);
} catch (e) {
  return [{
    json: {
      ...dadosOriginais,
      deve_notificar: false,
      erro_parse: true,
      resposta_raw: responseText
    }
  }];
}

const userMap = dadosOriginais.userMap || {};

const gerarMencaoHTML = (userId) => {
  let nome = null;
  for (const [key, val] of Object.entries(userMap)) {
    if (Number(val) === Number(userId)) {
      nome = key;
      break;
    }
  }
  if (!nome) return '';
  const nomeFormatado = nome.toLowerCase().replace(/\s+/g, '-');
  return `<a class="user_mention_editor router" href="https://contato-serv.monday.com/users/${userId}-${nomeFormatado}" data-mention-type="User" data-mention-id="${userId}" target="_blank" rel="noopener noreferrer">@${nome}</a>`;
};

// IDs de quem DEVE (cobrados)
const todosIdsDevedores = [];
if (analise.user_id_quem_deve) {
  todosIdsDevedores.push(Number(analise.user_id_quem_deve));
}
if (analise.user_ids_adicionais && Array.isArray(analise.user_ids_adicionais)) {
  analise.user_ids_adicionais.forEach(id => {
    if (id && !todosIdsDevedores.includes(Number(id))) {
      todosIdsDevedores.push(Number(id));
    }
  });
}

// IDs do PSC (ciência) — garante que não repete devedores
const todosIdsPSC = [];
if (analise.user_ids_psc && Array.isArray(analise.user_ids_psc)) {
  analise.user_ids_psc.forEach(id => {
    const numId = Number(id);
    if (numId && !todosIdsDevedores.includes(numId) && !todosIdsPSC.includes(numId)) {
      todosIdsPSC.push(numId);
    }
  });
}

// Menções HTML dos devedores
const mencoesDevedoresHTML = todosIdsDevedores
  .map(id => gerarMencaoHTML(id))
  .filter(m => m !== '')
  .join(' ');

// Menções HTML do PSC
const mencoesPSCHTML = todosIdsPSC
  .map(id => gerarMencaoHTML(id))
  .filter(m => m !== '')
  .join(' ');

// Converter markdown residual para HTML (segurança caso a IA ignore as instruções)
const converterMarkdown = (texto) => {
  return String(texto || '')
    .replace(/\*\*(.+?)\*\*/g, '<b>$1</b>')
    .replace(/\*(.+?)\*/g, '<i>$1</i>');
};

// Montar mensagem completa: menções + corpo + seção PSC (se houver)
let mensagemMonday = '';
if (analise.deve_notificar) {
  const cabecalho = `<p>${mencoesDevedoresHTML}</p>`;
  const corpo = `<p>${converterMarkdown(analise.mensagem_monday)}</p>`;
  const psc = mencoesPSCHTML
    ? `<p>PSC: ${mencoesPSCHTML}</p>`
    : '';
  mensagemMonday = cabecalho + corpo + psc;
}

const linkDemanda = `https://contato-serv.monday.com/boards/${dadosOriginais.boardID}/pulses/${dadosOriginais.pulseID}`;

return [{
  json: {
    deve_notificar: analise.deve_notificar,
    motivo: analise.motivo,
    quem_deve: analise.quem_deve,
    nome_quem_deve: analise.nome_quem_deve,
    user_id_quem_deve: analise.user_id_quem_deve,
    user_ids_adicionais: analise.user_ids_adicionais || [],
    user_ids_psc: todosIdsPSC,
    urgencia: analise.urgencia,
    prazo_detectado: analise.prazo_detectado,
    prazo_vencido: analise.prazo_vencido,
    mensagem_monday_html: mensagemMonday,
    mensagem_monday: analise.mensagem_monday,
    mensagem_whatsapp: analise.mensagem_whatsapp,
    setores_envolvidos: analise.setores_envolvidos,
    pulseID: dadosOriginais.pulseID,
    boardID: dadosOriginais.boardID,
    itemName: dadosOriginais.itemName,
    itemId: dadosOriginais.itemId,
    setorDemandante: dadosOriginais.setorDemandante,
    setorDemandado: dadosOriginais.setorDemandado,
    horas_inativo: dadosOriginais.horas_inativo,
    dias_inativo: dadosOriginais.dias_inativo,
    id_datatable: dadosOriginais.id_datatable,
    linkDemanda: linkDemanda,
    updates: dadosOriginais.updates,
    userMap: dadosOriginais.userMap,
    ultimoUpdateId: dadosOriginais.ultimoUpdateId
  }
}];

// Nó 7 — Montar Prompt para análise da IA
const itemData = $('HTTP Request - Monday GraphQL').item.json;
const preTriagem = $('Code Node - Pré-triagem').item.json;

const item = itemData.data.items[0];

const getColumn = (id) => {
  const col = item.column_values.find(c => c.id === id);
  return col ? { text: col.text || '', value: col.value || '' } : { text: '', value: '' };
};

const demandante = getColumn('person6');
const demandado = getColumn('pessoas_mkkdd33s');
const setorDemandante = getColumn('dropdown_mkkdndgn');
const setorDemandado = getColumn('sele__o_m_ltipla_mkkd31pa');
const status = getColumn('status_mkkd4hrz');

const parsePersonIds = (coluna) => {
  try {
    const parsed = JSON.parse(coluna.value);
    if (parsed.personsAndTeams) {
      return parsed.personsAndTeams
        .filter(p => p.kind === 'person')
        .map(p => p.id);
    }
    return [];
  } catch (e) {
    return [];
  }
};

const demandanteIds = parsePersonIds(demandante);
const demandadoIds = parsePersonIds(demandado);

const usersData = $('HTTP Request1').first().json;
const userMap = {};

if (usersData.data && usersData.data.users) {
  usersData.data.users.forEach(u => {
    userMap[u.name] = Number(u.id);
  });
}

item.updates.forEach(u => {
  if (u.creator && u.creator.id && u.creator.name) {
    userMap[u.creator.name] = Number(u.creator.id);
  }
});

const todasMensagens = [];

item.updates.forEach(u => {
  todasMensagens.push({
    autor: u.creator.name,
    autorId: u.creator.id,
    data: u.created_at,
    texto: u.text_body,
    tipo: 'atualização'
  });

  if (u.replies && u.replies.length > 0) {
    u.replies.forEach(r => {
      todasMensagens.push({
        autor: r.creator.name,
        autorId: r.creator.id,
        data: r.created_at,
        texto: r.text_body,
        tipo: 'resposta'
      });

      if (r.creator && r.creator.id && r.creator.name) {
        userMap[r.creator.name] = Number(r.creator.id);
      }
    });
  }
});

todasMensagens.sort((a, b) => new Date(a.data) - new Date(b.data));

const ultimoUpdateId = item.updates && item.updates.length > 0
  ? item.updates[0].id
  : null;

const updates = todasMensagens.map((m, i) => {
  return `[Mensagem ${i + 1} de ${todasMensagens.length}] Autor: ${m.autor} (ID: ${m.autorId}) | Data: ${m.data}\nMensagem: ${m.texto}`;
}).join('\n\n');

const agora = new Date().toISOString();

const prompt = `Você é um assistente de gestão de demandas corporativas. Analise a demanda abaixo e responda EXCLUSIVAMENTE em JSON válido, sem markdown, sem explicação, sem texto fora do JSON.

CONTEXTO DA DEMANDA:
- Nome: ${item.name}
- ID: ${item.id}
- Status atual: ${status.text}
- Horas sem atualização: ${preTriagem.horas_inativo}
- Dias sem atualização: ${preTriagem.dias_inativo}
- Demandante: ${demandante.text} (IDs Monday: ${JSON.stringify(demandanteIds)})
- Demandado: ${demandado.text} (IDs Monday: ${JSON.stringify(demandadoIds)})
- Setor(es) Demandante(s): ${setorDemandante.text}
- Setor(es) Demandado(s): ${setorDemandado.text}
- Data/hora atual: ${agora}

MAPEAMENTO COMPLETO DE USUÁRIOS (Nome → ID Monday):
${JSON.stringify(userMap, null, 2)}

IDs dos Demandantes: ${JSON.stringify(demandanteIds)}
IDs dos Demandados: ${JSON.stringify(demandadoIds)}

HISTÓRICO COMPLETO DA DEMANDA (em ordem cronológica, da mais antiga para a mais recente):
A ÚLTIMA MENSAGEM DA LISTA É A MAIS RECENTE E DEVE TER MAIOR PESO NA SUA ANÁLISE.
${updates || 'Nenhuma atualização encontrada.'}

REGRAS DE ANÁLISE:
1. PRIORIDADE MÁXIMA: Analise as mensagens em ORDEM CRONOLÓGICA REVERSA (da mais recente para a mais antiga). A decisão de "quem deve" se baseia PRIMARIAMENTE na última mensagem da thread, NÃO em ações listadas em atas ou documentos antigos.
2. Se a última mensagem é de alguém COBRANDO ou SOLICITANDO algo a outra pessoa, quem deve é a PESSOA COBRADA (quem foi mencionado/solicitado), NÃO quem cobrou.
3. Se a última mensagem é do demandado pedindo informações ao demandante, quem deve é o demandante.
4. Se alguém mencionou um prazo ("até sexta", "3 dias", "semana que vem", etc.), calcule se o prazo já venceu com base na data atual. Se o prazo ainda NÃO venceu, NÃO notifique (deve_notificar = false).
5. Escreva a mensagem como se você fosse um colega de trabalho solicitando retorno, de forma natural e humana. NUNCA mencione que é um sistema automático, bot, automação, cobrança automática ou qualquer variação disso. A mensagem deve parecer que foi escrita por uma pessoa real pedindo atualização.
6. A urgência deve ser: "baixa" (1-2 dias parado), "media" (3-5 dias), "alta" (mais de 5 dias).
7. IMPORTANTE: O campo "user_id_quem_deve" DEVE conter o ID numérico do Monday da pessoa. Use o MAPEAMENTO COMPLETO DE USUÁRIOS fornecido acima. NUNCA retorne null neste campo.
8. Se houver múltiplas pessoas devendo (ex: alguém cobrou 3 pessoas de uma vez), coloque a primeira como principal em "user_id_quem_deve" e as demais em "user_ids_adicionais". Use o MAPEAMENTO para buscar os IDs de TODAS as pessoas mencionadas.
9. NUNCA confunda quem COBRA com quem DEVE. Se a pessoa X mandou mensagem dizendo "Solicito ao Y e Z que façam tal coisa", quem deve são Y e Z, NÃO o X.
10. CAMPO PSC (Para Seu Conhecimento): Identifique quem deve ser notificado apenas para CIÊNCIA — sem ser cobrado. Regras do PSC:
    - Se estamos cobrando o DEMANDADO: inclua os IDs dos DEMANDANTES em "user_ids_psc"
    - Se estamos cobrando o DEMANDANTE: inclua os IDs dos DEMANDADOS em "user_ids_psc"
    - Se outras pessoas foram mencionadas na última mensagem como partes interessadas (ex: supervisores, gestores, outros colaboradores citados), inclua seus IDs também em "user_ids_psc"
    - Não inclua em "user_ids_psc" quem já está em "user_id_quem_deve" ou "user_ids_adicionais"
    - Se não houver ninguém para PSC, retorne array vazio []
    - Use o MAPEAMENTO COMPLETO para resolver os IDs. NUNCA inclua null ou 0.
11. FORMATAÇÃO: Use HTML para negrito quando necessário: <b>texto</b>. NUNCA use markdown (**texto**). Não use emojis. Não mencione o ID numérico da demanda. Escreva de forma direta, natural e concisa — como uma mensagem de texto entre colegas.

FORMATO DE RESPOSTA (JSON puro):
{
  "deve_notificar": true/false,
  "motivo": "breve explicação da decisão",
  "quem_deve": "demandante" ou "demandado" ou "ambos",
  "nome_quem_deve": "Nome da pessoa principal que deve",
  "user_id_quem_deve": 12345678,
  "user_ids_adicionais": [87654321, 11223344],
  "user_ids_psc": [99887766, 55443322],
  "urgencia": "baixa" ou "media" ou "alta",
  "prazo_detectado": "data do prazo se encontrado, null se não",
  "prazo_vencido": true/false/null,
  "mensagem_monday": "Mensagem de cobrança para postar no Monday (SEM mencionar PSC — as menções serão adicionadas automaticamente pelo sistema)",
  "mensagem_whatsapp": "Mensagem de cobrança para enviar no WhatsApp do setor",
  "setores_envolvidos": ["setor1", "setor2"] — USE APENAS setores desta lista exata: Operacional, RH, DP, Financeiro, Jurídico, Administrativo, TI, Compras, Fiscal, Comercial, Diretoria, Sesmt, Contratos. Não invente outros nomes.
}`;

return [
  {
    json: {
      prompt: prompt,
      pulseID: preTriagem.pulseID,
      boardID: preTriagem.boardID,
      itemName: item.name,
      itemId: item.id,
      demandante: demandante,
      demandado: demandado,
      demandanteIds: demandanteIds,
      demandadoIds: demandadoIds,
      setorDemandante: setorDemandante.text,
      setorDemandado: setorDemandado.text,
      horas_inativo: preTriagem.horas_inativo,
      dias_inativo: preTriagem.dias_inativo,
      id_datatable: preTriagem.id_datatable,
      updates: item.updates,
      userMap: userMap,
      ultimoUpdateId: ultimoUpdateId
    }
  }
];

// Nó 10.1 — Preparar mutations prontas para Monday + lista de notificações
const dados = $input.item.json;

// IDs dos devedores (cobrados)
const userIds = [];
if (dados.user_id_quem_deve) {
  userIds.push(Number(dados.user_id_quem_deve));
}
if (dados.user_ids_adicionais && Array.isArray(dados.user_ids_adicionais)) {
  dados.user_ids_adicionais.forEach(id => {
    const numId = Number(id);
    if (numId && !userIds.includes(numId)) {
      userIds.push(numId);
    }
  });
}

// IDs do PSC (ciência)
const userIdsPSC = [];
if (dados.user_ids_psc && Array.isArray(dados.user_ids_psc)) {
  dados.user_ids_psc.forEach(id => {
    const numId = Number(id);
    if (numId && !userIds.includes(numId) && !userIdsPSC.includes(numId)) {
      userIdsPSC.push(numId);
    }
  });
}

const escapeGraphQL = (str) => {
  return str
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '');
};

const bodyEscapado = escapeGraphQL(dados.mensagem_monday_html);
const ultimoUpdateId = dados.ultimoUpdateId || null;

// Mutation do create_update (reply)
let mutationUpdate;
if (ultimoUpdateId) {
  mutationUpdate = {
    query: `mutation { create_update(item_id: ${dados.pulseID}, parent_id: ${ultimoUpdateId}, body: "${bodyEscapado}") { id } }`
  };
} else {
  mutationUpdate = {
    query: `mutation { create_update(item_id: ${dados.pulseID}, body: "${bodyEscapado}") { id } }`
  };
}

// Texto da notificação de cobrança
const textoCobranca = escapeGraphQL(
  dados.mensagem_monday || 'Você possui uma demanda pendente de atualização. Favor verificar.'
);

// Texto da notificação de ciência (PSC)
const textoCiencia = escapeGraphQL(
  `[CIÊNCIA] A demanda "${dados.itemName}" recebeu uma cobrança automática. Você foi incluído para acompanhamento.`
);

