  groupedMessages[groupId].messages.push({
    data_hora: dataHora,
    sender: sender,
    content: content
  });

  // Guardar IDs para atualizar depois
  groupedMessages[groupId].message_ids.push(messageId);

  // Atualizar período (pegar primeira e última mensagem)
  if (new Date(timestamp) < new Date(groupedMessages[groupId].period_start)) {
    groupedMessages[groupId].period_start = timestamp;
