  if (new Date(timestamp) > new Date(groupedMessages[groupId].period_end)) {
    groupedMessages[groupId].period_end = timestamp;
  }

  // Extrair links da mensagem
  const urlRegex = /(https?:\/\/[^\s]+)/g;
  const foundLinks = content.match(urlRegex);
  if (foundLinks) {
    groupedMessages[groupId].links.push(...foundLinks);
  }
}

