  query: `mutation { create_notification(user_id: ${userId}, target_id: ${dados.pulseID}, text: "${textoCiencia}", target_type: Project) { text } }`
}));

// Unir todas as notificações: devedores primeiro, PSC depois
const notificacoes = [...notificacoesCobranca, ...notificacoesPSC];

return [{
