// ENGINE DE PDF
// ============================================================
function normalizarParaPDF(str) {
  return String(str)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\x00-\x7F]/g, '');
}

function truncar(str, max) {
  const n = normalizarParaPDF(str);
  if (n.length <= max) return n;
  return n.substring(0, max - 3).trimEnd() + '...';
}

function criarGerador() {
  let pdf = '%PDF-1.4\n';
  const objetos = [];
  const offsets = {};
  const F = { normal: 'F1', bold: 'F2' };
  const C = {
    azulEscuro: [0.07, 0.12, 0.19],
    azulMedio:  [0.18, 0.40, 0.65],
    branco:     [1.00, 1.00, 1.00],
    preto:      [0.10, 0.10, 0.10],
    cinzaClaro: [0.95, 0.95, 0.95],
    cinzaMedio: [0.75, 0.75, 0.75],
    verde:      [0.13, 0.55, 0.13],
    amarelo:    [0.70, 0.55, 0.00],
    laranja:    [0.80, 0.35, 0.00],
    vermelho:   [0.75, 0.10, 0.10],
  };
  const rgb = c => c[0].toFixed(3)+' '+c[1].toFixed(3)+' '+c[2].toFixed(3);
  const esc = s => normalizarParaPDF(String(s)).replace(/[()\\]/g, '\\$&');

  function pagina() {
    const ops = [];
    return {
      rect(x,y,w,h,cf,cb){
        ops.push('q');
        if(cf) ops.push(rgb(cf)+' rg '+x+' '+y+' '+w+' '+h+' re f');
        if(cb) ops.push(rgb(cb)+' RG 0.5 w '+x+' '+y+' '+w+' '+h+' re S');
        ops.push('Q');
      },
      linha(x1,y1,x2,cor,esp){
        ops.push('q '+(esp||0.5)+' w '+rgb(cor||C.cinzaMedio)+' RG '+x1+' '+y1+' m '+x2+' '+y1+' l S Q');
      },
      txt(x,y,t,fonte,tam,cor){
        ops.push('q BT /'+(fonte||F.normal)+' '+(tam||11)+' Tf '+rgb(cor||C.preto)+' rg '+x+' '+y+' Td ('+esc(t)+') Tj ET Q');
      },
      build(){ return ops.join('\n'); }
    };
  }

  function addObj(id, conteudo){ objetos.push({ id, conteudo }); }

  function compilar(streams) {
    const nf = 3 + streams.length * 2;
    addObj(1, '<</Type /Catalog /Pages 2 0 R>>');
    addObj(2, '<</Type /Pages /Kids ['+streams.map((_,i)=>(3+i*2)+' 0 R').join(' ')+'] /Count '+streams.length+'>>');
    streams.forEach((s,i) => {
      const pid=3+i*2, sid=4+i*2, len=Buffer.byteLength(s,'latin1');
      addObj(pid, '<</Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Contents '+sid+' 0 R /Resources <</Font <</F1 '+nf+' 0 R /F2 '+(nf+1)+' 0 R>>>>>>');
      addObj(sid, '<</Length '+len+'>>\nstream\n'+s+'\nendstream');
    });
    addObj(nf,   '<</Type /Font /Subtype /Type1 /BaseFont /Helvetica>>');
    addObj(nf+1, '<</Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold>>');
    objetos.forEach(({id,conteudo}) => {
      offsets[id] = Buffer.byteLength(pdf,'latin1');
      pdf += id+' 0 obj\n'+conteudo+'\nendobj\n';
    });
    const xp = Buffer.byteLength(pdf,'latin1');
    const mx = Math.max(...objetos.map(o => o.id));
    let xref = 'xref\n0 '+(mx+1)+'\n0000000000 65535 f \n';
    for(let i=1;i<=mx;i++)
      xref += (offsets[i]!==undefined ? String(offsets[i]).padStart(10,'0') : '0000000000')+' 00000 n \n';
    xref += 'trailer\n<</Size '+(mx+1)+' /Root 1 0 R>>\nstartxref\n'+xp+'\n%%EOF';
    return Buffer.from(pdf+xref,'latin1');
  }

  return { pagina, compilar, C, F };
}

