const rmResponse = $('BuscarRM').item.json;
const rmData = Array.isArray(rmResponse) ? rmResponse[0] : rmResponse;
const mondayItem = $('LerCardMonday').item.json;

let dataInicioStr = null;
let dataFimStr = null;
let diasDireitoNoCard = 0;
let periodoAtualNoMonday = 0;
let idCardDP = null;
let dataLimiteGozarMonday = null;

if (mondayItem.column_values) {
    for (const col of mondayItem.column_values) {
        if (col.id === 'date_mm27ndv7') dataInicioStr = col.text;
        if (col.id === 'date_mm27bqzj') dataFimStr = col.text;
        if (col.id === 'numeric_mm2wmaxe') diasDireitoNoCard = parseFloat(col.text) || 0;
        if (col.id === 'numeric_mm27f3yp') periodoAtualNoMonday = parseInt(col.text) || 0;
        if (col.id === 'text_mm2cnkhm') idCardDP = col.text;
        if (col.id === 'date_mm276v4g') dataLimiteGozarMonday = col.text;
    }
}

let grupoMes = "";
if (dataInicioStr) {
    const partesData = dataInicioStr.split('-');
    if (partesData.length >= 2) {
        grupoMes = partesData[1] + '/' + partesData[0];
    }
}

const saldoDisponivel = diasDireitoNoCard > 0
    ? diasDireitoNoCard
    : Math.ceil(parseFloat(rmData.FERIAS_A_MARCAR) || 30);

const proximoPeriodoParaDP = periodoAtualNoMonday + 1;

let diasUtilizados = 0;
if (dataInicioStr && dataFimStr) {
    const dataInicio = new Date(dataInicioStr + 'T00:00:00');
    const dataFim = new Date(dataFimStr + 'T00:00:00');
    const diffTempo = dataFim.getTime() - dataInicio.getTime();
    diasUtilizados = Math.ceil(diffTempo / (1000 * 3600 * 24)) + 1;
}

if (diasUtilizados === 0) {
    return { json: { acao: "NADA", motivo: "Datas não preenchidas." } };
}

let dataLimiteGozarFormatada = dataLimiteGozarMonday || "";
let fimAquisitivoFormatado = "";
let inicioAquisitivoFormatado = "";
let dataAdmissaoFormatada = "";

if (rmData.FIMPERAQUIS) {
    const fimAquisitivo = new Date(rmData.FIMPERAQUIS);
    fimAquisitivoFormatado = fimAquisitivo.toISOString().split('T')[0];

    if (!dataLimiteGozarFormatada) {
        const dataLimiteFallback = new Date(fimAquisitivo);
        dataLimiteFallback.setFullYear(dataLimiteFallback.getFullYear() + 1);
        dataLimiteGozarFormatada = dataLimiteFallback.toISOString().split('T')[0];
    }
}

if (rmData.INICIOPERAQUIS) {
    inicioAquisitivoFormatado = new Date(rmData.INICIOPERAQUIS).toISOString().split('T')[0];
}

if (rmData.DATAADMISSAO) {
    dataAdmissaoFormatada = new Date(rmData.DATAADMISSAO).toISOString().split('T')[0];
}

const diasRestantes = saldoDisponivel - diasUtilizados;

const hoje = new Date();
hoje.setHours(0, 0, 0, 0);

const dataInicioObj = new Date(dataInicioStr + 'T00:00:00');
const diasAteInicioFerias = Math.ceil(
    (dataInicioObj.getTime() - hoje.getTime()) / (1000 * 3600 * 24)
);

const dadosBase = {
    idItemAntigo: mondayItem.id,
    idCardDP: idCardDP,
    boardId: mondayItem.board?.id || mondayItem.board_id,
    CHAPA: rmData.CHAPA,
    NOME: rmData.NOME,
    NOME_ORIGINAL: rmData.NOME,
    NOME_DP: rmData.NOME,
    UNIDADE_MACRO: rmData.UNIDADE_MACRO,
    NOME_SUBSECAO: rmData.NOME_SUBSECAO,
    CODCONTRATO: rmData.CODCONTRATO,
    JORNADA: rmData.JORNADA,
    INICIOPERAQUIS: inicioAquisitivoFormatado,
    FIMPERAQUIS: fimAquisitivoFormatado,
    DATAADMISSAO: dataAdmissaoFormatada,
    DataLimiteGozar: dataLimiteGozarFormatada,
    DATA_INICIO: dataInicioStr,
    DATA_FIM: dataFimStr,
    DIAS_GOZADOS: diasUtilizados,
    NOME_DO_GRUPO: grupoMes,
    PROXIMO_PERIODO: proximoPeriodoParaDP,
    diasAteInicioFerias: diasAteInicioFerias
};

if (diasUtilizados > saldoDisponivel) {
    return {
        json: {
            ...dadosBase,
            acao: "ERRO_VALIDACAO",
            userId: 50429030,
            diasSolicitados: diasUtilizados,
            saldoDisponivel: saldoDisponivel,
            mensagem: `❌ Solicitação inválida! Foram solicitados ${diasUtilizados} dias para ${rmData.NOME} (chapa ${rmData.CHAPA}), mas o saldo disponível é de apenas ${saldoDisponivel} dias. As datas foram limpas — ajuste e tente novamente.`
        }
    };
}

// CASO A: 30 dias ou menos antes do início das férias → exige justificativa.
if (diasAteInicioFerias <= 30) {
    const linkForm = `https://forms.monday.com/forms/666dc72fa665c7d688023dc0ce08f467?r=use1` +
      `&chapa=${encodeURIComponent(rmData.CHAPA || '')}` +
      `&cardOpId=${encodeURIComponent(mondayItem.id || '')}` +
      `&cardDpId=${encodeURIComponent(idCardDP || '')}` +
      `&dataInicio=${encodeURIComponent(dataInicioStr || '')}` +
      `&dataFim=${encodeURIComponent(dataFimStr || '')}` +
      `&diasSolicitados=${encodeURIComponent(String(diasUtilizados))}` +
      `&diasAteInicio=${encodeURIComponent(String(diasAteInicioFerias))}`;

    return {
        json: {
            ...dadosBase,
            acao: "PRECISA_JUSTIFICATIVA",
            userId: 50429030,
            diasAteInicioFerias: diasAteInicioFerias,
            linkForm: linkForm,
            mensagem: `⚠️ A solicitação passou da data recomendada.

Funcionário: ${rmData.NOME}
Chapa: ${rmData.CHAPA}
Período solicitado: ${dataInicioStr} a ${dataFimStr}
Dias solicitados: ${diasUtilizados}
Dias até o início das férias: ${diasAteInicioFerias}

Para prosseguir com a solicitação, preencha a justificativa no formulário abaixo:

${linkForm}`
        }
    };
}

// CASO B: entre 31 e 41 dias antes do início das férias → gera aviso agora.
if (diasAteInicioFerias >= 31 && diasAteInicioFerias <= 41) {
    return {
        json: {
            ...dadosBase,
            acao: "GERAR_AVISO_AGORA",
            NOME: diasRestantes > 0 ? `${rmData.NOME} (Saldo)` : rmData.NOME,
            DIAS_FERIAS: diasUtilizados,
            DiasDeDireito: diasRestantes > 0 ? diasRestantes : 0
        }
    };
}

// CASO C: mais de 41 dias antes do início das férias → agenda para 41 dias antes.
const dataGerarAviso = new Date(dataInicioObj);
dataGerarAviso.setDate(dataGerarAviso.getDate() - 41);

if (diasRestantes > 0) {
    return {
        json: {
            ...dadosBase,
            acao: "AGENDAR_AVISO",
            dataGerarAviso: dataGerarAviso.toISOString().split('T')[0],
            NOME: `${rmData.NOME} (Saldo)`,
            DiasDeDireito: diasRestantes,
            motivo: `Período ${proximoPeriodoParaDP} solicitado. Restam ${diasRestantes} dias.`
        }
    };
}

return {
    json: {
        ...dadosBase,
        acao: "AGENDAR_AVISO",
        dataGerarAviso: dataGerarAviso.toISOString().split('T')[0],
        DiasDeDireito: 0
    }
};

