// getDay() retorna: 0 = Domingo, 1 = Seg, 2 = Ter, 3 = Qua, 4 = Qui, 5 = Sex, 6 = Sábado
if (dPagto.getDay() === 6) { 
    // Se caiu no Sábado, volta 1 dia para Sexta
    dPagto.setDate(dPagto.getDate() - 1);
} else if (dPagto.getDay() === 0) { 
    // Se caiu no Domingo, volta 2 dias para Sexta
    dPagto.setDate(dPagto.getDate() - 3);
}

const dataPagtoFormatada = dPagto.toISOString().split('T')[0];

// 5. Entrega tudo mastigadinho para o n8n usar (incluindo o contrato e o nome)
