// Pega as URLs com segurança e camufla para o Google Docs aceitar!
const getUrl = (nodeName) => {
    try { 
        const json = $(nodeName).first().json;
        // Se o nó falhou, json pode ter { error: ... } ou estrutura diferente
        const url = json?.data?.assets?.[0]?.public_url;
        return (url && url.startsWith('http')) ? url : null;
    } catch(e) { 
        return null; 
    }
};

const urls = {
    "foto1": getUrl("Get URL Foto 1"),
    "foto2": getUrl("Get URL Foto 2"),
    "foto3": getUrl("Get URL Foto 3"),
    "foto4": getUrl("Get URL Foto 4"),
    "foto5": getUrl("Get URL Foto 5")
};

let posicoes = [];

function buscarPosicao(elementos) {
  if (!elementos) return;
  for (const el of elementos) {
    if (el.paragraph && el.paragraph.elements) {
      let textoDoParagrafo = "";
      let inicio = el.startIndex;

      for (const p of el.paragraph.elements) {
        if (p.textRun && p.textRun.content) {
          textoDoParagrafo += p.textRun.content;
        }
      }

      let textoMinusc = textoDoParagrafo.toLowerCase();

      Object.keys(urls).forEach(tag => {
        if (textoMinusc.includes(tag)) {
          posicoes.push({
            tag: tag,
            index: inicio + textoMinusc.indexOf(tag),
            url: urls[tag] // Aqui já vai entrar o link camuflado
          });
        }
      });
    }
    if (el.table && el.table.tableRows) {
      for (const row of el.table.tableRows) {
        for (const cell of row.tableCells) { buscarPosicao(cell.content); }
      }
    }
  }
}

buscarPosicao(content);

posicoes.sort((a, b) => b.index - a.index);

let requests = [];

for (const item of posicoes) {
  // Apaga a palavra
  requests.push({ deleteContentRange: { range: { startIndex: item.index, endIndex: item.index + item.tag.length } } });

  // Insere a imagem com o link limpo pelo Proxy
  if (item.url) {
      requests.push({ insertInlineImage: { uri: item.url, location: { index: item.index }, objectSize: { height: { magnitude: 225, unit: "PT" }, width: { magnitude: 225, unit: "PT" } } } });
  }
}

return { json: { requests: requests, urls_camufladas: urls } };

