// Celetista - Buscar empregado no RM (autocomplete CLT)
// Entrada:  ?nome=<string> (minimo 3 caracteres)
// Saida:    { resultados: [{codigo, secaoCodigo, nome, chapa, cpf, funcao, admissao, secao, localUnidade, contrato, codcoligada}, ...] }
// SQL:      2313 - PFP CLT ATESTADOS
//           PFU.CODCATEGORIAESOCIAL <> '111' e PFU.CODSITUACAO <> 'D'.
//           Filtra PFU.NOME LIKE '%' + :NOME + '%'.
// ==============================================================

const nomeRaw = ($json.query?.nome || '').toString().trim();

if (nomeRaw.length < 3) {
  return [{
    json: {
      _statusCode: 200,
      _skip: true,
      resultados: []
    }
  }];
}

// A API do RM aceita o codigo da consulta SQL. Usar o codigo evita conflito de titulo/permissao.
const SQL_NAME = encodeURIComponent('2313');
const nomeParaRM = encodeURIComponent(nomeRaw);
const urlRM = 'https://contatoservicos165112.rm.cloudtotvs.com.br:8051/api/framework/v1/consultaSQLServer/RealizaConsulta/' + SQL_NAME + '/3/P/?parameters=$CODCOLIGADA%3D3%3BNOME%3D' + nomeParaRM;

return [{
  json: {
    nomeRaw,
    urlRM
  }
}];

// ==============================================================
// Celetista - Normaliza resposta do RM em shape camelCase
// Aliases reais da SQL CLT:
//   Codigo              -> codigo
//   Nome do Funcionario -> nome
//   Funcionario         -> chapa
//   CPF                 -> cpf
//   Funcao              -> funcao
//   Admissao            -> admissao
