    .toUpperCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ');
}

function getItemId(item) {
  return (
    item.json.id ||
    item.json.itemId ||
    item.json.data?.create_item?.id ||
    item.json.data?.create_board_item?.id ||
    item.json.board_item?.id ||
    null
  );
}

function montarChave(codColigada, codSecao) {
  return `${normalizarNumero(codColigada)}|${normalizarTexto(codSecao)}`;
}

function deveReceberDadosRm(nome) {
  const nomeNormalizado = normalizarNome(nome);

  if (nomeNormalizado.includes('ADIANTAMENTO')) return false;
  if (nomeNormalizado.includes('AFASTADO INSS')) return false;

  return true;
}

const mondayPorChave = new Map();

for (let i = 0; i < itensCriados.length; i++) {
  const criado = itensCriados[i];
  const padronizado = itensPadronizados[i];

  if (!criado || !padronizado) continue;

  const nome = padronizado.json.name;

  if (!deveReceberDadosRm(nome)) {
    continue;
  }

  const itemId = getItemId(criado);

  const codColigada = padronizado.json.codColigada;
  const codSecao = padronizado.json.codSecao;

  if (!itemId || !codColigada || !codSecao) continue;

  const chave = montarChave(codColigada, codSecao);

  mondayPorChave.set(chave, {
    itemId,
    codColigada: normalizarNumero(codColigada),
    codSecao: normalizarTexto(codSecao),
    name: nome
  });
}

const saida = [];

for (const item of retornoRm) {
  const rm = item.json;

  const codColigada = rm.CODCOLIGADA ?? rm.codColigada;
  const codSecao = rm.CODSECAO ?? rm.codSecao;

  const chave = montarChave(codColigada, codSecao);
  const monday = mondayPorChave.get(chave);

  if (!monday) continue;

  const qtdFuncionarios = normalizarNumero(rm.QTD_FUNCIONARIOS);
  const intermitentes = normalizarNumero(rm.INTERMITENTES);
  const afastados = normalizarNumero(rm.AFASTADOS);

  saida.push({
    json: {
      itemId: monday.itemId,
      name: monday.name,
      codColigada: monday.codColigada,
      codSecao: monday.codSecao,
      qtdFuncionarios,
      intermitentes,
      afastados,
      columnValues: {
        n_meros4__1: qtdFuncionarios,
        dup__of_qntd__de_func___1: intermitentes,
        n_meros6__1: afastados
      }
    }
  });
}

return saida;

