  item;

if (!card) {
  throw new Error('Card do Monday não encontrado.');
}

const columnValues = card.column_values || [];

function getColumnById(id) {
  return columnValues.find((column) => column.id === id) || null;
}

function getColumnText(id, fallback = null) {
  const column = getColumnById(id);

  if (!column) {
    return fallback;
  }

  return column.text || column.display_value || parseColumnValue(column.value) || fallback;
}

function parseColumnValue(value) {
  if (!value) {
    return null;
  }

  try {
    const parsed = JSON.parse(value);

    if (typeof parsed === 'string' || typeof parsed === 'number') {
      return parsed;
    }

    if (parsed?.date) {
      return parsed.date;
    }

    return null;
  } catch {
    return value;
  }
}

function toNumber(value, fieldName) {
  const normalized = String(value ?? '').trim().replace(',', '.');
  const parsed = Number(normalized);

  if (!Number.isFinite(parsed)) {
    throw new Error(`Campo inválido: ${fieldName} = ${value}`);
  }

  return parsed;
}

function normalizeFileName(value) {
  return String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-zA-Z0-9._-]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

function getCurrentDateParts(timeZone = 'America/Cuiaba') {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(new Date());

  const byType = Object.fromEntries(parts.map((part) => [part.type, part.value]));

  return {
    ano: Number(byType.year),
    mes: Number(byType.month),
    dia: Number(byType.day),
    isoDate: `${byType.year}-${byType.month}-${byType.day}`,
  };
}

function getCaixaFromCompetencia(anoComp, mesComp) {
  if (mesComp === 12) {
    return {
      anoCaixa: anoComp + 1,
      mesCaixa: 1,
    };
  }

  return {
    anoCaixa: anoComp,
    mesCaixa: mesComp + 1,
  };
}

