function toNumber(value) {
  if (typeof value === 'number') return value;
  return Number(String(value ?? '0').replace(/\./g, '').replace(',', '.')) || 0;
}

function formatMoney(value) {
  return toNumber(value).toLocaleString('pt-BR', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

const rows = $input.all().map(item => item.json);

const funcionariosMap = new Map();

for (const row of rows) {
  const key = `${row.CODCOLIGADA}|${row.CHAPA}`;

  if (!funcionariosMap.has(key)) {
    funcionariosMap.set(key, {
      codColigada: row.CODCOLIGADA,
      chapa: row.CHAPA,
      nome: row.NOME,
      cpf: row.CPF,
      dataAdmissao: row.DATAADMISSAO,
      codSituacao: row.CODSITUACAO,
      codSecao: row.CODSECAO,
      secao: row.SECAO,
      codFuncao: row.CODFUNCAO,
      funcao: row.FUNCAO,
      salario: toNumber(row.SALARIO),

      proventos: [],
      descontos: [],
      bases: [],

      totalProventos: 0,
      totalDescontos: 0,
      liquido: 0,

      fgtsESocial: 0,
      baseInssEnvelope: 0,
    });
  }

  const funcionario = funcionariosMap.get(key);

  const evento = {
    codigo: row.CODEVENTO,
    descricao: row.EVENTO,
    tipo: row.PROVDESCBASE,
    referencia: toNumber(row.REF),
    valor: toNumber(row.VALOR),
    referenciaFmt: formatMoney(row.REF),
    valorFmt: formatMoney(row.VALOR),
  };

  if (evento.tipo === 'P') {
    funcionario.proventos.push(evento);
    funcionario.totalProventos += evento.valor;
  } else if (evento.tipo === 'D') {
    funcionario.descontos.push(evento);
    funcionario.totalDescontos += evento.valor;
  } else {
    funcionario.bases.push(evento);
  }

  if (String(evento.descricao).toUpperCase() === 'FGTS ESOCIAL') {
    funcionario.fgtsESocial = evento.valor;
  }

  if (String(evento.descricao).toUpperCase() === 'BASE INSS - ENVELOPE') {
    funcionario.baseInssEnvelope = evento.valor;
  }
}

const funcionarios = Array.from(funcionariosMap.values()).map(funcionario => {
  funcionario.liquido = funcionario.totalProventos - funcionario.totalDescontos;

  return {
    ...funcionario,
    salarioFmt: formatMoney(funcionario.salario),
    totalProventosFmt: formatMoney(funcionario.totalProventos),
    totalDescontosFmt: formatMoney(funcionario.totalDescontos),
    liquidoFmt: formatMoney(funcionario.liquido),
    fgtsESocialFmt: formatMoney(funcionario.fgtsESocial),
    baseInssEnvelopeFmt: formatMoney(funcionario.baseInssEnvelope),
  };
});

const totais = funcionarios.reduce((acc, funcionario) => {
  acc.totalFuncionarios += 1;
  acc.proventos += funcionario.totalProventos;
  acc.descontos += funcionario.totalDescontos;
  acc.liquido += funcionario.liquido;
  acc.fgtsESocial += funcionario.fgtsESocial;
  acc.baseInssEnvelope += funcionario.baseInssEnvelope;

  if (funcionario.codSituacao === 'A') {
    acc.ativos += 1;
  } else if (funcionario.codSituacao === 'D') {
    acc.demitidos += 1;
  } else {
    acc.outros += 1;
  }

  return acc;
}, {
  totalFuncionarios: 0,
  ativos: 0,
  demitidos: 0,
  outros: 0,
  proventos: 0,
  descontos: 0,
  liquido: 0,
  fgtsESocial: 0,
  baseInssEnvelope: 0,
});

