function fixEncoding(value) {
  if (value === null || value === undefined) return '';

  const text = String(value);

  try {
    return decodeURIComponent(escape(text));
  } catch {
    return text;
  }
}

function escapeHtml(value) {
  return fixEncoding(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function formatDate(value) {
  if (!value) return '';

  const date = new Date(value);

  if (Number.isNaN(date.getTime())) {
    return escapeHtml(value);
  }

  return date.toLocaleDateString('pt-BR');
}

function money(value) {
  if (typeof value === 'string') return value;

  return Number(value || 0).toLocaleString('pt-BR', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

function statusLabel(codSituacao) {
  const map = {
    A: 'Ativo',
    D: 'Demitido',
    F: 'Férias',
    P: 'Af. Previdência',
    T: 'Af. Ac. Trabalho',
    E: 'Licença Maternidade',
    V: 'Aviso Prévio',
  };

  return map[codSituacao] || codSituacao || '';
}

function renderEvento(evento) {
  if (!evento) {
    return `
      <td class="code"></td>
      <td class="desc"></td>
      <td class="ref"></td>
      <td class="value"></td>
    `;
  }

  return `
    <td class="code">${escapeHtml(evento.codigo)}</td>
    <td class="desc">${escapeHtml(evento.descricao)}</td>
    <td class="ref">${escapeHtml(evento.referenciaFmt)}</td>
    <td class="value">${escapeHtml(evento.valorFmt)}</td>
  `;
}

function renderEventos(funcionario) {
  const esquerda = [...(funcionario.proventos || []), ...(funcionario.bases || [])];
  const direita = funcionario.descontos || [];
  const max = Math.max(esquerda.length, direita.length);

  let rows = '';

  for (let index = 0; index < max; index++) {
    rows += `
      <tr>
        ${renderEvento(esquerda[index])}
        <td class="gap"></td>
        ${renderEvento(direita[index])}
      </tr>
    `;
  }

  return rows;
}

